std::string USER_NAME = "";


TEMPLATE_MATCHING::TEMPLATE_MATCHING()
{
    //// FILE PATH
    if(0) {
        std::string file_name("template_matching.cpp");
        std::string config_path_ = __FILE__;
        config_path_.resize(config_path_.length() - file_name.length());
        config_path_ += "../..";
        // m_package_path = ros::package::getPath("hanyang_matching_process");
        m_package_path = config_path_;
    } else {
        const char* username = getenv("USER");  // Linux/macOS
        USER_NAME = username;
        std::cout << "Current user: " << USER_NAME << std::endl;
        std::string config_path_ = "/home/" + USER_NAME + "/[scanDataHanyang]/hanyang_matching_config";
        m_package_path = config_path_;

        std::string home_folder_path = "/home/" + USER_NAME;
        m_home_folder_path = home_folder_path;
    }

    std::cout << "Package path is " << m_package_path << std::endl;
    initializeTemplate();

    //// Load CAD & object data
    for(size_t i = 0; i < m_ptr_template_list.size(); i++) {
        ROS_LOG_WARN("******************************************");
        ROS_LOG_WARN("*** [m_ptr_template_list(idx): %zu] setTargetObjectTemplate - Start!**", i);
        setTargetObjectTemplate(i, true); // cylinder
        ROS_LOG_WARN("*** setTargetObjectTemplate - Finished!**");
        ROS_LOG_WARN("******************************************");
    }
}

TEMPLATE_MATCHING::~TEMPLATE_MATCHING()
{
}


void TEMPLATE_MATCHING::icp_matchingInitProcess(bool do_measured_cloud_process, const pcl::PointCloud<pcl::PointXYZRGBNormal> &cloud_in, const pcl::PointCloud<pcl::PointXYZRGBNormal> &cloud_scan, const int target_id, const std::string target_name, const Eigen::VectorXf q_scan, bool do_scan_sampling, size_t sampling_num, bool b_plot)
{
    printf("---------------------------------------------------------\n");
    ROS_LOG_INFO("Template Matching Start! (bin picking)");
    ROS_LOG_INFO("Initial processing for matching");
    printf("---------------------------------------------------------\n");
    printf("\n\n\n\n");
    printf("---------------------------------------------------------\n");
    ROS_LOG_INFO("Template Matching Start! (bin picking)");
    printf("---------------------------------------------------------\n");
    //// a) Load template data
    CTARGET_OBJECT_DATA* target_object_data = m_ptr_template_list[target_id - 1];

    //// For RVIZ
    target_object_data->mask_data.idx_target_mask_in = target_object_data->mask_data.pre_selected_idx_set[0];
    //// Multi-thread에서는 아래 변수 clear 한 후에 시작
    target_object_data->mask_data.pre_selected_idx_set.clear();
    target_object_data->multi_thread_test_num = 0;
    target_object_data->is_feasible_pose = false;

    pcl::PointXYZ minPt, maxPt;
    pcl::PointCloud<pcl::PointXYZ>::Ptr cloud_src(new pcl::PointCloud<pcl::PointXYZ>);
    pcl::PointCloud<pcl::PointXYZRGBNormal>::Ptr cloud_src_rgbn(new pcl::PointCloud<pcl::PointXYZRGBNormal>);
    pcl::PointCloud<pcl::PointXYZ>::Ptr cloud_mask_base_aligned(new pcl::PointCloud<pcl::PointXYZ>);
    pcl::PointCloud<pcl::PointXYZRGBNormal>::Ptr cloud_mask_base_aligned_rgbn(new pcl::PointCloud<pcl::PointXYZRGBNormal>);
    pcl::PointCloud<pcl::PointXYZ>::Ptr cloud_tgt(new pcl::PointCloud<pcl::PointXYZ>);
    pcl::PointCloud<pcl::PointXYZ>::Ptr cloud_scan_raw(new pcl::PointCloud<pcl::PointXYZ>);
    pcl::copyPointCloud(cloud_in, *cloud_src);
    pcl::copyPointCloud(cloud_scan, *cloud_scan_raw);

    //// b) Measured cloud processing and plot results
    *target_object_data->cloud_scan_raw = *cloud_scan_raw; // metric: [m]
    target_object_data->robot_scan_JS_position = q_scan;    
    target_object_data->sampling_num = sampling_num;
    target_object_data->debug_mode = false;
    
    //// Scan cloud processing for collision check (merging with bin CAD)
    if (target_object_data->do_collision_check_using_voxel_map) {  // gripper CAD 파일의 voxel map 이용
        doScanCloudProcessingForCollisionCheck(target_object_data);
    }
    ROS_LOG_INFO("Mask detected num.: %zu", target_object_data->mask_data.mask_confident_idx_set.size());
    // m_pcl_proc.plotCloud(*target_object_data->cloud_scan_base_aligned_with_bin_collision_check_process, 800.0, "plot cloud_scan_base_aligned_with_bin_collision_check_process");
}

//// 최신 버전의 함수: icp_matchingSingleProcessVer3
bool TEMPLATE_MATCHING::icp_matchingSingleProcessVer3(std::shared_ptr<bool> &ptr_is_pose_assigned, std::vector<size_t> &mask_confident_idx_set, std::vector<size_t> &pre_selected_idx_set, const size_t thread_id, CTARGET_OBJECT_DATA &object_data, bool b_plot)
{

    mtx.lock();
    CTARGET_OBJECT_DATA object_data_in;
    initializeTargetObjectData(object_data_in);
    object_data_in = object_data;

    ////////////////////////////////////////
    ////////////////////////////////////////
    object_data_in.print_log = false;
    bool print_log = object_data_in.print_log;
    ////////////////////////////////////////
    ////////////////////////////////////////

    if(print_log) {
        std::cout << "[icp_matchingSingleProcessVer3] &object_data: " << &object_data << " [Thread #" << thread_id << "]\n";
        std::cout << "[icp_matchingSingleProcessVer3] &object_data_in: " << &object_data_in << " [Thread #" << thread_id << "]\n";
    }

    object_data_in.cloud_scan_base_aligned_with_bin_collision_check_process->clear();
    *object_data_in.cloud_scan_base_aligned_with_bin_collision_check_process = *object_data.cloud_scan_base_aligned_with_bin_collision_check_raw;


    ////////////////////////////////////////
    std::stringstream ss_check;
    ss_check.str("");
    ss_check << "/home/irl/Documents/check_point_cloud/scan_cloud_bin_filtered_" << "thread_" << thread_id << "_raw_global.ply";
    pcl::io::savePLYFile(ss_check.str(), *object_data.cloud_scan_base_aligned_with_bin_collision_check_raw, true);
    ss_check.str("");
    ss_check << "/home/irl/Documents/check_point_cloud/scan_cloud_bin_filtered_" << "thread_" << thread_id << "_raw_local.ply";
    pcl::io::savePLYFile(ss_check.str(), *object_data_in.cloud_scan_base_aligned_with_bin_collision_check_process, true);
    ////////////////////////////////////////

    mtx.unlock();



    mtx.lock();
    bool l_ptr_is_pose_assigned_1 = *ptr_is_pose_assigned;
    mtx.unlock();

    if(l_ptr_is_pose_assigned_1) {
        ROS_LOG_WARN("[Stage 1] Grasping pose is already detected in another thread [Not in this thread #%zu]", thread_id);
        ROS_LOG_ERROR("ptr_is_pose_assigned - True!!!");

        return true; 
    }

    if(print_log) {
        for (size_t j = 0; j < mask_confident_idx_set.size(); j++) {
            ROS_LOG_ERROR("[mask_confident_idx_set] Mask query index #%zu [Thread #%zu]", mask_confident_idx_set[j] + 1,  thread_id);
        }
        for (size_t j = 0; j < pre_selected_idx_set.size(); j++) {
            ROS_LOG_ERROR("[before - pre_selected_idx_set] #%zu [Thread #%zu]", pre_selected_idx_set[j] + 1,  thread_id);
        }
    }

    selectMaskSAMVer4(mask_confident_idx_set, pre_selected_idx_set, object_data_in);

    if(print_log) {
        for (size_t j = 0; j < pre_selected_idx_set.size(); j++) {
            ROS_LOG_ERROR("[after - pre_selected_idx_set] #%zu [Thread #%zu]", pre_selected_idx_set[j] + 1,  thread_id);
        }
    }

    if(print_log) {
        ROS_LOG_ERROR("[idx_target_mask_process] #%zu [Thread #%zu]", object_data_in.mask_data.idx_target_mask_process + 1,  thread_id);
        pcl::PointCloud<pcl::PointXYZ>::Ptr cloud_mask_base(new pcl::PointCloud<pcl::PointXYZ>);
        *cloud_mask_base = object_data_in.mask_data.mask_cloud_base_aligned_list[object_data_in.mask_data.idx_target_mask_process]; // on_points에서 미리 처리된 cloud
        pcl::PointXYZ minPt, maxPt;
        pcl::getMinMax3D(*object_data_in.cloud_base_aligned, minPt, maxPt);
        ROS_LOG_WARN("*object_data_in.cloud_base_aligned_test1: (min,max) [Thread #%zu]: x: (%f, %f), y: (%f, %f), z: (%f, %f)\n", object_data_in.mask_data.idx_target_mask_process + 1, minPt.x, maxPt.x, minPt.y, maxPt.y, minPt.z, maxPt.z);
        m_math.cloudScaling(*cloud_mask_base, 1);
        pcl::getMinMax3D(*cloud_mask_base, minPt, maxPt);
        ROS_LOG_WARN("cloud_mask_base_test1: (min,max) [Thread #%zu]: x: (%f, %f), y: (%f, %f), z: (%f, %f)\n", object_data_in.mask_data.idx_target_mask_process + 1, minPt.x, maxPt.x, minPt.y, maxPt.y, minPt.z, maxPt.z);
    }



    //// update ////
    mtx.lock();
    object_data.mask_data.pre_selected_idx_set = pre_selected_idx_set;
    mtx.unlock();
    //// update ////
    if(print_log) {
        ROS_LOG_WARN("pre_selected_idx_set.size(): %zu (thread id: #%zu)", pre_selected_idx_set.size(), thread_id);

        printf("---------------------------------------------------------\n");
        ROS_LOG_WARN("Single Processing for a mask Start! (***** Multi thread id: #%zu *****)", thread_id);
        ROS_LOG_WARN("Current mask index: # %zu\n", pre_selected_idx_set.back()+1);
        printf("---------------------------------------------------------\n");
    }


    //// c) Matching process - Quick align and ICP
    //// c-2) Matching process - Pre-matching
    doPreMatchingProcessMultiThreaded(object_data_in);
    //// c-3) Measured cloud의 FPFH 특징 초기 1회만 미리 산출 - Quick align에서 연산량을 많이 차지함.
    calMeasuredCloudFeatureForQuickAlignMultiThreaded(object_data_in);

    //// c-4) Matching process - Quick align and ICP
    doTemplateMatchingProcessMultiThreaded(object_data_in, thread_id);

    mtx.lock();
    bool l_ptr_is_pose_assigned_2 = *ptr_is_pose_assigned;
    mtx.unlock();

    if(l_ptr_is_pose_assigned_2) {
        ROS_LOG_WARN("[Stage 2] Grasping pose is already detected in another thread [Not in this thread #%zu]", thread_id);
        ROS_LOG_ERROR("ptr_is_pose_assigned - True!!!");

        return true; 
    }

    // vec_out_sub_pose_set.clear();
    ////////////////// Re-matching start
    mtx.lock();

    bool do_re_matching = object_data_in.do_re_matching;
    bool is_matching_success = object_data_in.is_matching_success;
    double matching_accuracy = object_data_in.matching_accuracy;
    size_t cnt_re_matching = object_data_in.cnt_re_matching;
    mtx.unlock();

    if(do_re_matching) {
        if(!is_matching_success) {
            //// TODO: 매칭 실패 시에, 특징 이용하여 일치점 찾는 기능 추가
            printf("\n\n\n******************************************************\n");
            printf("******************************************************\n");
            printf("******************************************************\n");
            printf("Current mask index: # %zu [Thread: %zu]\n", pre_selected_idx_set.back()+1, thread_id);
            printf("Matching_accuracy is too low! (matching_accuracy: %0.3f) [Thread: %zu]\n", matching_accuracy, thread_id);
            printf("******************************************************\n");
            printf("******************************************************\n");
            printf("******************************************************\n\n\n");

            for (size_t j = 0; j < cnt_re_matching; j++) {


                mtx.lock();
                bool l_ptr_is_pose_assigned_3 = *ptr_is_pose_assigned;
                mtx.unlock();

                if(l_ptr_is_pose_assigned_3) {
                    ROS_LOG_WARN("[Stage 3] Grasping pose is already detected in another thread [Not in this thread #%zu]", thread_id);
                    ROS_LOG_ERROR("ptr_is_pose_assigned - True!!!");

                    return true; 
                }

                //// c-re) Matching process - Quick align and ICP
                doTemplateMatchingProcessMultiThreaded(object_data_in, thread_id);

                mtx.lock();
                bool is_re_matching_success = object_data_in.is_matching_success;
                double re_matching_accuracy = object_data_in.matching_accuracy;
                mtx.unlock();


                if(is_re_matching_success) {
                    printf("\n\n\n******************************************************\n");
                    printf("******************************************************\n");
                    printf("**********(icp_matchingSingleProcessVer3)*************\n");
                    printf("Re-matching Process End! (# of attempts: %zu) [Thread: %zu]\n", j+1, thread_id);
                    printf("Matching_accuracy! (matching_accuracy: %0.3f) [Thread: %zu]\n", re_matching_accuracy, thread_id);
                    printf("**********(icp_matchingSingleProcessVer3)*************\n");
                    printf("******************************************************\n");
                    printf("******************************************************\n\n\n");
                    break;
                } else {
                    printf("\n\n\n******************************************************\n");
                    printf("******************************************************\n");
                    printf("**********(icp_matchingSingleProcessVer3)*************\n");
                    printf("Re-matching Processing... (# of attempts: %zu) [Thread: %zu]\n", j+1, thread_id);
                    printf("Matching_accuracy under the limit (matching_accuracy: %0.3f) [Thread: %zu]\n", re_matching_accuracy, thread_id);
                    printf("**********(icp_matchingSingleProcessVer3)***********\n");
                    printf("******************************************************\n");
                    printf("******************************************************\n\n\n");
                }
            }
        }
    }


    mtx.lock();
    ////////////////// Re-matching end
    object_data.is_matching_success = object_data_in.is_matching_success;
    object_data.matching_accuracy = object_data_in.matching_accuracy;
    bool is_final_matching_success = object_data.is_matching_success;
    double final_matching_accuracy = object_data_in.matching_accuracy;
    mtx.unlock();


    mtx.lock();
    bool l_ptr_is_pose_assigned_4 = *ptr_is_pose_assigned;
    mtx.unlock();

    if(l_ptr_is_pose_assigned_4) {
        ROS_LOG_WARN("[Stage 4] Grasping pose is already detected in another thread [Not in this thread #%zu]", thread_id);
        ROS_LOG_ERROR("ptr_is_pose_assigned - True!!!");

        return true; 
    }


        //// NOTICE: 스레드 간에 이 cloud가 영향을 받아 소실되는 문제 발생 --> 아래와 같이 지역변수로 변경
    // //// update
    // mtx.lock();
    // *target_object_data.cloud_scan_base_aligned_with_bin_collision_check_process = *cloud_env_base_frame;  // [mm]
    // mtx.unlock();

    pcl::PointCloud<pcl::PointXYZ>::Ptr l_cloud_scan_base_aligned_with_bin_collision_check_process(new pcl::PointCloud<pcl::PointXYZ>);
    if(!is_final_matching_success) {
        ROS_LOG_ERROR("Mask index #%zu - Matching Failure, SKIP! [Thread: %zu]", pre_selected_idx_set.back()+1, thread_id);
        ROS_LOG_ERROR("Mask index #%zu - Matching Failure, SKIP! [Thread: %zu]", pre_selected_idx_set.back()+1, thread_id);
        ROS_LOG_ERROR("Mask index #%zu - Matching Failure, SKIP! [Thread: %zu]", pre_selected_idx_set.back()+1, thread_id);

        printf("\n\n\n******************************************************\n");
        printf("Matching failure! [Thread: %zu]\n", thread_id);
        printf("******************************************************\n");
        printf("******************************************************\n");
        printf("Another mask selection! [Thread: %zu]\n", thread_id);
        printf("Current mask index: # %zu [Thread: %zu]\n", pre_selected_idx_set.back()+1, thread_id);
        printf("Matching_accuracy: %0.3f) [Thread: %zu]\n", final_matching_accuracy, thread_id);
        printf("******************************************************\n");
        printf("******************************************************\n");
        printf("******************************************************\n\n\n");

        return false;
    } else {
        ROS_LOG_ERROR("Mask index #%zu - Matching Success! [Thread: %zu]", pre_selected_idx_set.back()+1, thread_id);
        ROS_LOG_ERROR("Mask index #%zu - Matching Success! [Thread: %zu]", pre_selected_idx_set.back()+1, thread_id);
        ROS_LOG_ERROR("Mask index #%zu - Matching Success! [Thread: %zu]", pre_selected_idx_set.back()+1, thread_id);

        //// For collision check - Matching된 CAD 이어 붙이기

        mtx.lock();
        pcl::copyPointCloud(*object_data_in.cloud_scan_base_aligned_with_bin_collision_check_process, *l_cloud_scan_base_aligned_with_bin_collision_check_process);
        mtx.unlock();
        removeObjectMeasuredCloudUsingMaskForCollisionCheckMultiThreaded(object_data_in, *l_cloud_scan_base_aligned_with_bin_collision_check_process);
        removeObjectMeasuredCloudUsingOBBForCollisionCheckMultiThreaded(object_data_in, *l_cloud_scan_base_aligned_with_bin_collision_check_process);
    }

    //// d) Cal. grasping pose
    mtx.lock();
    ss_check.str("");
    ss_check << "/home/irl/Documents/check_point_cloud/scan_cloud_bin_filtered_" << "thread_" << thread_id << ".ply";
    pcl::io::savePLYFile(ss_check.str(), *object_data_in.cloud_scan_base_aligned_with_bin_collision_check_process, true);

    ss_check.str("");
    ss_check << "/home/irl/Documents/check_point_cloud/scan_cloud_bin_filtered_" << "thread_" << thread_id << "_removeObjects.ply";
    pcl::io::savePLYFile(ss_check.str(), *l_cloud_scan_base_aligned_with_bin_collision_check_process, true);

    mtx.unlock();
    bool is_pose_detection_success = calGraspingPoseMultiThreadedVer2(ptr_is_pose_assigned, object_data_in, *l_cloud_scan_base_aligned_with_bin_collision_check_process);
   
    if(is_pose_detection_success) 
    {
        mergeObjectCADCloudForCollisionCheckMultiThreaded(object_data_in, true, *l_cloud_scan_base_aligned_with_bin_collision_check_process);

        printf("\n\n\n******************************************************\n");
        printf("******************************************************\n");
        printf("******************************************************\n");
        //// Monitoring
        mtx.lock();
        bool is_object_pose_flipped = object_data_in.is_object_pose_flipped;
        Eigen::Vector3f vec_flip_check = object_data_in.measured_object_normal_for_flip_check;
        std::string detection_mode = object_data_in.mask_data.detection_mode;
        mtx.unlock();

        if(is_object_pose_flipped) {
            printf("----- Object flipped in post processing! - 180 deg w.r.t {O} Flipped!  -----\n");
            printf("vec_flip_check: %0.3f, %0.3f, %0.3f\n", vec_flip_check[0], vec_flip_check[1], vec_flip_check[2]);
            printf("------------------------------------------------------\n");
        } else {
            printf("----- No object flip in post processing! -----\n");
            printf("------------------------------------------------------\n");
        }
        printf("Current mask index: # %zu (Mask detection mode: %s) [Thread: %zu]\n", pre_selected_idx_set.back()+1, detection_mode.c_str(), thread_id);
        printf("Matching_accuracy(success): %0.3f) [Thread: %zu]\n", final_matching_accuracy, thread_id);
        printf("******************************************************\n");
        printf("******************************************************\n");
        printf("******************************************************\n\n\n");
    } else { // 충돌이 발생하거나 로봇 작업영역에서 벗어난 경우, 다른 mask에 대해 다시 수행
        mergeObjectCADCloudForCollisionCheckMultiThreaded(object_data_in, true, *l_cloud_scan_base_aligned_with_bin_collision_check_process);

        printf("\n\n\n******************************************************\n");
        printf("Pose detection failure!\n");
        printf("******************************************************\n");
        printf("******************************************************\n");
        printf("Another mask selection!\n");
        printf("Current mask index: # %zu [Thread: %zu]\n", pre_selected_idx_set.back()+1, thread_id);
        printf("Matching_accuracy: %0.3f) [Thread: %zu]\n", final_matching_accuracy, thread_id);
        printf("******************************************************\n");
        printf("******************************************************\n");
        printf("******************************************************\n\n\n");
        // return false;
    }

    // update
    mtx.lock();
    object_data_in.detected_mask_num = object_data_in.mask_data.mask_confident_idx_set.size(); // 현재 인식된 마스크 개수
    bool is_feasible_pose = object_data_in.is_feasible_pose;
    mtx.unlock();

    if(is_feasible_pose) {
        ROS_LOG_INFO("Feasible pose! (icp_matchingSingleProcessVer3)");
        ROS_LOG_WARN("(***** Multi thread id: #%zu *****)", thread_id);

        //// update
        mtx.lock();
        object_data.grasping_pose = object_data_in.grasping_pose;
        object_data.grasping_sub_pose = object_data_in.grasping_sub_pose;
        object_data.zig_pose = object_data_in.zig_pose;
        object_data.T_O2GP_final = object_data_in.T_O2GP_final;

        object_data.matching_accuracy = object_data_in.matching_accuracy;
        pcl::copyPointCloud(*object_data_in.cloud_final_results_for_collision_check, *object_data.cloud_final_results_for_collision_check);

        object_data.is_feasible_pose = object_data_in.is_feasible_pose;
        pcl::copyPointCloud(*object_data_in.cloud_matching_results, *object_data.cloud_matching_results);
        pcl::copyPointCloud(*object_data_in.cloud_pre_matching_results, *object_data.cloud_pre_matching_results);

        object_data.mask_data.idx_target_mask_in = object_data_in.mask_data.idx_target_mask_in;
        object_data.mask_data.idx_target_mask_process = object_data_in.mask_data.idx_target_mask_process;

        object_data.approach_distance = object_data_in.approach_distance;
        object_data.is_grasping_pose_flipped = object_data_in.is_grasping_pose_flipped;
        object_data.gripper_open_length = object_data_in.gripper_open_length;
        object_data.gripper_close_length = object_data_in.gripper_close_length;
        object_data.matching_accuracy_limit = object_data_in.matching_accuracy_limit;
        object_data.detected_mask_num = object_data_in.detected_mask_num;
        object_data.gripper_tip_index = object_data_in.gripper_tip_index;


        object_data.object_bin_to_object_teach_pose_to_be_saved_from_initial_teaching = object_data_in.object_bin_to_object_teach_pose_to_be_saved_from_initial_teaching;
        object_data.object_bin_to_base_pose_to_be_saved_from_initial_teaching = object_data_in.object_bin_to_base_pose_to_be_saved_from_initial_teaching;

        ////////////////////////////////////////////////
        ss_check.str("");
        ss_check << "/home/irl/Documents/check_point_cloud/scan_cloud_bin_filtered_" << "thread_" << thread_id << "_feasible_pose.ply";
        pcl::io::savePLYFile(ss_check.str(), *object_data_in.cloud_scan_base_aligned_with_bin_collision_check_process, true);

        ss_check.str("");
        ss_check << "/home/irl/Documents/check_point_cloud/scan_cloud_bin_filtered_" << "thread_" << thread_id << "_removeObjects_feasible_pose.ply";
        pcl::io::savePLYFile(ss_check.str(), *l_cloud_scan_base_aligned_with_bin_collision_check_process, true);
        ////////////////////////////////////////////////


        mtx.unlock();

        return true;
    } else {
        ROS_LOG_INFO("Infeasible pose! (icp_matchingSingleProcessVer3)");
        ROS_LOG_WARN("(***** Multi thread id: #%zu *****)", thread_id);

        mtx.lock();
        pcl::copyPointCloud(*object_data_in.cloud_final_results_for_collision_check, *object_data.cloud_final_results_for_collision_check);
        object_data.is_feasible_pose = object_data_in.is_feasible_pose;
        pcl::copyPointCloud(*object_data_in.cloud_matching_results, *object_data.cloud_matching_results);
        pcl::copyPointCloud(*object_data_in.cloud_pre_matching_results, *object_data.cloud_pre_matching_results);

        object_data.mask_data.idx_target_mask_in = object_data_in.mask_data.idx_target_mask_in;
        object_data.mask_data.idx_target_mask_process = object_data_in.mask_data.idx_target_mask_process;


        ////////////////////////////////////////////////
        ss_check.str("");
        ss_check << "/home/irl/Documents/check_point_cloud/scan_cloud_bin_filtered_" << "thread_" << thread_id << "_infeasible_pose.ply";
        pcl::io::savePLYFile(ss_check.str(), *object_data_in.cloud_scan_base_aligned_with_bin_collision_check_process, true);

        ss_check.str("");
        ss_check << "/home/irl/Documents/check_point_cloud/scan_cloud_bin_filtered_" << "thread_" << thread_id << "_removeObjects_infeasible_pose.ply";
        pcl::io::savePLYFile(ss_check.str(), *l_cloud_scan_base_aligned_with_bin_collision_check_process, true);
        ////////////////////////////////////////////////

        mtx.unlock();


        return false;
    }
}




//// 최신 버전의 함수: icp_matchingSingleProcessVer3
bool TEMPLATE_MATCHING::gicp_matchingSingleProcessVer1(std::shared_ptr<bool> &ptr_is_pose_assigned, std::vector<size_t> &mask_confident_idx_set, std::vector<size_t> &pre_selected_idx_set, const size_t thread_id, CTARGET_OBJECT_DATA &object_data, bool b_plot)
{

    mtx.lock();
    CTARGET_OBJECT_DATA object_data_in;
    initializeTargetObjectData(object_data_in);
    object_data_in = object_data;

    ////////////////////////////////////////
    ////////////////////////////////////////
    object_data_in.print_log = false;
    bool print_log = object_data_in.print_log;
    ////////////////////////////////////////
    ////////////////////////////////////////

    if(print_log) {
        std::cout << "[gicp_matchingSingleProcessVer1] &object_data: " << &object_data << " [Thread #" << thread_id << "]\n";
        std::cout << "[gicp_matchingSingleProcessVer1] &object_data_in: " << &object_data_in << " [Thread #" << thread_id << "]\n";
    }

    object_data_in.cloud_scan_base_aligned_with_bin_collision_check_process->clear();
    *object_data_in.cloud_scan_base_aligned_with_bin_collision_check_process = *object_data.cloud_scan_base_aligned_with_bin_collision_check_raw;


    ////////////////////////////////////////
    std::stringstream ss_check;
    ss_check.str("");
    ss_check << "/home/irobot/Documents/check_point_cloud/scan_cloud_bin_filtered_" << "thread_" << thread_id << "_raw_global.ply";
    pcl::io::savePLYFile(ss_check.str(), *object_data.cloud_scan_base_aligned_with_bin_collision_check_raw, true);
    ss_check.str("");
    ss_check << "/home/irobot/Documents/check_point_cloud/scan_cloud_bin_filtered_" << "thread_" << thread_id << "_raw_local.ply";
    pcl::io::savePLYFile(ss_check.str(), *object_data_in.cloud_scan_base_aligned_with_bin_collision_check_process, true);
    ////////////////////////////////////////

    mtx.unlock();



    mtx.lock();
    bool l_ptr_is_pose_assigned_1 = *ptr_is_pose_assigned;
    mtx.unlock();

    if(l_ptr_is_pose_assigned_1) {
        ROS_LOG_WARN("[Stage 1] Grasping pose is already detected in another thread [Not in this thread #%zu]", thread_id);
        ROS_LOG_ERROR("ptr_is_pose_assigned - True!!!");

        return true; 
    }

    if(print_log) {
        for (size_t j = 0; j < mask_confident_idx_set.size(); j++) {
            ROS_LOG_ERROR("[mask_confident_idx_set] Mask query index #%zu [Thread #%zu]", mask_confident_idx_set[j] + 1,  thread_id);
        }
        for (size_t j = 0; j < pre_selected_idx_set.size(); j++) {
            ROS_LOG_ERROR("[before - pre_selected_idx_set] #%zu [Thread #%zu]", pre_selected_idx_set[j] + 1,  thread_id);
        }
    }

    selectMaskSAMVer4(mask_confident_idx_set, pre_selected_idx_set, object_data_in);

    if(print_log) {
        for (size_t j = 0; j < pre_selected_idx_set.size(); j++) {
            ROS_LOG_ERROR("[after - pre_selected_idx_set] #%zu [Thread #%zu]", pre_selected_idx_set[j] + 1,  thread_id);
        }
    }

    if(print_log) {
        ROS_LOG_ERROR("[idx_target_mask_process] #%zu [Thread #%zu]", object_data_in.mask_data.idx_target_mask_process + 1,  thread_id);
        pcl::PointCloud<pcl::PointXYZ>::Ptr cloud_mask_base(new pcl::PointCloud<pcl::PointXYZ>);
        *cloud_mask_base = object_data_in.mask_data.mask_cloud_base_aligned_list[object_data_in.mask_data.idx_target_mask_process]; // on_points에서 미리 처리된 cloud
        pcl::PointXYZ minPt, maxPt;
        pcl::getMinMax3D(*object_data_in.cloud_base_aligned, minPt, maxPt);
        ROS_LOG_WARN("*object_data_in.cloud_base_aligned_test1: (min,max) [Thread #%zu]: x: (%f, %f), y: (%f, %f), z: (%f, %f)\n", object_data_in.mask_data.idx_target_mask_process + 1, minPt.x, maxPt.x, minPt.y, maxPt.y, minPt.z, maxPt.z);
        m_math.cloudScaling(*cloud_mask_base, 1);
        pcl::getMinMax3D(*cloud_mask_base, minPt, maxPt);
        ROS_LOG_WARN("cloud_mask_base_test1: (min,max) [Thread #%zu]: x: (%f, %f), y: (%f, %f), z: (%f, %f)\n", object_data_in.mask_data.idx_target_mask_process + 1, minPt.x, maxPt.x, minPt.y, maxPt.y, minPt.z, maxPt.z);
    }



    //// update ////
    mtx.lock();
    object_data.mask_data.pre_selected_idx_set = pre_selected_idx_set;
    mtx.unlock();
    //// update ////
    if(print_log) {
        ROS_LOG_WARN("pre_selected_idx_set.size(): %zu (thread id: #%zu)", pre_selected_idx_set.size(), thread_id);

        printf("---------------------------------------------------------\n");
        ROS_LOG_WARN("Single Processing for a mask Start! (***** Multi thread id: #%zu *****)", thread_id);
        ROS_LOG_WARN("Current mask index: # %zu\n", pre_selected_idx_set.back()+1);
        printf("---------------------------------------------------------\n");
    }


    //// c) Matching process - Quick align and ICP
    //// c-2) Matching process - Pre-matching
    doPreMatchingProcessMultiThreaded(object_data_in);
    //// c-3) Measured cloud의 FPFH 특징 초기 1회만 미리 산출 - Quick align에서 연산량을 많이 차지함.
    calMeasuredCloudFeatureForQuickAlignMultiThreaded(object_data_in);

    //// c-4) Matching process - Quick align and GICP
    //// NOTICE: Quick align + GICP 사용
    doTemplateMatchingProcessUsingGICPMultiThreaded(object_data_in, thread_id);

    //// NOTICE: Only GICP 사용
    // doTemplateMatchingProcessUsingGICPWithoutQuickAlignMultiThreaded(object_data_in, thread_id);
    


    mtx.lock();
    bool l_ptr_is_pose_assigned_2 = *ptr_is_pose_assigned;
    mtx.unlock();

    if(l_ptr_is_pose_assigned_2) {
        ROS_LOG_WARN("[Stage 2] Grasping pose is already detected in another thread [Not in this thread #%zu]", thread_id);
        ROS_LOG_ERROR("ptr_is_pose_assigned - True!!!");

        return true; 
    }

    // vec_out_sub_pose_set.clear();
    ////////////////// Re-matching start
    mtx.lock();

    bool do_re_matching = object_data_in.do_re_matching;
    bool is_matching_success = object_data_in.is_matching_success;
    double matching_accuracy = object_data_in.matching_accuracy;
    size_t cnt_re_matching = object_data_in.cnt_re_matching;
    mtx.unlock();

    if(do_re_matching) {
        if(!is_matching_success) {
            //// TODO: 매칭 실패 시에, 특징 이용하여 일치점 찾는 기능 추가
            printf("\n\n\n******************************************************\n");
            printf("******************************************************\n");
            printf("******************************************************\n");
            printf("Current mask index: # %zu [Thread: %zu]\n", pre_selected_idx_set.back()+1, thread_id);
            printf("Matching_accuracy is too low! (matching_accuracy: %0.3f) [Thread: %zu]\n", matching_accuracy, thread_id);
            printf("******************************************************\n");
            printf("******************************************************\n");
            printf("******************************************************\n\n\n");

            for (size_t j = 0; j < cnt_re_matching; j++) {


                mtx.lock();
                bool l_ptr_is_pose_assigned_3 = *ptr_is_pose_assigned;
                mtx.unlock();

                if(l_ptr_is_pose_assigned_3) {
                    ROS_LOG_WARN("[Stage 3] Grasping pose is already detected in another thread [Not in this thread #%zu]", thread_id);
                    ROS_LOG_ERROR("ptr_is_pose_assigned - True!!!");

                    return true; 
                }

                //// c-re) Matching process - Quick align and GICP
                //// NOTICE: Quick align + GICP 사용
                doTemplateMatchingProcessUsingGICPMultiThreaded(object_data_in, thread_id);
                //// NOTICE: Only GICP 사용
                // doTemplateMatchingProcessUsingGICPWithoutQuickAlignMultiThreaded(object_data_in, thread_id);
                

                mtx.lock();
                bool is_re_matching_success = object_data_in.is_matching_success;
                double re_matching_accuracy = object_data_in.matching_accuracy;
                mtx.unlock();


                if(is_re_matching_success) {
                    printf("\n\n\n******************************************************\n");
                    printf("******************************************************\n");
                    printf("**********(gicp_matchingSingleProcessVer1)*************\n");
                    printf("Re-matching Process End! (# of attempts: %zu) [Thread: %zu]\n", j+1, thread_id);
                    printf("Matching_accuracy! (matching_accuracy: %0.3f) [Thread: %zu]\n", re_matching_accuracy, thread_id);
                    printf("**********(gicp_matchingSingleProcessVer1)*************\n");
                    printf("******************************************************\n");
                    printf("******************************************************\n\n\n");
                    break;
                } else {
                    printf("\n\n\n******************************************************\n");
                    printf("******************************************************\n");
                    printf("**********(gicp_matchingSingleProcessVer1)*************\n");
                    printf("Re-matching Processing... (# of attempts: %zu) [Thread: %zu]\n", j+1, thread_id);
                    printf("Matching_accuracy under the limit (matching_accuracy: %0.3f) [Thread: %zu]\n", re_matching_accuracy, thread_id);
                    printf("**********(gicp_matchingSingleProcessVer1)***********\n");
                    printf("******************************************************\n");
                    printf("******************************************************\n\n\n");
                }
            }
        }
    }


    mtx.lock();
    ////////////////// Re-matching end
    object_data.is_matching_success = object_data_in.is_matching_success;
    object_data.matching_accuracy = object_data_in.matching_accuracy;
    bool is_final_matching_success = object_data.is_matching_success;
    double final_matching_accuracy = object_data_in.matching_accuracy;
    mtx.unlock();


    mtx.lock();
    bool l_ptr_is_pose_assigned_4 = *ptr_is_pose_assigned;
    mtx.unlock();

    if(l_ptr_is_pose_assigned_4) {
        ROS_LOG_WARN("[Stage 4] Grasping pose is already detected in another thread [Not in this thread #%zu]", thread_id);
        ROS_LOG_ERROR("ptr_is_pose_assigned - True!!!");

        return true; 
    }


        //// NOTICE: 스레드 간에 이 cloud가 영향을 받아 소실되는 문제 발생 --> 아래와 같이 지역변수로 변경
    // //// update
    // mtx.lock();
    // *target_object_data.cloud_scan_base_aligned_with_bin_collision_check_process = *cloud_env_base_frame;  // [mm]
    // mtx.unlock();

    pcl::PointCloud<pcl::PointXYZ>::Ptr l_cloud_scan_base_aligned_with_bin_collision_check_process(new pcl::PointCloud<pcl::PointXYZ>);
    if(!is_final_matching_success) {
        ROS_LOG_ERROR("Mask index #%zu - Matching Failure, SKIP! [Thread: %zu]", pre_selected_idx_set.back()+1, thread_id);
        ROS_LOG_ERROR("Mask index #%zu - Matching Failure, SKIP! [Thread: %zu]", pre_selected_idx_set.back()+1, thread_id);
        ROS_LOG_ERROR("Mask index #%zu - Matching Failure, SKIP! [Thread: %zu]", pre_selected_idx_set.back()+1, thread_id);

        printf("\n\n\n******************************************************\n");
        printf("Matching failure! [Thread: %zu]\n", thread_id);
        printf("******************************************************\n");
        printf("******************************************************\n");
        printf("Another mask selection! [Thread: %zu]\n", thread_id);
        printf("Current mask index: # %zu [Thread: %zu]\n", pre_selected_idx_set.back()+1, thread_id);
        printf("Matching_accuracy: %0.3f) [Thread: %zu]\n", final_matching_accuracy, thread_id);
        printf("******************************************************\n");
        printf("******************************************************\n");
        printf("******************************************************\n\n\n");

        return false;
    } else {
        ROS_LOG_ERROR("Mask index #%zu - Matching Success! [Thread: %zu]", pre_selected_idx_set.back()+1, thread_id);
        ROS_LOG_ERROR("Mask index #%zu - Matching Success! [Thread: %zu]", pre_selected_idx_set.back()+1, thread_id);
        ROS_LOG_ERROR("Mask index #%zu - Matching Success! [Thread: %zu]", pre_selected_idx_set.back()+1, thread_id);

        //// For collision check - Matching된 CAD 이어 붙이기

        mtx.lock();
        pcl::copyPointCloud(*object_data_in.cloud_scan_base_aligned_with_bin_collision_check_process, *l_cloud_scan_base_aligned_with_bin_collision_check_process);
        mtx.unlock();
        removeObjectMeasuredCloudUsingMaskForCollisionCheckMultiThreaded(object_data_in, *l_cloud_scan_base_aligned_with_bin_collision_check_process);
        removeObjectMeasuredCloudUsingOBBForCollisionCheckMultiThreaded(object_data_in, *l_cloud_scan_base_aligned_with_bin_collision_check_process);
    }

    //// d) Cal. grasping pose
    mtx.lock();
    ss_check.str("");
    ss_check << "/home/irobot/Documents/check_point_cloud/scan_cloud_bin_filtered_" << "thread_" << thread_id << ".ply";
    pcl::io::savePLYFile(ss_check.str(), *object_data_in.cloud_scan_base_aligned_with_bin_collision_check_process, true);

    ss_check.str("");
    ss_check << "/home/irobot/Documents/check_point_cloud/scan_cloud_bin_filtered_" << "thread_" << thread_id << "_removeObjects.ply";
    pcl::io::savePLYFile(ss_check.str(), *l_cloud_scan_base_aligned_with_bin_collision_check_process, true);

    mtx.unlock();
    bool is_pose_detection_success = calGraspingPoseMultiThreadedVer2(ptr_is_pose_assigned, object_data_in, *l_cloud_scan_base_aligned_with_bin_collision_check_process);
   
    if(is_pose_detection_success) 
    {
        mergeObjectCADCloudForCollisionCheckMultiThreaded(object_data_in, true, *l_cloud_scan_base_aligned_with_bin_collision_check_process);

        printf("\n\n\n******************************************************\n");
        printf("******************************************************\n");
        printf("******************************************************\n");
        //// Monitoring
        mtx.lock();
        bool is_object_pose_flipped = object_data_in.is_object_pose_flipped;
        Eigen::Vector3f vec_flip_check = object_data_in.measured_object_normal_for_flip_check;
        std::string detection_mode = object_data_in.mask_data.detection_mode;
        mtx.unlock();

        if(is_object_pose_flipped) {
            printf("----- Object flipped in post processing! - 180 deg w.r.t {O} Flipped!  -----\n");
            printf("vec_flip_check: %0.3f, %0.3f, %0.3f\n", vec_flip_check[0], vec_flip_check[1], vec_flip_check[2]);
            printf("------------------------------------------------------\n");
        } else {
            printf("----- No object flip in post processing! -----\n");
            printf("------------------------------------------------------\n");
        }
        printf("Current mask index: # %zu (Mask detection mode: %s) [Thread: %zu]\n", pre_selected_idx_set.back()+1, detection_mode.c_str(), thread_id);
        printf("Matching_accuracy(success): %0.3f) [Thread: %zu]\n", final_matching_accuracy, thread_id);
        printf("******************************************************\n");
        printf("******************************************************\n");
        printf("******************************************************\n\n\n");
    } else { // 충돌이 발생하거나 로봇 작업영역에서 벗어난 경우, 다른 mask에 대해 다시 수행
        mergeObjectCADCloudForCollisionCheckMultiThreaded(object_data_in, true, *l_cloud_scan_base_aligned_with_bin_collision_check_process);

        printf("\n\n\n******************************************************\n");
        printf("Pose detection failure!\n");
        printf("******************************************************\n");
        printf("******************************************************\n");
        printf("Another mask selection!\n");
        printf("Current mask index: # %zu [Thread: %zu]\n", pre_selected_idx_set.back()+1, thread_id);
        printf("Matching_accuracy: %0.3f) [Thread: %zu]\n", final_matching_accuracy, thread_id);
        printf("******************************************************\n");
        printf("******************************************************\n");
        printf("******************************************************\n\n\n");
        // return false;
    }

    // update
    mtx.lock();
    object_data_in.detected_mask_num = object_data_in.mask_data.mask_confident_idx_set.size(); // 현재 인식된 마스크 개수
    bool is_feasible_pose = object_data_in.is_feasible_pose;
    mtx.unlock();

    if(is_feasible_pose) {
        ROS_LOG_INFO("Feasible pose! (gicp_matchingSingleProcessVer1)");
        ROS_LOG_WARN("(***** Multi thread id: #%zu *****)", thread_id);

        //// update
        mtx.lock();
        object_data.grasping_pose = object_data_in.grasping_pose;
        object_data.grasping_sub_pose = object_data_in.grasping_sub_pose;
        object_data.zig_pose = object_data_in.zig_pose;
        object_data.T_O2GP_final = object_data_in.T_O2GP_final;

        object_data.matching_accuracy = object_data_in.matching_accuracy;
        pcl::copyPointCloud(*object_data_in.cloud_final_results_for_collision_check, *object_data.cloud_final_results_for_collision_check);

        object_data.is_feasible_pose = object_data_in.is_feasible_pose;
        pcl::copyPointCloud(*object_data_in.cloud_matching_results, *object_data.cloud_matching_results);
        pcl::copyPointCloud(*object_data_in.cloud_pre_matching_results, *object_data.cloud_pre_matching_results);

        object_data.mask_data.idx_target_mask_in = object_data_in.mask_data.idx_target_mask_in;
        object_data.mask_data.idx_target_mask_process = object_data_in.mask_data.idx_target_mask_process;

        object_data.approach_distance = object_data_in.approach_distance;
        object_data.is_grasping_pose_flipped = object_data_in.is_grasping_pose_flipped;
        object_data.gripper_open_length = object_data_in.gripper_open_length;
        object_data.gripper_close_length = object_data_in.gripper_close_length;
        object_data.matching_accuracy_limit = object_data_in.matching_accuracy_limit;
        object_data.detected_mask_num = object_data_in.detected_mask_num;
        object_data.gripper_tip_index = object_data_in.gripper_tip_index;


        object_data.object_bin_to_object_teach_pose_to_be_saved_from_initial_teaching = object_data_in.object_bin_to_object_teach_pose_to_be_saved_from_initial_teaching;
        object_data.object_bin_to_base_pose_to_be_saved_from_initial_teaching = object_data_in.object_bin_to_base_pose_to_be_saved_from_initial_teaching;

        ////////////////////////////////////////////////
        ss_check.str("");
        ss_check << "/home/irobot/Documents/check_point_cloud/scan_cloud_bin_filtered_" << "thread_" << thread_id << "_feasible_pose.ply";
        pcl::io::savePLYFile(ss_check.str(), *object_data_in.cloud_scan_base_aligned_with_bin_collision_check_process, true);

        ss_check.str("");
        ss_check << "/home/irobot/Documents/check_point_cloud/scan_cloud_bin_filtered_" << "thread_" << thread_id << "_removeObjects_feasible_pose.ply";
        pcl::io::savePLYFile(ss_check.str(), *l_cloud_scan_base_aligned_with_bin_collision_check_process, true);
        ////////////////////////////////////////////////


        mtx.unlock();

        return true;
    } else {
        ROS_LOG_INFO("Infeasible pose! (gicp_matchingSingleProcessVer1)");
        ROS_LOG_WARN("(***** Multi thread id: #%zu *****)", thread_id);

        mtx.lock();
        pcl::copyPointCloud(*object_data_in.cloud_final_results_for_collision_check, *object_data.cloud_final_results_for_collision_check);
        object_data.is_feasible_pose = object_data_in.is_feasible_pose;
        pcl::copyPointCloud(*object_data_in.cloud_matching_results, *object_data.cloud_matching_results);
        pcl::copyPointCloud(*object_data_in.cloud_pre_matching_results, *object_data.cloud_pre_matching_results);

        object_data.mask_data.idx_target_mask_in = object_data_in.mask_data.idx_target_mask_in;
        object_data.mask_data.idx_target_mask_process = object_data_in.mask_data.idx_target_mask_process;


        ////////////////////////////////////////////////
        ss_check.str("");
        ss_check << "/home/irobot/Documents/check_point_cloud/scan_cloud_bin_filtered_" << "thread_" << thread_id << "_infeasible_pose.ply";
        pcl::io::savePLYFile(ss_check.str(), *object_data_in.cloud_scan_base_aligned_with_bin_collision_check_process, true);

        ss_check.str("");
        ss_check << "/home/irobot/Documents/check_point_cloud/scan_cloud_bin_filtered_" << "thread_" << thread_id << "_removeObjects_infeasible_pose.ply";
        pcl::io::savePLYFile(ss_check.str(), *l_cloud_scan_base_aligned_with_bin_collision_check_process, true);
        ////////////////////////////////////////////////

        mtx.unlock();


        return false;
    }
}

//// 최신 버전의 함수: icp_matchingSingleProcessVer3
void TEMPLATE_MATCHING::icp_matchingBinPicking(bool do_measured_cloud_process, const pcl::PointCloud<pcl::PointXYZRGBNormal> &cloud_in, const pcl::PointCloud<pcl::PointXYZRGBNormal> &cloud_scan, const int target_id, const std::string target_name, const Eigen::VectorXf q_scan, std::vector<double> &vec_out, std::vector<std::vector<double>> &vec_out_sub_pose_set, std::vector<double> &zig_pose, double &matching_accuracy, bool do_scan_sampling, size_t sampling_num, bool b_plot)
{
    printf("\n\n\n\n");
    printf("---------------------------------------------------------\n");
    ROS_LOG_INFO("[%s, line: %d]Template Matching Start! (bin picking)", __func__, __LINE__);
    printf("---------------------------------------------------------\n");
    vec_out_sub_pose_set.clear();

    pcl::PointXYZ minPt, maxPt;
    pcl::PointCloud<pcl::PointXYZ>::Ptr cloud_src(new pcl::PointCloud<pcl::PointXYZ>);
    pcl::PointCloud<pcl::PointXYZRGBNormal>::Ptr cloud_src_rgbn(new pcl::PointCloud<pcl::PointXYZRGBNormal>);
    pcl::PointCloud<pcl::PointXYZ>::Ptr cloud_mask_base_aligned(new pcl::PointCloud<pcl::PointXYZ>);
    pcl::PointCloud<pcl::PointXYZRGBNormal>::Ptr cloud_mask_base_aligned_rgbn(new pcl::PointCloud<pcl::PointXYZRGBNormal>);
    pcl::PointCloud<pcl::PointXYZ>::Ptr cloud_tgt(new pcl::PointCloud<pcl::PointXYZ>);
    pcl::PointCloud<pcl::PointXYZ>::Ptr cloud_scan_raw(new pcl::PointCloud<pcl::PointXYZ>);
    pcl::copyPointCloud(cloud_in, *cloud_src);
    pcl::copyPointCloud(cloud_scan, *cloud_scan_raw);

    //// a) Load template data
    CTARGET_OBJECT_DATA* target_object_data = m_ptr_template_list[target_id - 1];

    //// b) Measured cloud processing and plot results
    *target_object_data->cloud_scan_raw = *cloud_scan_raw; // metric: [m]
    target_object_data->robot_scan_JS_position = q_scan;    
    target_object_data->sampling_num = sampling_num;
    target_object_data->debug_mode = false;


    const std::string json_path_for_quick_align = m_package_path + "/config/quick_align_matrix_table/quick_align_matrix_table_" + target_name + ".json";
    target_object_data->json_path_for_quick_align = json_path_for_quick_align;

    ///////////////////////////
    ROS_LOG_INFO("[%s, line: %d]", __func__, __LINE__);
    if(0)
    {
        *target_object_data->cloud_measured = *cloud_src; // metric: [m]
        Eigen::Vector3d sensor_origin = {0.0, 0.0, 0.0};
        m_pcl_proc.cloudNormalEst2Measured(*cloud_src, *cloud_src_rgbn, 10, sensor_origin, 80.0); // K = 10, angle: 80 [deg]
        *target_object_data->cloud_measured_rgbn = *cloud_src_rgbn; // metric: [m]
        ///////////////////////////

        if (do_measured_cloud_process)
        {
            //// TODO: 아래 처리도 초기 1회만 수행
            doMeasuredCloudProcessing(target_object_data); // Mask cloud processing
        }
        else // base frame 기준으로 이미 변환된 경우
        {
        }
    }
    else
    {
        size_t idx_init_mask = target_object_data->mask_data.pre_selected_idx_set[0];
        pcl::copyPointCloud(target_object_data->mask_data.cloud_mask_rgba_list[idx_init_mask], *cloud_src);
        *cloud_src_rgbn = target_object_data->mask_data.cloud_mask_rgbn_list[idx_init_mask];
        *target_object_data->cloud_measured = *cloud_src; // metric: [m]
        *target_object_data->cloud_measured_rgbn = *cloud_src_rgbn; // metric: [m]

        *cloud_mask_base_aligned = target_object_data->mask_data.mask_cloud_base_aligned_list[idx_init_mask];
        *cloud_mask_base_aligned_rgbn = target_object_data->mask_data.mask_cloud_base_aligned_rgbn_list[idx_init_mask];
        m_math.cloudScaling(*cloud_mask_base_aligned, 1); // m to mm
        m_math.cloudScaling(*cloud_mask_base_aligned_rgbn, 1); // m to mm
        *target_object_data->cloud_base_aligned = *cloud_mask_base_aligned; // metric: [mm]
        *target_object_data->cloud_base_aligned_rgbn = *cloud_mask_base_aligned_rgbn; // metric: [mm]
    }
    ROS_LOG_INFO("[%s, line: %d]", __func__, __LINE__);
    //// Scan cloud processing for collision check (merging with bin CAD)
    if (target_object_data->do_collision_check_using_voxel_map) {  // gripper CAD 파일의 voxel map 이용
        doScanCloudProcessingForCollisionCheck(target_object_data);
    }
    ROS_LOG_INFO("Mask detected num.: %zu", target_object_data->mask_data.mask_confident_idx_set.size());
    // m_pcl_proc.plotCloud(*target_object_data->cloud_scan_base_aligned_with_bin_collision_check_process, 800.0, "plot cloud_scan_base_aligned_with_bin_collision_check_process");

    // update raw mask index 
    target_object_data->mask_data.idx_target_mask_in = target_object_data->mask_data.pre_selected_idx_set[0];
    target_object_data->mask_data.idx_target_mask_process = target_object_data->mask_data.pre_selected_idx_set[0];

    // 충돌이 없는 자세를 찾을 때까지 반복
    size_t candidate_cnt = target_object_data->mask_data.mask_confident_idx_set.size();
    size_t re_matching_cnt = 0;

    target_object_data->mask_data.pre_selected_idx_set.clear(); //// 241017 추가
    for (size_t i = 0; i < candidate_cnt; i++)
    {
        ROS_LOG_INFO("target_object_data->mask_data.mask_confident_idx_set.size(): %zu", target_object_data->mask_data.mask_confident_idx_set.size());
        ROS_LOG_INFO("target_object_data->mask_data.pre_selected_idx_set.size(): %zu", target_object_data->mask_data.pre_selected_idx_set.size());
        if(target_object_data->mask_data.mask_confident_idx_set.size() > 1)
        {
            if(target_object_data->mask_data.mask_confident_idx_set.size() < target_object_data->mask_data.pre_selected_idx_set.size()) { break; }
        }

        //// Visualization
        if (target_object_data->plot_base_aligned_cloud_results)
        {
            pcl::PointCloud<pcl::PointXYZRGBA>::Ptr cloud_plot(new pcl::PointCloud<pcl::PointXYZRGBA>);
            pcl::copyPointCloud(*target_object_data->cloud_base_aligned, *cloud_plot); // metric: [m]
            
            pcl::visualization::PCLVisualizer viewer("Filtering");
            int v1(0);
            int v2(1);
            viewer.createViewPort(0.0, 0.0, 0.5, 1.0, v1);
            viewer.createViewPort(0.5, 0.0, 1.0, 1.0, v2);
            viewer.setBackgroundColor(1, 1, 1, v1);
            viewer.setBackgroundColor(1, 1, 1, v2);
            float txt_color = 0.0; // black text

            // raw cloud is green
            pcl::visualization::PointCloudColorHandlerCustom<pcl::PointXYZRGBA> cloud_raw_color_h(cloud_plot, 10, 10, 255);
            viewer.addPointCloud(cloud_plot, cloud_raw_color_h, "cloud_raw_v1", v1);

            // aligned point cloud is red
            pcl::visualization::PointCloudColorHandlerCustom<pcl::PointXYZRGBA> cloud_align_color_h(cloud_plot, 10, 10, 255);
            viewer.addPointCloud(cloud_plot, cloud_align_color_h, "cloud_aligned", v2);

            // Adding text descriptions in each viewport
            viewer.addText("Black: Original point cloud\nBlue: raw point cloud", 10, 15, 16, txt_color, txt_color, txt_color, "icp_info_1", v1);
            viewer.addText("Black: Original point cloud\nBlue: Downsampling point cloud", 10, 15, 16, txt_color, txt_color, txt_color, "icp_info_2", v2);

            while (!viewer.wasStopped())
            {
                viewer.spinOnce(100);
                boost::this_thread::sleep(boost::posix_time::microseconds(100000));
            }
            viewer.close();
        }

        //// 충돌 발생 시, Candidate pose 생성 (이때 mask는 on_points함수에서 처리되어 저장된 cloud를 불러와 사용) 
        if(i>0) {ROS_LOG_INFO("Candidate pose generation start!");}


        //// NOTICE: matching 기반의 자세 추정, Image 픽셀 좌표 기반의 자세 변환 --> 두 가지 모드
        if(!target_object_data->is_image_based_picking_process) { // Matching process

            bool is_image_ai_detection_ = false;
            if(is_image_ai_detection_ && target_object_data->target_id == 8) { // Door Hinge
                ROS_LOG_WARN("---------------------------------------");
                ROS_LOG_WARN("POSE ESTIMATION MODE: DOOR HINGE - Using open3D");
                ROS_LOG_WARN("---------------------------------------");
                
                Eigen::Matrix4f T_S2O_from_open3d = Eigen::Matrix4f::Identity();
                for(int i = 0; i < 4; i++) {
                    for(int j = 0; j < 4; j++) {
                        T_S2O_from_open3d(i, j) = target_object_data->mask_data.hinge_pose_transformation[i*4 + j];
                    }
                }
                ROS_LOG_WARN("\n\n");
                std::cout << "T_S2O_from_open3d" << std::endl;
                std::cout << T_S2O_from_open3d << std::endl;
                ROS_LOG_WARN("\n\n");


                Eigen::Matrix4f T_B2O_from_open3d = target_object_data->T_B2S*T_S2O_from_open3d;

                cout << "********************" << endl;
                cout << "T_B2O_from_open3d" << endl;
                cout << T_B2O_from_open3d << endl;
                cout << "********************" << endl;

                //// Update
                target_object_data->T_matching_B2O = T_B2O_from_open3d;
                target_object_data->T_matching_O2B = T_B2O_from_open3d.inverse();

                target_object_data->matching_accuracy = 1.0;


            } else {

                //// c) Matching process - Quick align and ICP
                ROS_LOG_WARN("---------------------------------------");
                ROS_LOG_WARN("POSE ESTIMATION MODE: TEMPLATE MATCHING");
                ROS_LOG_WARN("---------------------------------------");

                //// c-2) Matching process - Pre-matching
                doPreMatchingProcess(target_object_data);
                //// c-3) Measured cloud의 FPFH 특징 초기 1회만 미리 산출 - Quick align에서 연산량을 많이 차지함.
                calMeasuredCloudFeatureForQuickAlign(target_object_data);
                //// c-4) Matching process - Quick align and ICP
                doTemplateMatchingProcess(target_object_data);



                if(target_object_data->do_matching_with_image_info) {
                    ROS_LOG_WARN("-------------------------------------------------");
                    ROS_LOG_WARN("MATCHING WITH IMAGE-BASED PICKING");
                    ROS_LOG_WARN("-------------------------------------------------");

                    Eigen::Matrix4f grasp_pose;
                    size_t selected_idx = target_object_data->mask_data.idx_target_mask_process;
                    geometry_msgs::msg::Pose2D picking_pose = target_object_data->mask_data.picking_poses[selected_idx];
                    cout << endl << endl << endl;
                    cout << "p_x: " << picking_pose.x << endl;
                    cout << "p_y: " << picking_pose.y << endl;
                    cout << "theta: " << picking_pose.theta << endl;
                    cout << endl << endl << endl;
                }


                ////////////////// Re-matching start
                if(target_object_data->do_re_matching) {
                    if(!target_object_data->is_matching_success) {
                        //// TODO: 매칭 실패 시에, 특징 이용하여 일치점 찾는 기능 추가
                        printf("\n\n\n******************************************************\n");
                        printf("******************************************************\n");
                        printf("******************************************************\n");
                        printf("Current mask index: # %zu\n", target_object_data->mask_data.pre_selected_idx_set.back()+1);
                        printf("Matching_accuracy is too low! (matching_accuracy: %0.3f)\n", target_object_data->matching_accuracy);
                        printf("******************************************************\n");
                        printf("******************************************************\n");
                        printf("******************************************************\n\n\n");

                        auto quick_align_z_threshold_raw = target_object_data->quick_align_z_threshold;
                        auto quick_align_min_sample_distance = target_object_data->quick_align_min_sample_distance;
                        auto quick_align_max_correspondence_distance = target_object_data->quick_align_max_correspondence_distance;
                        auto quick_align_iteration = target_object_data->quick_align_iteration;

                        //// Modify quick align parameter 
                        auto quick_align_sample_num = target_object_data->quick_align_sample_num;
                        auto quick_align_corr_rnd_k = target_object_data->quick_align_corr_rnd_k;
                        ROS_LOG_WARN("Before --------------------------------------------");
                        ROS_LOG_WARN("[%s] quick_align_sample_num: %i", __func__, quick_align_sample_num);
                        ROS_LOG_WARN("[%s] quick_align_corr_rnd_k: %i", __func__, quick_align_corr_rnd_k);
                        ROS_LOG_WARN("Before --------------------------------------------");

                        for (size_t j = 0; j < target_object_data->cnt_re_matching; j++) {


                            // 현재 시간을 시드로 사용하여 랜덤 번호 생성기 초기화
                            std::srand(static_cast<unsigned int>(std::time(nullptr)));

                            // 3부터 10까지의 랜덤 정수 생성
                            int randomNumber1 = std::rand() % 8 + 3; // (0~7) + 3 => 3~10
                            int randomNumber2 = std::rand() % 30 + 6; // (0~29) + 6 => 6~35

                            // 결과 출력
                            std::cout << "랜덤 숫자1: " << randomNumber1 << std::endl;
                            std::cout << "랜덤 숫자2: " << randomNumber2 << std::endl;
                            target_object_data->quick_align_sample_num = randomNumber1; // the number of samples to use during each iteration
                            target_object_data->quick_align_corr_rnd_k = randomNumber2; // the number of neighbors to use when selecting a random feature correspondence.


                            //// c-re) Matching process - Quick align and ICP
                            doTemplateMatchingProcess(target_object_data);
                            
                            if(target_object_data->is_matching_success) {
                                printf("\n\n\n******************************************************\n");
                                printf("******************************************************\n");
                                printf("******************************************************\n");
                                printf("[icp_matchingBinPicking] Re-matching Process End! (# of attempts: %zu)\n", j+1);
                                printf("Matching_accuracy! (matching_accuracy: %0.3f)\n", target_object_data->matching_accuracy);
                                printf("******************************************************\n");
                                printf("******************************************************\n");
                                printf("******************************************************\n\n\n");
                                break;
                            } else {
                                printf("\n\n\n******************************************************\n");
                                printf("******************************************************\n");
                                printf("******************************************************\n");
                                printf("Re-matching Processing... (# of attempts: %zu)\n", j+1);
                                printf("Matching_accuracy under the limit (matching_accuracy: %0.3f)\n", target_object_data->matching_accuracy);
                                printf("******************************************************\n");
                                printf("******************************************************\n");
                                printf("******************************************************\n\n\n");
                            }
                        }

                        // 파라미터 다시 기본 값으로 세팅
                        target_object_data->quick_align_sample_num = quick_align_sample_num;
                        target_object_data->quick_align_corr_rnd_k = quick_align_corr_rnd_k;
                    }
                }
                ////////////////// Re-matching end

                if(!target_object_data->is_matching_success) {
                    ROS_LOG_INFO("Mask index #%zu - Matching Failure, SKIP!", i + 1);
                    ROS_LOG_INFO("Mask index #%zu - Matching Failure, SKIP!", i + 1);
                    ROS_LOG_INFO("Mask index #%zu - Matching Failure, SKIP!", i + 1);


                    if(i + 1 == candidate_cnt) { 
                        ROS_LOG_INFO("Candidate is empty!: %zu", candidate_cnt);
                        break; 
                    }
                    printf("\n\n\n******************************************************\n");
                    printf("Matching failure!\n");
                    printf("******************************************************\n");
                    printf("******************************************************\n");
                    printf("Another mask selection!\n");
                    printf("Current mask index: # %zu\n", target_object_data->mask_data.pre_selected_idx_set.back()+1);
                    printf("Matching_accuracy: %0.3f)\n", target_object_data->matching_accuracy);
                    printf("******************************************************\n");
                    printf("******************************************************\n");
                    printf("******************************************************\n\n\n");

                    if(target_object_data->mask_data.detection_mode == "mask_rcnn_detection") {
                        selectMaskRCNN(target_object_data, *cloud_src, *cloud_src_rgbn, *cloud_mask_base_aligned, *cloud_mask_base_aligned_rgbn);
                    } else if(target_object_data->mask_data.detection_mode == "mask_sam_detection") {
                        selectMaskSAM(target_object_data, *cloud_src, *cloud_src_rgbn, *cloud_mask_base_aligned, *cloud_mask_base_aligned_rgbn);
                    }
                    *target_object_data->cloud_measured = *cloud_src; // metric: [m]
                    *target_object_data->cloud_measured_rgbn = *cloud_src_rgbn; // metric: [m]

                    m_math.cloudScaling(*cloud_mask_base_aligned, 1); // m to mm
                    m_math.cloudScaling(*cloud_mask_base_aligned_rgbn, 1); // m to mm
                    *target_object_data->cloud_base_aligned = *cloud_mask_base_aligned; // metric: [mm]
                    *target_object_data->cloud_base_aligned_rgbn = *cloud_mask_base_aligned_rgbn; // metric: [mm]

                    continue;
                }

                if (target_object_data->do_collision_check_using_voxel_map) {
                    //// For collision check - Matching된 CAD 이어 붙이기
                    ROS_LOG_WARN("[%s] removeObjectMeasuredCloudUsingMaskForCollisionCheck Start", __func__);
                    removeObjectMeasuredCloudUsingMaskForCollisionCheck(target_object_data);
                    ROS_LOG_WARN("[%s] removeObjectMeasuredCloudUsingMaskForCollisionCheck End", __func__);
                    ROS_LOG_WARN("[%s] removeObjectMeasuredCloudUsingOBBForCollisionCheck Start", __func__);
                    removeObjectMeasuredCloudUsingOBBForCollisionCheck(target_object_data);
                    ROS_LOG_WARN("[%s] removeObjectMeasuredCloudUsingOBBForCollisionCheck End", __func__);
                }
            }


            

        } else { // Image에서 얻은 pixel좌표를 곧바로 파지 자세로 변환
            ROS_LOG_WARN("-------------------------------------------------");
            ROS_LOG_WARN("POSE ESTIMATION MODE: IMAGE-BASED PICKING PROCESS");
            ROS_LOG_WARN("-------------------------------------------------");

            // //// Image picking point를 직접 사용하는 경우, ex) 볼트
            // ROS_LOG_INFO(" bolt!!! (image-based picking process)");


            Eigen::Matrix4f grasp_pose;
            size_t selected_idx = target_object_data->mask_data.idx_target_mask_process;
            geometry_msgs::msg::Pose2D picking_pose = target_object_data->mask_data.picking_poses[selected_idx];

            cout << endl << endl << endl;

            sensor_msgs::msg::Image l_mask_img;
            l_mask_img = target_object_data->mask_data.mask_imgs[selected_idx];
            
            cv_bridge::CvImagePtr l_mask_ptr;
            l_mask_ptr = cv_bridge::toCvCopy(l_mask_img, sensor_msgs::image_encodings::BGR8);
            cv::Mat l_img_tmp = l_mask_ptr->image;      

            size_t l_pixel_horizontal = picking_pose.x; // 가로 (단축), 
            size_t l_pixel_vertical = picking_pose.y; // 세로 (장축)

            size_t l_pt_idx = l_img_tmp.cols * l_pixel_vertical + l_pixel_horizontal;

            pcl::PointXYZRGBA pt_tmp;
            pt_tmp.x = cloud_scan_raw->points[l_pt_idx].x;
            pt_tmp.y = cloud_scan_raw->points[l_pt_idx].y;
            pt_tmp.z = cloud_scan_raw->points[l_pt_idx].z;

            m_math.printCloudMinMax(*cloud_scan_raw, "cloud size: ");
            cout << "l_img_tmp.cols: " << l_img_tmp.cols  << "l_img_tmp.rows" << l_img_tmp.rows << endl;

            cout << "bolt picking pose" << endl;
            cout << "cloud size: " << cloud_scan_raw -> size() << endl;
            cout << "p_x: " << picking_pose.x << endl;
            cout << "p_y: " << picking_pose.y << endl;
            cout << "theta: " << picking_pose.theta << endl;
            
            // float l_rot_angle = -(360.0 - picking_pose.theta); // 스캐너 좌표계 기준으로 +x축으로부터 +z 방향 회전각도
            // l_rot_angle -= 180.0; // +x축 벡터가 0도로부터 회전한 각도

            float l_rot_angle = picking_pose.theta;

            cout << "{S} 기준 z 방향 회전각도: " << l_rot_angle << endl;

            cout << "Current Mask Index: #" << selected_idx + 1 << endl;
            cout << "{S} 기준 포인트 x: " << pt_tmp.x << "{S} 기준 포인트 y: " << pt_tmp.y << "{S} 기준 포인트 z: " << pt_tmp.z << endl;
            
            cout << endl << endl << endl;


            Eigen::Matrix4f T_S2O_image = Eigen::Matrix4f::Identity();
            Eigen::Matrix3f tmp_rotM;

            //// Ry 기준으로 180도 회전
            Eigen::Matrix4f tmp_HTM_Ry_180;
            m_math.genRotM(180.0, tmp_rotM, tmp_HTM_Ry_180, 1); // Ry
            T_S2O_image = T_S2O_image*tmp_HTM_Ry_180;

            //// Rz 기준으로 각도 출력만큼 회전
            Eigen::Matrix4f tmp_HTM_Rz;
            m_math.genRotM(l_rot_angle, tmp_rotM, tmp_HTM_Rz, 2); // Rz

            T_S2O_image = T_S2O_image*tmp_HTM_Rz;


                                // ////////////////////////////////////////////////////
                                // ////////////////////////////////////////////////////
                                // ////////////////////////////////////////////////////
                                // //// NOTICE: 상자에 수직하게 들어가도록 처리
                                // //// Ry 기준으로 19도 회전 (센서 좌표계 기울기)
                                // Eigen::Matrix4f tmp_HTM_sensor_tilting;
                                // m_math.genRotM(19.0, tmp_rotM, tmp_HTM_sensor_tilting, 1); // Ry
                                // T_S2O_image = T_S2O_image*tmp_HTM_sensor_tilting;

                                // //// Rx 기준으로 19도 회전 (센서 좌표계 기울기)
                                // m_math.genRotM(9.0, tmp_rotM, tmp_HTM_sensor_tilting, 0); // Rx
                                // T_S2O_image = T_S2O_image*tmp_HTM_sensor_tilting;
                                // ////////////////////////////////////////////////////
                                // ////////////////////////////////////////////////////
                                // ////////////////////////////////////////////////////

            //// Position
            T_S2O_image(0, 3) = 1000.0*pt_tmp.x;
            T_S2O_image(1, 3) = 1000.0*pt_tmp.y;
            T_S2O_image(2, 3) = 1000.0*pt_tmp.z;


            // l_rot_angle *= DEGTORAD;
            // T_S2O_image(0, 0) = cos(l_rot_angle); T_S2O_image(0, 1) = -sin(l_rot_angle);
            // T_S2O_image(1, 0) = sin(l_rot_angle); T_S2O_image(1, 1) = cos(l_rot_angle);

            // T_S2O_image(0, 3) = 1000.0*pt_tmp.x;
            // T_S2O_image(1, 3) = 1000.0*pt_tmp.y;
            // T_S2O_image(2, 3) = 1000.0*pt_tmp.z;

            // //// Rx 기준으로 180도 회전
            // Eigen::Matrix4f tmp_HTM_Rx;
            // m_math.genRotM(180.0, tmp_rotM, tmp_HTM_Rx, 0); // Rx
            
            // Eigen::Matrix4f T_S2O_image_process = T_S2O_image*tmp_HTM_Rx;
            

            // cout << "********************" << endl;
            // cout << "T_S2O_image" << endl;
            // cout << T_S2O_image << endl;
            // cout << "********************" << endl;

            Eigen::Matrix4f T_S2O_image_process = T_S2O_image;

            cout << "********************" << endl;
            cout << "T_S2O_image_process" << endl;
            cout << T_S2O_image_process << endl;
            cout << "********************" << endl;
            
            Eigen::Matrix4f T_B2O_image = target_object_data->T_B2S*T_S2O_image_process;

            cout << "********************" << endl;
            cout << "T_B2O_image" << endl;
            cout << T_B2O_image << endl;
            cout << "********************" << endl;



            T_B2O_image.block<3, 3>(0, 0) = tmp_HTM_Rz.block<3, 3>(0, 0);
            cout << "********************" << endl;
            cout << "T_B2O_image(final)" << endl;
            cout << T_B2O_image << endl;
            cout << "********************" << endl;

            // Eigen::Matrix4f T_O
            // T_B2O = 

            target_object_data->T_matching_B2O = T_B2O_image;
            target_object_data->T_matching_O2B = T_B2O_image.inverse();
            // //// Base 기준 좌표로 변환
        }

        //// d) Cal. grasping pose
        bool is_pose_detection_success = calGraspingPose(target_object_data);
        if(is_pose_detection_success) 
        { 
            printf("\n\n\n******************************************************\n");
            printf("******************************************************\n");
            printf("******************************************************\n");
            //// Monitoring
            if(target_object_data->is_object_pose_flipped) {
	            printf("----- Object flipped in post processing! - 180 deg w.r.t {O} Flipped!  -----\n");
                Eigen::Vector3f vec_flip_check = target_object_data->measured_object_normal_for_flip_check;
                printf("vec_flip_check: %0.3f, %0.3f, %0.3f\n", vec_flip_check[0], vec_flip_check[1], vec_flip_check[2]);
                printf("------------------------------------------------------\n");
            } else {
	            printf("----- No object flip in post processing! -----\n");
                printf("------------------------------------------------------\n");
            }
            printf("Matching Process Finished! (# of attempts: %zu)\n", i+1);
            printf("Current mask index: # %zu (Mask detection mode: %s)\n", target_object_data->mask_data.pre_selected_idx_set.back()+1, target_object_data->mask_data.detection_mode.c_str());
            printf("Matching_accuracy(success): %0.3f)\n", target_object_data->matching_accuracy);
            printf("******************************************************\n");
            printf("******************************************************\n");
            printf("******************************************************\n\n\n");
            break; 
        }
        else // 충돌이 발생하거나 로봇 작업영역에서 벗어난 경우, 다른 mask에 대해 다시 수행
        {
            if(i + 1 == candidate_cnt) { 
                ROS_LOG_INFO("Candidate is empty!: %zu", candidate_cnt);
                break; 
            }
            printf("\n\n\n******************************************************\n");
            printf("Pose detection failure!\n");
            printf("******************************************************\n");
            printf("******************************************************\n");
            printf("Another mask selection!\n");
            printf("Current mask index: # %zu\n", target_object_data->mask_data.pre_selected_idx_set.back()+1);
            printf("Matching_accuracy: %0.3f)\n", target_object_data->matching_accuracy);
            printf("******************************************************\n");
            printf("******************************************************\n");
            printf("******************************************************\n\n\n");

            if(target_object_data->mask_data.detection_mode == "mask_rcnn_detection") {
                //// 다음 물체에서의 충돌확인을 위해 앞서 제거했던 부분에 매칭된 CAD 파일을 병합함
                //// 다음 물체에서의 충돌확인을 위해 앞서 제거했던 부분에 매칭된 CAD 파일을 병합함
                //// Object CAD cloud
                // merging matching results w.r.t {B}
                pcl::PointCloud<pcl::PointXYZ>::Ptr cloud_object_CAD(new pcl::PointCloud<pcl::PointXYZ>);
                pcl::copyPointCloud(*target_object_data->cloud_CAD_uniformly_downsampled, *cloud_object_CAD);
                Eigen::Matrix4f T_B2O = target_object_data->T_matching_B2O;
                pcl::transformPointCloud(*cloud_object_CAD, *cloud_object_CAD, T_B2O);
                //// update
                *target_object_data->cloud_scan_base_aligned_with_bin_collision_check_process += *cloud_object_CAD; // [mm]
                //// 다음 물체에서의 충돌확인을 위해 앞서 제거했던 부분에 매칭된 CAD 파일을 병합함
                //// 다음 물체에서의 충돌확인을 위해 앞서 제거했던 부분에 매칭된 CAD 파일을 병합함
                selectMaskRCNN(target_object_data, *cloud_src, *cloud_src_rgbn, *cloud_mask_base_aligned, *cloud_mask_base_aligned_rgbn);
            } else if(target_object_data->mask_data.detection_mode == "mask_sam_detection") {
                //// 다음 물체에서의 충돌확인을 위해 앞서 제거했던 부분에 매칭된 CAD 파일을 병합함
                //// 다음 물체에서의 충돌확인을 위해 앞서 제거했던 부분에 매칭된 CAD 파일을 병합함
                //// Object CAD cloud
                // merging matching results w.r.t {B}
                pcl::PointCloud<pcl::PointXYZ>::Ptr cloud_object_CAD(new pcl::PointCloud<pcl::PointXYZ>);
                pcl::copyPointCloud(*target_object_data->cloud_CAD_uniformly_downsampled, *cloud_object_CAD);
                Eigen::Matrix4f T_B2O = target_object_data->T_matching_B2O;
                pcl::transformPointCloud(*cloud_object_CAD, *cloud_object_CAD, T_B2O);
                //// update
                *target_object_data->cloud_scan_base_aligned_with_bin_collision_check_process += *cloud_object_CAD; // [mm]
                //// 다음 물체에서의 충돌확인을 위해 앞서 제거했던 부분에 매칭된 CAD 파일을 병합함
                //// 다음 물체에서의 충돌확인을 위해 앞서 제거했던 부분에 매칭된 CAD 파일을 병합함
                selectMaskSAM(target_object_data, *cloud_src, *cloud_src_rgbn, *cloud_mask_base_aligned, *cloud_mask_base_aligned_rgbn);
            }
            *target_object_data->cloud_measured = *cloud_src; // metric: [m]
            *target_object_data->cloud_measured_rgbn = *cloud_src_rgbn; // metric: [m]

            m_math.cloudScaling(*cloud_mask_base_aligned, 1); // m to mm
            m_math.cloudScaling(*cloud_mask_base_aligned_rgbn, 1); // m to mm
            *target_object_data->cloud_base_aligned = *cloud_mask_base_aligned; // metric: [mm]
            *target_object_data->cloud_base_aligned_rgbn = *cloud_mask_base_aligned_rgbn; // metric: [mm]
        }
    }

    // 인식된 mask가 없는 경우
    if(candidate_cnt == 0)
    {
        target_object_data->is_feasible_pose = false;
    }
    // 매칭이 제대로 되지 않은 경우
    if(!target_object_data->is_matching_success) {
        target_object_data->is_feasible_pose = false;
    }

    // output
    vec_out = target_object_data->grasping_pose; // output
    //// TODO: 아래 변수 처리
    vec_out_sub_pose_set.push_back(target_object_data->grasping_sub_pose); 

    zig_pose = target_object_data->zig_pose;
    matching_accuracy = target_object_data->matching_accuracy;

    // update
    target_object_data->detected_mask_num = target_object_data->mask_data.mask_confident_idx_set.size(); // 현재 인식된 마스크 개수

    if(target_object_data->is_feasible_pose) {

        //// 251006 추가, 추후 다중 스레드에서 사용 주의
        if(target_object_data->do_quick_align && target_object_data->is_matching_success) { // 매칭 성공한 Quick align 결과를 json에 저장
            //// JSON에 저장
            ROS_LOG_WARN("[%s, line: %d] **************", __func__, __LINE__);
            m_pcl_proc.printMatrixAsJson(target_object_data->T_process_quick_for_json, "target_object_data->T_process_quick_for_json");
            m_pcl_proc.appendTransformAndUpdateCount(json_path_for_quick_align, target_object_data->T_process_quick_for_json);
            ROS_LOG_WARN("[%s, line: %d] **************", __func__, __LINE__);
            ROS_LOG_WARN("Quick align T saved to [%s]", json_path_for_quick_align.c_str());
            ROS_LOG_WARN("[%s, line: %d] **************", __func__, __LINE__);
        }
        ROS_LOG_INFO("[%s, line: %d] Feasible pose! (icp_matchingBinPicking)", __func__, __LINE__);
    } else {
        ROS_LOG_INFO("[%s, line: %d] Infeasible pose! (icp_matchingBinPicking)", __func__, __LINE__);
    }


    printf("---------------------------------------------------------\n");
    if(target_object_data->is_eye_in_hand) { ROS_LOG_WARN("[%s] [EYE-IN-HAND] MODE", __func__); }
    // else { ROS_LOG_WARN("[%s] [EYE-TO-HAND] MODE (Usage: %s)", __func__, target_object_data->scanner_usage_mode.c_str());  }

    if(target_object_data->do_quick_align) { ROS_LOG_WARN("[%s] [Quick Align] MODE", __func__); }
    else { ROS_LOG_WARN("[%s] [No Quick Align, using Matrix Table] MODE", __func__); }

    ROS_LOG_INFO("[%s, line: %d]Template Matching End! (bin picking)", __func__, __LINE__);
    printf("---------------------------------------------------------\n");

}

//// 최신 버전의 함수: icp_matchingSingleProcessVer3
void TEMPLATE_MATCHING::icp_matchingMultipleBinPicking(bool do_measured_cloud_process, const pcl::PointCloud<pcl::PointXYZRGBNormal> &cloud_in, const pcl::PointCloud<pcl::PointXYZRGBNormal> &cloud_scan, const int target_id, const std::string target_name, const Eigen::VectorXf q_scan, std::vector<double> &vec_out, std::vector<std::vector<double>> &vec_out_sub_pose_set, std::vector<double> &zig_pose, double &matching_accuracy, bool do_scan_sampling, size_t sampling_num, bool b_plot)
{
    printf("\n\n\n\n");
    printf("---------------------------------------------------------\n");
    ROS_LOG_INFO("Template Matching Start! (bin picking)");
    printf("---------------------------------------------------------\n");
    vec_out_sub_pose_set.clear();

    pcl::PointXYZ minPt, maxPt;
    pcl::PointCloud<pcl::PointXYZ>::Ptr cloud_src(new pcl::PointCloud<pcl::PointXYZ>);
    pcl::PointCloud<pcl::PointXYZRGBNormal>::Ptr cloud_src_rgbn(new pcl::PointCloud<pcl::PointXYZRGBNormal>);
    pcl::PointCloud<pcl::PointXYZ>::Ptr cloud_mask_base_aligned(new pcl::PointCloud<pcl::PointXYZ>);
    pcl::PointCloud<pcl::PointXYZRGBNormal>::Ptr cloud_mask_base_aligned_rgbn(new pcl::PointCloud<pcl::PointXYZRGBNormal>);
    pcl::PointCloud<pcl::PointXYZ>::Ptr cloud_tgt(new pcl::PointCloud<pcl::PointXYZ>);
    pcl::PointCloud<pcl::PointXYZ>::Ptr cloud_scan_raw(new pcl::PointCloud<pcl::PointXYZ>);
    pcl::copyPointCloud(cloud_in, *cloud_src);
    pcl::copyPointCloud(cloud_scan, *cloud_scan_raw);

    //// a) Load template data
    CTARGET_OBJECT_DATA* target_object_data = m_ptr_template_list[target_id - 1];


    //// b) Measured cloud processing and plot results
    *target_object_data->cloud_scan_raw = *cloud_scan_raw; // metric: [m]
    target_object_data->robot_scan_JS_position = q_scan;    
    target_object_data->sampling_num = sampling_num;
    target_object_data->debug_mode = false;
    ///////////////////////////
    if(0)
    {
        *target_object_data->cloud_measured = *cloud_src; // metric: [m]
        Eigen::Vector3d sensor_origin = {0.0, 0.0, 0.0};
        m_pcl_proc.cloudNormalEst2Measured(*cloud_src, *cloud_src_rgbn, 10, sensor_origin, 80.0); // K = 10, angle: 80 [deg]
        *target_object_data->cloud_measured_rgbn = *cloud_src_rgbn; // metric: [m]
        ///////////////////////////

        if (do_measured_cloud_process)
        {
            //// TODO: 아래 처리도 초기 1회만 수행
            doMeasuredCloudProcessing(target_object_data); // Mask cloud processing
        }
        else // base frame 기준으로 이미 변환된 경우
        {
        }
    }
    else
    {
        size_t idx_init_mask = target_object_data->mask_data.pre_selected_idx_set[0];
        pcl::copyPointCloud(target_object_data->mask_data.cloud_mask_rgba_list[idx_init_mask], *cloud_src);
        *cloud_src_rgbn = target_object_data->mask_data.cloud_mask_rgbn_list[idx_init_mask];
        *target_object_data->cloud_measured = *cloud_src; // metric: [m]
        *target_object_data->cloud_measured_rgbn = *cloud_src_rgbn; // metric: [m]

        *cloud_mask_base_aligned = target_object_data->mask_data.mask_cloud_base_aligned_list[idx_init_mask];
        *cloud_mask_base_aligned_rgbn = target_object_data->mask_data.mask_cloud_base_aligned_rgbn_list[idx_init_mask];
        m_math.cloudScaling(*cloud_mask_base_aligned, 1); // m to mm
        m_math.cloudScaling(*cloud_mask_base_aligned_rgbn, 1); // m to mm
        *target_object_data->cloud_base_aligned = *cloud_mask_base_aligned; // metric: [mm]
        *target_object_data->cloud_base_aligned_rgbn = *cloud_mask_base_aligned_rgbn; // metric: [mm]
    }
    //// Scan cloud processing for collision check (merging with bin CAD)
    if (target_object_data->do_collision_check_using_voxel_map) {  // gripper CAD 파일의 voxel map 이용
        doScanCloudProcessingForCollisionCheck(target_object_data);
    }
    ROS_LOG_INFO("Mask detected num.: %zu", target_object_data->mask_data.mask_confident_idx_set.size());
    // m_pcl_proc.plotCloud(*target_object_data->cloud_scan_base_aligned_with_bin_collision_check_process, 800.0, "plot cloud_scan_base_aligned_with_bin_collision_check_process");

    // update raw mask index 
    target_object_data->mask_data.idx_target_mask_in = target_object_data->mask_data.pre_selected_idx_set[0];
    target_object_data->mask_data.idx_target_mask_process = target_object_data->mask_data.pre_selected_idx_set[0];
 
    ////////////////////////////////////////////////
    //// 1회 측정에 모든 자세 추출
    // 인식된 모든 마스크에 대해 수행
    // clear data
    target_object_data->bp_result_set_grasping_pose.clear(); // pose
    target_object_data->bp_result_set_sub_grasping_pose_set.clear(); // sub_pose_set
    target_object_data->bp_result_set_zig_pose.clear(); // zig_pose
    target_object_data->bp_result_set_matching_accuracy.clear(); // matching accuracy
    target_object_data->bp_result_set_mask_idx.clear(); // selected mask index
    target_object_data->bp_result_set_is_pose_feasible.clear();

	target_object_data->cloud_final_multiple_results_for_collision_check->clear();

    std::vector<std::vector<double>> sub_pose_set;

    size_t candidate_cnt = target_object_data->mask_data.mask_confident_idx_set.size();
    ROS_LOG_INFO("candidate_cnt: %zu", candidate_cnt);
    ROS_LOG_INFO("candidate_cnt: %zu", candidate_cnt);
    ROS_LOG_INFO("candidate_cnt: %zu", candidate_cnt);
    size_t re_matching_cnt = 0;
    for (size_t i = 0; i < candidate_cnt; i++)
    {
        //////////////////////////////////////////////////////////////////////
        //////////////////////////////////////////////////////////////////////
        //////////////////////////////////////////////////////////////////////
        
        ///////////////////////////////
        //// 현재 마스크 정보 불러오기
        pcl::PointCloud<pcl::PointXYZRGBA>::Ptr cloud_mask_sensor(new pcl::PointCloud<pcl::PointXYZRGBA>);
        pcl::PointCloud<pcl::PointXYZRGBNormal>::Ptr cloud_mask_sensor_rgbn(new pcl::PointCloud<pcl::PointXYZRGBNormal>);
        pcl::PointCloud<pcl::PointXYZ>::Ptr cloud_mask_base(new pcl::PointCloud<pcl::PointXYZ>);
        pcl::PointCloud<pcl::PointXYZRGBNormal>::Ptr cloud_mask_base_rgbn(new pcl::PointCloud<pcl::PointXYZRGBNormal>);
        *cloud_mask_sensor = target_object_data->mask_data.cloud_mask_rgba_list[i];
        *cloud_mask_sensor_rgbn = target_object_data->mask_data.cloud_mask_rgbn_list[i];
        *cloud_mask_base = target_object_data->mask_data.mask_cloud_base_aligned_list[i]; // on_points에서 미리 처리된 cloud
        *cloud_mask_base_rgbn = target_object_data->mask_data.mask_cloud_base_aligned_rgbn_list[i];
        // output mask cloud
        pcl::copyPointCloud(*cloud_mask_sensor, *cloud_src);
        pcl::copyPointCloud(*cloud_mask_sensor_rgbn, *cloud_src_rgbn);
        pcl::copyPointCloud(*cloud_mask_base, *cloud_mask_base_aligned);
        pcl::copyPointCloud(*cloud_mask_base_rgbn, *cloud_mask_base_aligned_rgbn);
        
        // update
        target_object_data->mask_data.idx_target_mask_process = i; // current index
        if(i>1) {
            target_object_data->mask_data.pre_selected_idx_set.push_back(i); // selected index update
        }
        ///////////////////////////////

        ///////////////////////////////
        //// update
        *target_object_data->cloud_measured = *cloud_src; // metric: [m]
        *target_object_data->cloud_measured_rgbn = *cloud_src_rgbn; // metric: [m]

        m_math.cloudScaling(*cloud_mask_base_aligned, 1); // m to mm
        m_math.cloudScaling(*cloud_mask_base_aligned_rgbn, 1); // m to mm
        *target_object_data->cloud_base_aligned = *cloud_mask_base_aligned; // metric: [mm]
        *target_object_data->cloud_base_aligned_rgbn = *cloud_mask_base_aligned_rgbn; // metric: [mm]
        ///////////////////////////////
        //////////////////////////////////////////////////////////////////////
        //////////////////////////////////////////////////////////////////////
        //////////////////////////////////////////////////////////////////////

        ROS_LOG_INFO("target_object_data->mask_data.mask_confident_idx_set.size(): %zu", target_object_data->mask_data.mask_confident_idx_set.size());
        ROS_LOG_INFO("target_object_data->mask_data.pre_selected_idx_set.size(): %zu", target_object_data->mask_data.pre_selected_idx_set.size());
        // if(target_object_data->mask_data.mask_confident_idx_set.size() > 1)
        // {
        //     if(target_object_data->mask_data.mask_confident_idx_set.size() < target_object_data->mask_data.pre_selected_idx_set.size()) { break; }
        // }

        //// Visualization
        if (target_object_data->plot_base_aligned_cloud_results)
        {
            pcl::PointCloud<pcl::PointXYZRGBA>::Ptr cloud_plot(new pcl::PointCloud<pcl::PointXYZRGBA>);
            pcl::copyPointCloud(*target_object_data->cloud_base_aligned, *cloud_plot); // metric: [m]
            
            pcl::visualization::PCLVisualizer viewer("Filtering");
            int v1(0);
            int v2(1);
            viewer.createViewPort(0.0, 0.0, 0.5, 1.0, v1);
            viewer.createViewPort(0.5, 0.0, 1.0, 1.0, v2);
            viewer.setBackgroundColor(1, 1, 1, v1);
            viewer.setBackgroundColor(1, 1, 1, v2);
            float txt_color = 0.0; // black text

            // raw cloud is green
            pcl::visualization::PointCloudColorHandlerCustom<pcl::PointXYZRGBA> cloud_raw_color_h(cloud_plot, 10, 10, 255);
            viewer.addPointCloud(cloud_plot, cloud_raw_color_h, "cloud_raw_v1", v1);

            // aligned point cloud is red
            pcl::visualization::PointCloudColorHandlerCustom<pcl::PointXYZRGBA> cloud_align_color_h(cloud_plot, 10, 10, 255);
            viewer.addPointCloud(cloud_plot, cloud_align_color_h, "cloud_aligned", v2);

            // Adding text descriptions in each viewport
            viewer.addText("Black: Original point cloud\nBlue: raw point cloud", 10, 15, 16, txt_color, txt_color, txt_color, "icp_info_1", v1);
            viewer.addText("Black: Original point cloud\nBlue: Downsampling point cloud", 10, 15, 16, txt_color, txt_color, txt_color, "icp_info_2", v2);

            while (!viewer.wasStopped())
            {
                viewer.spinOnce(100);
                boost::this_thread::sleep(boost::posix_time::microseconds(100000));
            }
            viewer.close();
        }

        //// c-2) Matching process - Pre-matching
        doPreMatchingProcess(target_object_data);
        //// c-3) Measured cloud의 FPFH 특징 초기 1회만 미리 산출 - Quick align에서 연산량을 많이 차지함.
        calMeasuredCloudFeatureForQuickAlign(target_object_data);
        //// c-4) Matching process - Quick align and ICP
        doTemplateMatchingProcess(target_object_data);

        ////////////////// Re-matching start
        if(target_object_data->do_re_matching)
        {
            if (target_object_data->is_object_complex_shaped) // Elbow joint
            {
                //// TODO: 이 부분 다시 작성해야 함. 일단 실린더 부분 사용
                if(!target_object_data->is_matching_success)
                {
                    //// TODO: 매칭 실패 시에, 특징 이용하여 일치점 찾는 기능 추가
                    printf("\n\n\n******************************************************\n");
                    printf("******************************************************\n");
                    printf("******************************************************\n");
                    printf("Current mask index: # %zu\n", target_object_data->mask_data.pre_selected_idx_set.back()+1);
                    printf("Matching_accuracy is too low! (matching_accuracy: %0.3f)\n", target_object_data->matching_accuracy);
                    printf("******************************************************\n");
                    printf("******************************************************\n");
                    printf("******************************************************\n\n\n");

                    // 5회 다시 수행
                    for (size_t j = 0; j < target_object_data->cnt_re_matching; j++)
                    {
                        //// c-re) Matching process - Quick align and ICP
                        doTemplateMatchingProcess(target_object_data);
                        if(target_object_data->is_matching_success) {
                            printf("\n\n\n******************************************************\n");
                            printf("******************************************************\n");
                            printf("******************************************************\n");
                            printf("Re-matching Process End! (# of attempts: %zu)\n", j+1);
                            printf("Matching_accuracy! (matching_accuracy: %0.3f)\n", target_object_data->matching_accuracy);
                            printf("******************************************************\n");
                            printf("******************************************************\n");
                            printf("******************************************************\n\n\n");
                            break;
                        } else {
                            printf("\n\n\n******************************************************\n");
                            printf("******************************************************\n");
                            printf("******************************************************\n");
                            printf("Re-matching Processing... (# of attempts: %zu)\n", j+1);
                            printf("Matching_accuracy under the limit (matching_accuracy: %0.3f)\n", target_object_data->matching_accuracy);
                            printf("******************************************************\n");
                            printf("******************************************************\n");
                            printf("******************************************************\n\n\n");
                        }
                    }
                }
            }
            else // Cylinder
            {
                if(target_object_data->matching_accuracy < target_object_data->matching_accuracy_limit)
                {
                    ////////////////////////////////////////////////////////////////////////////////
                    printf("Matching_accuracy is at threshold! (matching_accuracy: %0.3f)\n", target_object_data->matching_accuracy);

                    //// TODO: 아래의 처리는 cylinder 형상의 물체에 적합
                    // pre-processing - major axis translation
                    Eigen::Matrix4f T_init = target_object_data->T_matching_O2B;
                    Eigen::Matrix4f T_result;
                    // cloud_base_aligned, cloud_CAD_uniformly_downsampled - [mm]
                    m_pcl_proc.matchingMajorAxisTranslation(*target_object_data->cloud_base_aligned, *target_object_data->cloud_CAD_uniformly_downsampled, T_init, T_result, false);

                    // precise alignment using ICP
                    CALIGN_PARAMETER align_param;
                    align_param.do_quick_align = target_object_data->do_quick_align;
                    align_param.quick_align_use_cloud_with_mesh_normal = target_object_data->quick_align_use_cloud_with_mesh_normal;
                    align_param.quick_align_z_threshold = target_object_data->quick_align_z_threshold;
                    align_param.icp_max_iter_inner = target_object_data->icp_max_iter_inner;
                    align_param.icp_max_iter_outer = target_object_data->icp_max_iter_outer;
                    align_param.icp_corr_threshold = target_object_data->icp_corr_threshold;
                    align_param.icp_euclidean_fitness_eps = target_object_data->icp_euclidean_fitness_eps;
                    align_param.icp_transformation_eps = target_object_data->icp_transformation_eps;
                    
                    Eigen::Matrix4f T_icp;
                    if(0) {
                        pcl::PointCloud<pcl::PointXYZ>::Ptr cloud_mask_tmp(new pcl::PointCloud<pcl::PointXYZ>);
                        pcl::transformPointCloud(*target_object_data->cloud_base_aligned, *cloud_mask_tmp, T_result);
                        m_math.printCloudMinMax(*target_object_data->cloud_CAD_uniformly_downsampled, "cloud_CAD_uniformly_downsampled in matching process");
                        m_pcl_proc.matchingReg2CADUsingICP4(align_param, *cloud_mask_tmp, *target_object_data->cloud_CAD_uniformly_downsampled, T_icp, false);
                    } else {
                        pcl::PointCloud<pcl::PointXYZRGBNormal>::Ptr cloud_mask_tmp(new pcl::PointCloud<pcl::PointXYZRGBNormal>);
                        pcl::transformPointCloudWithNormals(*target_object_data->cloud_base_aligned_rgbn, *cloud_mask_tmp, T_result);
                        m_math.printCloudMinMax(*target_object_data->cloud_CAD_uniformly_downsampled, "cloud_CAD_uniformly_downsampled in matching process");
                        m_pcl_proc.matchingReg2CADUsingICP4NoEstNormal(align_param, *cloud_mask_tmp, *target_object_data->cloud_CAD_uniformly_downsampled_with_est_normal, T_icp, false);
                    }
                    
                    T_result = T_icp*T_result;

                    pcl::PointCloud<pcl::PointXYZ>::Ptr cloud_tmp(new pcl::PointCloud<pcl::PointXYZ>);
                    pcl::PointCloud<pcl::PointXYZRGB>::Ptr cloud_matching_results(new pcl::PointCloud<pcl::PointXYZRGB>);
                    pcl::transformPointCloud(*target_object_data->cloud_base_aligned, *cloud_tmp, T_result);

                    /////////////////////
                    //// 바로 옆 물체의 노이즈로 인해 실린더 매칭 정확도가 떨어지는 문제
                    /////////////////////
                    if(target_object_data->do_post_eucidean_filtering_for_matching_accuracy)
                    {
                        if(target_object_data->plot_post_processing_euclidean_filtering_results) { m_pcl_proc.plotCloud(*cloud_tmp, 800.0, "cloud_base_aligned - final results"); }
                        
                        //// Euclidean filtering for noise reduction
                        // 빛 반사로 인한 노이즈 제거 - Euclidean clustering 적용
                        bool b_plot_ec = target_object_data->plot_post_processing_euclidean_filtering_results;
                        double ec_tol = 3.0;
                        size_t ec_min_size = target_object_data->euclidean_cluster_min_size;
                        size_t ec_max_size = target_object_data->euclidean_cluster_max_size;

                        //// TODO: 대상 물체 및 voxel filter size에 따라 아래 값이 변경되므로 JSON으로 통합
                        pcl::PointCloud<pcl::PointXYZ>::Ptr cloud_base_aligned_process(new pcl::PointCloud<pcl::PointXYZ>);
                        if (filterUsingEuclideanClustering(*cloud_tmp, *cloud_base_aligned_process, ec_tol, ec_min_size, ec_max_size, b_plot_ec))
                        {
                            *cloud_tmp = *cloud_base_aligned_process;
                        }
                        if(target_object_data->plot_post_processing_euclidean_filtering_results) { m_pcl_proc.plotCloud(*cloud_tmp, 800.0, "cloud_tmp - final results"); }
                        if(target_object_data->plot_post_processing_euclidean_filtering_results) { m_pcl_proc.plotCloud(*cloud_base_aligned_process, 800.0, "cloud_base_aligned - final results"); }
                    }
                    /////////////////////
                    /////////////////////
                    /////////////////////
                    pcl::copyPointCloud(*cloud_tmp, *cloud_matching_results);

                    //// output
                    target_object_data->T_matching_O2B = T_result;
                    target_object_data->T_matching_B2O = T_result.inverse();

                    //// Evaluate matching results
                    target_object_data->matching_accuracy = evaluateMatchingResults("b", *cloud_matching_results, target_object_data->m_OctoMap_CAD);
                    *target_object_data->cloud_matching_results = *cloud_matching_results;
                    printf("----- Re-matching accuracy (object: %s): %0.3f -----\n", target_object_data->target_object_name.c_str(), target_object_data->matching_accuracy);
                    ////////////////////////////////////////////////////////////////////////////////
                }
                else if(target_object_data->matching_accuracy < target_object_data->matching_accuracy < target_object_data->matching_accuracy_limit - 1)
                {
                    //// TODO: 매칭 실패 시에, 특징 이용하여 일치점 찾는 기능 추가
                    if(re_matching_cnt > 1) 
                    {
                        re_matching_cnt = 0;
                        printf("\n\n\n\n\n\n\n******************************************************\n");
                        printf("******************************************************\n");
                        printf("******************************************************\n");
                        printf("Current mask index: # %zu\n", target_object_data->mask_data.pre_selected_idx_set.back()+1);
                        printf("Matching_accuracy is too low! (matching_accuracy: %0.3f)\n", target_object_data->matching_accuracy);
                        printf("******************************************************\n");
                        printf("******************************************************\n");
                        printf("******************************************************\n\n\n");
                        if(target_object_data->mask_data.detection_mode == "mask_rcnn_detection") {
                            selectMaskRCNN(target_object_data, *cloud_src, *cloud_src_rgbn, *cloud_mask_base_aligned, *cloud_mask_base_aligned_rgbn);
                        } else if(target_object_data->mask_data.detection_mode == "mask_sam_detection") {
                            selectMaskSAM(target_object_data, *cloud_src, *cloud_src_rgbn, *cloud_mask_base_aligned, *cloud_mask_base_aligned_rgbn);
                        }
                        *target_object_data->cloud_measured = *cloud_src; // metric: [m]
                        *target_object_data->cloud_measured_rgbn = *cloud_src_rgbn; // metric: [m]
            
                        m_math.cloudScaling(*cloud_mask_base_aligned, 1); // m to mm
                        m_math.cloudScaling(*cloud_mask_base_aligned_rgbn, 1); // m to mm
                        *target_object_data->cloud_base_aligned = *cloud_mask_base_aligned; // metric: [mm]
                        *target_object_data->cloud_base_aligned_rgbn = *cloud_mask_base_aligned_rgbn; // metric: [mm]
                    }
                    else
                    {
                        printf("\n\n\n\n\n\n\n******************************************************\n");
                        printf("******************************************************\n");
                        printf("******************************************************\n");
                        printf("Matching_accuracy is too low! (matching_accuracy: %0.3f)\n", target_object_data->matching_accuracy);
                        printf("******************************************************\n");
                        printf("******************************************************\n");
                        printf("******************************************************\n\n\n");

                        re_matching_cnt++;
                    }
                    continue;
                }
            }
        }
        ////////////////// Re-matching end

        //// For collision check - Matching된 CAD 이어 붙이기
        // mergeMatchingCAD2ScanResults(target_object_data);
        ROS_LOG_WARN("[%s] removeObjectMeasuredCloudUsingMaskForCollisionCheck Start", __func__);
        removeObjectMeasuredCloudUsingMaskForCollisionCheck(target_object_data);
        ROS_LOG_WARN("[%s] removeObjectMeasuredCloudUsingMaskForCollisionCheck End", __func__);
        ROS_LOG_WARN("[%s] removeObjectMeasuredCloudUsingOBBForCollisionCheck Start", __func__);
        removeObjectMeasuredCloudUsingOBBForCollisionCheck(target_object_data);
        ROS_LOG_WARN("[%s] removeObjectMeasuredCloudUsingOBBForCollisionCheck End", __func__);

        //// d) Cal. grasping pose
        bool is_matching_success = target_object_data->matching_accuracy > target_object_data->matching_accuracy_limit;
        bool is_pose_detection_success = calGraspingPose(target_object_data);
        if(is_pose_detection_success && is_matching_success) 
        { 
            printf("\n\n\n******************************************************\n");
            printf("******************************************************\n");
            printf("******************************************************\n");
            //// Monitoring
            if(target_object_data->is_object_pose_flipped) {
	            printf("----- Object flipped in post processing! - 180 deg w.r.t {O} Flipped!  -----\n");
                Eigen::Vector3f vec_flip_check = target_object_data->measured_object_normal_for_flip_check;
                printf("vec_flip_check: %0.3f, %0.3f, %0.3f\n", vec_flip_check[0], vec_flip_check[1], vec_flip_check[2]);
                printf("------------------------------------------------------\n");
            } else {
	            printf("----- No object flip in post processing! -----\n");
                printf("------------------------------------------------------\n");
            }
            printf("Matching Process Finished! (# of attempts: %zu)\n", i+1);
            printf("Current mask index: # %zu (Mask detection mode: %s)\n", target_object_data->mask_data.pre_selected_idx_set.back()+1, target_object_data->mask_data.detection_mode.c_str());
            printf("Matching_accuracy(success): %0.3f)\n", target_object_data->matching_accuracy);
            printf("******************************************************\n");
            printf("******************************************************\n");
            printf("******************************************************\n\n\n");


            //// TODO: 완전 자세가 없으면 대체 자세를 넣도록 하는 기능 추가, 현재는 1개만 넣어서 보내며 사실상 사용하지 않음
            sub_pose_set.clear();
            sub_pose_set.push_back(target_object_data->grasping_sub_pose); 
            size_t current_selected_mask_idx = target_object_data->mask_data.pre_selected_idx_set.back()+1;

            ////////////////////////////////////////////
            // update data
            target_object_data->bp_result_set_grasping_pose.push_back(target_object_data->grasping_pose); // pose
            target_object_data->bp_result_set_sub_grasping_pose_set.push_back(sub_pose_set); // sub_pose_set
            target_object_data->bp_result_set_zig_pose.push_back(target_object_data->zig_pose); // zig_pose
            target_object_data->bp_result_set_matching_accuracy.push_back(target_object_data->matching_accuracy); // matching accuracy
            target_object_data->bp_result_set_mask_idx.push_back(current_selected_mask_idx); // selected mask index
            target_object_data->bp_result_set_is_pose_feasible.push_back(true); // is_pose_feasible
            
        }
        else // 충돌이 발생하거나 로봇 작업영역에서 벗어난 경우 Skip
        {
            ROS_LOG_INFO("candidate_cnt: %zu", candidate_cnt);
            ROS_LOG_INFO("candidate_cnt: %zu", candidate_cnt);
            ROS_LOG_INFO("candidate_cnt: %zu", candidate_cnt);
            if(i + 1 == candidate_cnt) { 
                ROS_LOG_INFO("Candidate is empty!: %zu", candidate_cnt);
                break; 
            }
            printf("\n\n\n******************************************************\n");
            if(!is_pose_detection_success) {
                printf("Pose detection failure!\n");
            }
            if(!is_matching_success) {
                printf("Matching accuracy is too low!\n");
            }
            printf("******************************************************\n");
            printf("******************************************************\n");
            printf("Current Mask Pose infeasible!\n");
            printf("Current mask index: # %zu\n", target_object_data->mask_data.pre_selected_idx_set.back()+1);
            printf("Matching_accuracy: %0.3f)\n", target_object_data->matching_accuracy);
            printf("******************************************************\n");
            printf("******************************************************\n");
            printf("******************************************************\n\n\n");

            // log

            ////////////////////////////////////////////
            // update data
            std::vector<double> infeasible_tmp(6, 0.0);
            sub_pose_set.clear();
            sub_pose_set.push_back(infeasible_tmp); 
            size_t current_selected_mask_idx = target_object_data->mask_data.pre_selected_idx_set.back()+1;

            target_object_data->bp_result_set_grasping_pose.push_back(infeasible_tmp); // pose
            target_object_data->bp_result_set_sub_grasping_pose_set.push_back(sub_pose_set); // sub_pose_set
            target_object_data->bp_result_set_zig_pose.push_back(infeasible_tmp); // zig_pose
            target_object_data->bp_result_set_matching_accuracy.push_back(0.0); // matching accuracy
            target_object_data->bp_result_set_mask_idx.push_back(current_selected_mask_idx); // selected mask index
            target_object_data->bp_result_set_is_pose_feasible.push_back(false); // is_pose_feasible
        }


        //// 다음 물체에서의 충돌확인을 위해 앞서 제거했던 부분에 매칭된 CAD 파일을 병합함
        //// 다음 물체에서의 충돌확인을 위해 앞서 제거했던 부분에 매칭된 CAD 파일을 병합함
        //// Object CAD cloud
        // merging matching results w.r.t {B}
        pcl::PointCloud<pcl::PointXYZ>::Ptr cloud_object_CAD(new pcl::PointCloud<pcl::PointXYZ>);
        pcl::copyPointCloud(*target_object_data->cloud_CAD_uniformly_downsampled, *cloud_object_CAD);
        Eigen::Matrix4f T_B2O = target_object_data->T_matching_B2O;
        pcl::transformPointCloud(*cloud_object_CAD, *cloud_object_CAD, T_B2O);
        //// update
        *target_object_data->cloud_scan_base_aligned_with_bin_collision_check_process += *cloud_object_CAD; // [mm]
        //// 다음 물체에서의 충돌확인을 위해 앞서 제거했던 부분에 매칭된 CAD 파일을 병합함
        //// 다음 물체에서의 충돌확인을 위해 앞서 제거했던 부분에 매칭된 CAD 파일을 병합함


        //// Merging cloud for RVIZ viewer 
        *target_object_data->cloud_final_multiple_results_for_collision_check += *target_object_data->cloud_final_results_for_collision_check; // [mm]
    }

    // 인식된 mask가 없는 경우
    if(candidate_cnt == 0)
    {
        target_object_data->is_feasible_pose = false;
    }

    // update
    target_object_data->detected_mask_num = target_object_data->mask_data.mask_confident_idx_set.size(); // 현재 인식된 마스크 개수

    for (size_t i = 0; i < target_object_data->bp_result_set_is_pose_feasible.size(); i++)
    {
        if(target_object_data->bp_result_set_is_pose_feasible[i]) {
            ROS_LOG_INFO("Mask #%zu - Feasible pose! (icp_matchingMultipleBinPicking)", i+1);
            std::vector<double> tmp1 = target_object_data->bp_result_set_grasping_pose[i];
            std::vector<double> tmp2 = target_object_data->bp_result_set_zig_pose[i];
            printf("Grasping Pose:     %0.5f, %0.5f, %0.5f, %0.3f, %0.3f, %0.3f\n", tmp1[0], tmp1[1], tmp1[2], tmp1[3], tmp1[4], tmp1[5]);
            printf("Zig Pose:          %0.5f, %0.5f, %0.5f, %0.3f, %0.3f, %0.3f\n", tmp2[0], tmp2[1], tmp2[2], tmp2[3], tmp2[4], tmp2[5]);
            printf("Matching_accuracy: %0.3f\n", target_object_data->bp_result_set_matching_accuracy[i]);
        }
        else {
            ROS_LOG_INFO("Mask #%zu - Infeasible pose! (icp_matchingMultipleBinPicking)", i+1);
        }
    }
    // output
    vec_out = target_object_data->grasping_pose; // output
    //// TODO: 아래 변수 처리
    vec_out_sub_pose_set.push_back(target_object_data->grasping_sub_pose); 

    zig_pose = target_object_data->zig_pose;
    matching_accuracy = target_object_data->matching_accuracy;

}

void TEMPLATE_MATCHING::icp_matchingGlobalToolCalibration(bool do_measured_cloud_process, const pcl::PointCloud<pcl::PointXYZRGBNormal> &cloud_in, const pcl::PointCloud<pcl::PointXYZRGBNormal> &cloud_scan, const int target_id, const std::string target_name, const Eigen::VectorXf q_scan, std::vector<double> &vec_out, std::vector<std::vector<double>> &vec_out_sub_pose_set, double &matching_accuracy, bool do_scan_sampling, size_t sampling_num, bool b_plot)
{
    ROS_LOG_INFO("Template matching(global tool calibration)!");
    vec_out_sub_pose_set.clear();

    pcl::PointXYZ minPt, maxPt;
    pcl::PointCloud<pcl::PointXYZ>::Ptr cloud_src(new pcl::PointCloud<pcl::PointXYZ>);
    pcl::PointCloud<pcl::PointXYZRGBNormal>::Ptr cloud_src_rgbn(new pcl::PointCloud<pcl::PointXYZRGBNormal>);
    pcl::PointCloud<pcl::PointXYZ>::Ptr cloud_mask_base_aligned(new pcl::PointCloud<pcl::PointXYZ>);
    pcl::PointCloud<pcl::PointXYZRGBNormal>::Ptr cloud_mask_base_aligned_rgbn(new pcl::PointCloud<pcl::PointXYZRGBNormal>);
    pcl::PointCloud<pcl::PointXYZ>::Ptr cloud_tgt(new pcl::PointCloud<pcl::PointXYZ>);
    pcl::PointCloud<pcl::PointXYZ>::Ptr cloud_scan_raw(new pcl::PointCloud<pcl::PointXYZ>);
    pcl::copyPointCloud(cloud_in, *cloud_src);
    pcl::copyPointCloud(cloud_scan, *cloud_scan_raw);

    //// a) Load template data
    CTARGET_OBJECT_DATA* target_object_data = m_ptr_template_list[target_id - 1];

    //// b) Measured cloud processing and plot results
    *target_object_data->cloud_scan_raw = *cloud_scan_raw; // metric: [m]
    *target_object_data->cloud_measured = *cloud_src; // metric: [m]

    ///////////////////////////
    ///////////////////////////
    ///////////////////////////
    // Normal estimation for measured cloud - Matching 후 Post processing에 사용
    //  - input cloud는 센서 좌표계 기준의 결과를 입력
    Eigen::Vector3d sensor_origin = {0.0, 0.0, 0.0};
    //// TODO: 적절한 K 설정 필요
    m_pcl_proc.cloudNormalEst2Measured(*cloud_src, *cloud_src_rgbn, 10, sensor_origin, 80.0); // K = 10, angle: 80 [deg]
    *target_object_data->cloud_measured_rgbn = *cloud_src_rgbn; // metric: [m]
    ///////////////////////////
    ///////////////////////////
    ///////////////////////////

    target_object_data->robot_scan_JS_position = q_scan;    
    target_object_data->sampling_num = sampling_num;
    // m_pcl_proc.plotCloud(*cloud_scan_raw, 0.800, "plot cloud_scan_raw");

    if (do_measured_cloud_process)
    {
        target_object_data->debug_mode = false;
        doMeasuredCloudProcessing(target_object_data); // Mask cloud processing
    }

    //// Scan cloud processing for collision check (merging with bin CAD)
    if (target_object_data->do_collision_check_using_voxel_map) // gripper CAD 파일의 voxel map 이용
    {
        doScanCloudProcessingForCollisionCheck(target_object_data);
    }
    // m_pcl_proc.plotCloud(*target_object_data->cloud_scan_base_aligned_with_bin_collision_check_process, 800.0, "plot cloud_scan_base_aligned_with_bin_collision_check_process");

    // update raw mask index 
    target_object_data->mask_data.idx_target_mask_in = target_object_data->mask_data.pre_selected_idx_set[0];
    target_object_data->mask_data.idx_target_mask_process = target_object_data->mask_data.pre_selected_idx_set[0];

    size_t candidate_cnt = 1;
    size_t re_matching_cnt = 0;
    for (size_t i = 0; i < candidate_cnt; i++)
    {
        if(target_object_data->mask_data.mask_confident_idx_set.size() > 1)
        {
            if(target_object_data->mask_data.mask_confident_idx_set.size() == target_object_data->mask_data.pre_selected_idx_set.size()) { break; }
        }

        //// Visualization
        if (target_object_data->plot_base_aligned_cloud_results)
        {
            pcl::PointCloud<pcl::PointXYZRGBA>::Ptr cloud_plot(new pcl::PointCloud<pcl::PointXYZRGBA>);
            pcl::copyPointCloud(*target_object_data->cloud_base_aligned, *cloud_plot); // metric: [m]
            
            pcl::visualization::PCLVisualizer viewer("Filtering");
            int v1(0);
            int v2(1);
            viewer.createViewPort(0.0, 0.0, 0.5, 1.0, v1);
            viewer.createViewPort(0.5, 0.0, 1.0, 1.0, v2);
            viewer.setBackgroundColor(1, 1, 1, v1);
            viewer.setBackgroundColor(1, 1, 1, v2);
            float txt_color = 0.0; // black text

            // raw cloud is green
            pcl::visualization::PointCloudColorHandlerCustom<pcl::PointXYZRGBA> cloud_raw_color_h(cloud_plot, 10, 10, 255);
            viewer.addPointCloud(cloud_plot, cloud_raw_color_h, "cloud_raw_v1", v1);

            // aligned point cloud is red
            pcl::visualization::PointCloudColorHandlerCustom<pcl::PointXYZRGBA> cloud_align_color_h(cloud_plot, 10, 10, 255);
            viewer.addPointCloud(cloud_plot, cloud_align_color_h, "cloud_aligned", v2);
            // viewer.setPointCloudRenderingProperties(pcl::visualization::PCL_VISUALIZER_POINT_SIZE, 1, "cloud_aligned name");

            // Adding text descriptions in each viewport
            viewer.addText("Black: Original point cloud\nBlue: raw point cloud", 10, 15, 16, txt_color, txt_color, txt_color, "icp_info_1", v1);
            viewer.addText("Black: Original point cloud\nBlue: Downsampling point cloud", 10, 15, 16, txt_color, txt_color, txt_color, "icp_info_2", v2);

            while (!viewer.wasStopped())
            {
                viewer.spinOnce(100);
                boost::this_thread::sleep(boost::posix_time::microseconds(100000));
            }
            viewer.close();
        }

        //// 충돌 발생 시, Candidate pose 생성 (이때 mask는 on_points함수에서 처리되어 저장된 cloud를 불러와 사용) 
        if(i>0) {ROS_LOG_INFO("Candidate pose generation start!");}

        // Monitoring results
        bool b_monitoring_results = false;
        if (b_monitoring_results)
        {
            std::cout << "DH: " << std::endl
                    << target_object_data->DH_parameters << std::endl;
            std::cout << "T_E2E: " << std::endl
                    << target_object_data->T_E2E << std::endl;
            std::cout << "T_E2S: " << std::endl
                    << target_object_data->T_E2S << std::endl;
            printf("cad_height_z: %fmm\n", target_object_data->cad_height_z);
        }

        //// c) Matching process - Quick align and ICP
        doTemplateMatchingProcessBefore(target_object_data);

        if (b_monitoring_results)
        {
            printf("\n\n\n******************************************************\n");
            printf("measured data size: %zu\n", target_object_data->cloud_base_aligned->size());
            printf("CAD data size: %zu\n", target_object_data->cloud_CAD_for_quick_align->size());
            printf("******************************************************\n\n\n");
            m_math.printCloudMinMax(*target_object_data->cloud_base_aligned, "cloud_base_aligned in matching process");
            m_math.printCloudMinMax(*target_object_data->cloud_CAD_for_quick_align, "cloud_CAD_for_quick_align in matching process");
        }
    }

    // 인식된 mask가 없는 경우
    if(candidate_cnt == 0)
    {
        target_object_data->is_feasible_pose = false;
    }

    // output
    std::vector<double> output_tmp(6, 0.0);
    vec_out = output_tmp; // output
    vec_out_sub_pose_set.push_back(target_object_data->grasping_sub_pose); 
    matching_accuracy = target_object_data->matching_accuracy;

    // update
    target_object_data->detected_mask_num = target_object_data->mask_data.mask_confident_idx_set.size(); // 현재 인식된 마스크 개수
    if(target_object_data->is_feasible_pose){
        ROS_LOG_INFO("is_feasible_pose (global tool calibration) ---- true");
    } else {
      ROS_LOG_INFO("is_feasible_pose(global tool calibration) ---- false");  
    }
    m_math.printHTM(target_object_data->T_B2E, "T_B2E");
    m_math.printHTM(target_object_data->T_matching_O2B, "T_matching_O2B");
}

std::vector<double> TEMPLATE_MATCHING::transformSensorPose2RobotPose(const Eigen::Matrix4f &T_in, const Eigen::VectorXf q_scan, const int target_id, const std::string target_name)
{
    ROS_LOG_INFO("transformSensorPose2RobotPose(bin picking)!");

    //// a) Load template data
    CTARGET_OBJECT_DATA* target_object_data = m_ptr_template_list[target_id - 1];
    target_object_data->robot_scan_JS_position = q_scan;

    Eigen::Matrix4f T_B2E;
    Eigen::Matrix4f T_B2S;
    if(target_object_data->is_eye_in_hand) 
    {

#if DO_FK_CALCULATION
        ROS_LOG_WARN("[%s][DO_FK_CALCULATION] - TRUE", __func__);
        //// d) Cal. grasping pose
        double DH[6][4];
        for (int i = 0; i < 6; i++)
        {
            for (int j = 0; j < 4; j++)
            {
                DH[i][j] = target_object_data->DH_parameters(i, j);
            }
        }
        Eigen::Matrix4f T_init;

        // Considering calibrated joint angle
        Eigen::VectorXf current_q(6);
        for (int i = 0; i < 6; i++) current_q[i] = target_object_data->robot_scan_JS_position[i] + target_object_data->calibration_delta_q[i]; // [deg]
        m_math.forwardKinematics(DH, current_q, T_init);
        T_B2E = T_init;
#else // 로봇 제어기에서 산출되는 T_B2E를 바로 이용
        ROS_LOG_WARN("[%s][DO_FK_CALCULATION] - FALSE", __func__);
        //// TODO: 250223
        //// pose2htm --> T_B2E
        std::vector<double> current_x(6, 0.0);
        for (int i = 0; i < 3; i++) {
            current_x[i] = target_object_data->robot_scan_CS_pose[i] * 1000.0; // [mm]
            current_x[i+3] = target_object_data->robot_scan_CS_pose[i+3] * DEGTORAD; // [rad]
        }
        ROS_LOG_WARN("[%s] current_x [m, deg]: %0.5f, %0.5f, %0.5f, %0.2f, %0.2f, %0.2f", __func__, current_x[0], current_x[1], current_x[2], current_x[3], current_x[4], current_x[5]);
        T_B2E = m_math.pose2htm(current_x); // [mm]
#endif

        T_B2E = T_B2E * target_object_data->T_E2E;
        // m_math.printHTM(T_B2E, "T_B2E");
        T_B2S = T_B2E * target_object_data->T_E2S; // HTM - Robot base(B) to Camera(S)
    }
    else 
    {
        ROS_LOG_WARN("EYE-TO-HAND SCANNER! [transformSensorPose2RobotPose]");
        T_B2S = target_object_data->T_B2S_global;
    }
   
    Eigen::Matrix4f T_tgt = T_B2S*T_in;

    std::vector<double> grasping_pose = m_math.htm2pose_mm2m(T_tgt, "main"); // [mm] to [m]
    return grasping_pose;
}

void TEMPLATE_MATCHING::initializeTemplate()
{
    try
    {
        importGripperJSON(m_grp_data);
        importBinJSON(m_bin_data);
        importOptimizationJSON(m_optimization_input);

        //// JSON File path
        std::stringstream target_object_list_path;
        target_object_list_path << m_package_path << "/config/target_object_list.json";
        std::ifstream ifs_target_object_list(target_object_list_path.str().c_str());
        json j_target_object_list = json::parse(ifs_target_object_list);
        // Target object
        std::vector<std::string> target_name_list = j_target_object_list["target_name"].get<std::vector<std::string> >();
        if(target_name_list.size() == 0) {throw std::string("The size of target_name_list is zero");}
        m_template_list.clear();
        m_ptr_template_list.clear();
        m_template_list.resize(target_name_list.size());
        for (size_t i = 0; i < target_name_list.size(); i++)
        {
            std::string target_name = target_name_list[i];
            CTARGET_OBJECT_DATA target_object_data;
            initializeTargetObjectData(target_object_data);
            target_object_data.target_name = target_name;
            target_object_data.target_id = i+1;
            m_template_list[i] = target_object_data;

            CTARGET_OBJECT_DATA* ptr_object_data = &m_template_list[i];
            m_ptr_template_list.push_back(ptr_object_data);
            
            printf("----- JSON import & voxelization finished! - target object: %s -----\n\n", target_object_data.target_name.c_str());
        }
        for (size_t i = 0; i < target_name_list.size(); i++) printf("----- JSON import & voxelization finished! - target object: %s -----\n\n", m_ptr_template_list[i]->target_name.c_str());
        printf("\n\n\n");
        ROS_LOG_INFO("Template initialize - Success!");
    }
    catch (std::string err)
    {
        ROS_LOG_INFO("Template initialize - Failure!");
    }
}

void TEMPLATE_MATCHING::setTargetObjectTemplate(const size_t &target_idx, bool do_overwrite)
{
    if(m_ptr_template_list[target_idx]->is_JSON_imported && !do_overwrite) return;
    try
    {
        printf("\n\n ********** Target object JSON import start **********\n");

        //// Color map for learning quick matching 
        std::stringstream color_map_quick_cad_learning_path;
        color_map_quick_cad_learning_path << m_package_path << "/config/color_map_quick_cad_learning.json";
        std::ifstream ifs_color_map_quick_cad_learning(color_map_quick_cad_learning_path.str().c_str());
        json j_color_map_quick_cad_learning = json::parse(ifs_color_map_quick_cad_learning);
        int color_map_cnt = j_color_map_quick_cad_learning["data_num"];
        std::vector<std::vector<double>> color_map(color_map_cnt);
        for (int i = 0; i < color_map_cnt; i++)
        {
            std::vector<double> color_tmp = j_color_map_quick_cad_learning["color_map"][i].get<std::vector<double>>();
            color_map[i] = color_tmp;
        }

        ////////////////////////////////////////////////////////////////////////
        //// JSON import
        printf("\n\n----- JSON import & voxelization start! - target object: %s -----\n", m_ptr_template_list[target_idx]->target_name.c_str());
        // a) import JSON
        importTargetJSONFiles(m_ptr_template_list[target_idx], m_grp_data, m_bin_data);
        // b) color map
        m_ptr_template_list[target_idx]->color_map = color_map;
        // c) optimization input
        m_ptr_template_list[target_idx]->optimization_input = m_optimization_input;
        // JSON load Success
        m_ptr_template_list[target_idx]->is_JSON_imported = true;
        printf("----- JSON import & voxelization finished! - target object: %s -----\n\n", m_ptr_template_list[target_idx]->target_name.c_str());
        ////////////////////////////////////////////////////////////////////////
        printf("\n\n\n");
        ROS_LOG_INFO("Template load (target object: %s) - Success!", m_ptr_template_list[target_idx]->target_name.c_str());
    }
    catch (std::string err)
    {
        ROS_LOG_INFO("Template load (target object: %s) - Failure!", m_ptr_template_list[target_idx]->target_name.c_str());
    }
}


void TEMPLATE_MATCHING::setTargetObjectRobotParameters(const size_t &target_idx, const std::vector<double> &dh, const std::vector<double> &tcp_default, const std::vector<double> &tcp)
{
    try
    {
        printf("\n\n ********** [target_idx: %zu] Set Robot Parameters Start **********\n", target_idx);
        ////////////////////////////////////////////////////////////////////////
        
        Eigen::MatrixXf DH_parameters(6, 4);
        Eigen::VectorXf calibration_delta_q(6);
        Eigen::VectorXf robot_tcp_default(6);
        Eigen::VectorXf robot_tcp(6);
        for (int i = 0; i < 6; i++) {
            for (int j = 0; j < 4; j++) {
                if (j == 0 || j == 2) {
                    DH_parameters(i, j) = 1000.0 * dh[i * 4 + j]; // m to mm
                } else {
                    DH_parameters(i, j) = DEGTORAD * dh[i * 4 + j]; // [deg] to [rad]
                }
            }
        }
        ROS_LOG_WARN("THIS1");
        // Robot calibration delta q
        for (int i = 0; i < 6; i++) {
            calibration_delta_q[i] = RADTODEG * DH_parameters(i, 3);
        }
        ROS_LOG_WARN("THIS2");
        // Robot tcp
        for (int i = 0; i < 3; i++) {
            robot_tcp_default[i] = tcp_default[i]; // [m]
            robot_tcp_default[i + 3] = DEGTORAD*tcp_default[i + 3]; // [rad]

        }
        ROS_LOG_WARN("THIS3");
        for (int i = 0; i < 3; i++) {
            robot_tcp[i] = tcp[i]; // [m]
            robot_tcp[i + 3] = DEGTORAD*tcp[i + 3]; // [rad]
        }
        ROS_LOG_WARN("THIS4");
        ///////////////////////////////////////////////////////
        m_ptr_template_list[target_idx]->DH_parameters = DH_parameters; // [mm], [rad]
        m_ptr_template_list[target_idx]->calibration_delta_q = calibration_delta_q;
        m_ptr_template_list[target_idx]->robot_tcp_default = robot_tcp_default; // [m], [rad]
        m_ptr_template_list[target_idx]->robot_tcp = robot_tcp; // [m], [rad]
        ////////////////////////////////////////////////////////////////////////
        ROS_LOG_WARN("THIS5");
        ROS_LOG_INFO("Set Robot Parameters (target object: %s) - Success!", m_ptr_template_list[target_idx]->target_name.c_str());
    }
    catch (std::string err)
    {
        ROS_LOG_INFO("Set Robot Parameters (target object: %s) - Failure!", m_ptr_template_list[target_idx]->target_name.c_str());
    }
}

void TEMPLATE_MATCHING::initializeGlobalCalibrationToolTemplate(const std::vector<double> &dh, const std::vector<double> &tcp_default, const std::vector<double> &tcp)
{
    try
    {
        //// Initialize
        importGripperJSON(m_grp_data);
        importBinJSON(m_bin_data);
        importOptimizationJSON(m_optimization_input);

        //////////////////////////////////////////

        //// Global calibration tool 
        m_template_tool_list.clear();
        m_ptr_template_tool_list.clear();
        m_template_tool_list.resize(1);
        CTARGET_OBJECT_DATA global_calibration_tool_data;
        initializeTargetObjectData(global_calibration_tool_data);
        global_calibration_tool_data.target_name = "global_calibration_tool";
        m_template_tool_list[0] = global_calibration_tool_data;

        CTARGET_OBJECT_DATA* ptr_tool_data = &m_template_tool_list[0];
        m_ptr_template_tool_list.push_back(ptr_tool_data);

        printf("\n\n\n");
        ROS_LOG_INFO("Template (Global Calibration Tool) initialize - Success!");


        //// Color map for learning quick matching 
        std::stringstream color_map_quick_cad_learning_path;
        color_map_quick_cad_learning_path << m_package_path << "/config/color_map_quick_cad_learning.json";
        std::ifstream ifs_color_map_quick_cad_learning(color_map_quick_cad_learning_path.str().c_str());
        json j_color_map_quick_cad_learning = json::parse(ifs_color_map_quick_cad_learning);
        int color_map_cnt = j_color_map_quick_cad_learning["data_num"];
        std::vector<std::vector<double>> color_map(color_map_cnt);
        for (int i = 0; i < color_map_cnt; i++)
        {
            std::vector<double> color_tmp = j_color_map_quick_cad_learning["color_map"][i].get<std::vector<double>>();
            color_map[i] = color_tmp;
        }

        ////////////////////////////////////////////////////////////////////////
        //// JSON import
        printf("\n\n----- JSON import & voxelization start! - target object: %s -----\n", m_ptr_template_tool_list[0]->target_name.c_str());
        // a) import JSON
        importGlobalCalibrationToolJSON(m_ptr_template_tool_list[0], m_grp_data, m_bin_data);

        // b) color map
        m_ptr_template_tool_list[0]->color_map = color_map;
        // c) optimization input
        m_ptr_template_tool_list[0]->optimization_input = m_optimization_input;
        // JSON load Success
        m_ptr_template_tool_list[0]->is_JSON_imported = true;
        printf("----- JSON import & voxelization finished! - target object: %s -----\n\n", m_ptr_template_tool_list[0]->target_name.c_str());
        ////////////////////////////////////////////////////////////////////////
        printf("\n\n\n");
        ROS_LOG_INFO("Template load (target object: %s) - Success!", m_ptr_template_tool_list[0]->target_name.c_str());

        try
        {
            printf("\n\n ********** Set Robot Parameters Start **********\n");
            ////////////////////////////////////////////////////////////////////////
            Eigen::MatrixXf DH_parameters(6, 4);
            Eigen::VectorXf calibration_delta_q(6);
            Eigen::VectorXf robot_tcp_default(6);
            Eigen::VectorXf robot_tcp(6);
            for (int i = 0; i < 6; i++)
            {
                for (int j = 0; j < 4; j++)
                {
                    if (j == 0 || j == 2)
                    {
                        DH_parameters(i, j) = 1000.0 * dh[i * 4 + j];
                    } // m to mm
                    else
                    {
                        DH_parameters(i, j) = dh[i * 4 + j]; // [rad]
                    }
                }
            }
            // Robot calibration delta q
            for (int i = 0; i < 6; i++) calibration_delta_q[i] = RADTODEG * DH_parameters(i, 3);
            // Robot tcp
            for (int i = 0; i < 6; i++) robot_tcp_default[i] = tcp_default[i]; // [m], [rad]
            for (int i = 0; i < 6; i++) robot_tcp[i] = tcp[i]; // [m], [rad]

            ///////////////////////////////////////////////////////
            m_ptr_template_tool_list[0]->DH_parameters = DH_parameters; // [mm], [rad]
            m_ptr_template_tool_list[0]->calibration_delta_q = calibration_delta_q;
            m_ptr_template_tool_list[0]->robot_tcp_default = robot_tcp_default; // [m], [rad]
            m_ptr_template_tool_list[0]->robot_tcp = robot_tcp; // [m], [rad]
            ////////////////////////////////////////////////////////////////////////
            ROS_LOG_INFO("Set Robot Parameters (target object: %s) - Success!", m_ptr_template_tool_list[0]->target_name.c_str());
        }
        catch (std::string err)
        {
            ROS_LOG_INFO("Set Robot Parameters (target object: %s) - Failure!", m_ptr_template_tool_list[0]->target_name.c_str());
        }
    }
    catch (std::string err)
    {
        ROS_LOG_INFO("Template initialize (Global Calibration Tool) - Failure!");
    }
}

void TEMPLATE_MATCHING::setTemplateParameters()
{
    ROS_LOG_INFO("Template Set Parameters");
    try
    {
        // Target object
        for (size_t i = 0; i < m_ptr_template_list.size(); i++)
        {
            printf("----- JSON Set Parameters Start! - target object: %s -----\n", m_ptr_template_list[i]->target_name.c_str());
            //// JSON File path
            std::stringstream robot_config_path, template_path;
            robot_config_path << m_package_path << "/config/robot_config.json";
            template_path << m_package_path << "/config/template_" << m_ptr_template_list[i]->target_name << ".json";
            importRobotConfigJSON(m_ptr_template_list[i], robot_config_path.str()); // parameter update
            importTargetObjectJSON(m_ptr_template_list[i], template_path.str()); // parameter update
            
            printf("----- JSON Set Parameters Finished! - target object: %s -----\n", m_ptr_template_list[i]->target_name.c_str());
        }
        ROS_LOG_INFO("Template Set Parameters - Success!");
    }
    catch (std::string err)
    {
        ROS_LOG_INFO("Template Set Parameters - Failure!");
    }
}

