            // pcl::transformPointCloud(*cloud_major_segment_process, *cloud_major_segment_process, T_matching_O2B.inverse());
            pcl::transformPointCloudWithNormals(*cloud_major_segment_process_rgbn, *cloud_major_segment_process_rgbn, T_matching_O2B.inverse());
            pcl::copyPointCloud(*cloud_major_segment_process_rgbn, *cloud_major_segment_process);
