            m_pcl_proc.matchingReg2CADUsingICP4NoEstNormal(align_param, *cloud_post_proc_tmp, *cloud_CAD_uniformly_downsampled_with_est_normal, T_icp_post_proc, false);

            //// 변경 GICP
            // m_pcl_proc.matchingReg2CADUsingGeneralizedICP1NoEstNormal(align_param, *cloud_post_proc_tmp, *cloud_CAD_uniformly_downsampled_with_est_normal, T_icp_post_proc, false);

