            m_pcl_proc.matchingSurfaceCheckAndICPVer1(align_param, *cloud_major_segment, *cloud_base_aligned_rgbn, *cloud_CAD_uniformly_downsampled_with_mesh_normal, md_KdTree_octoMap_CAD, T_init_post_proc, T_B2S, T_result_post_proc, false);
            pcl::transformPointCloud(*cloud_base_aligned, *cloud_tmp, T_result_post_proc);
