/** @brief Korean: 입력된 회전축, 회전각도를 이용하여 회전 및 변환행렬을 계산한다.
 * @param[in] angle : 회전각도
 * @param[out] rotM : 회전축을 중심으로 회전각도만큼 회전한 회전행렬
 * @param[out] HTM : 회전축을 중심으로 회전각도만큼 회전한 변환행렬
 * @param[in] direction : 회전 축 설정 (0: Rx, 1: Ry, 2: Rz)
 */
bool TEMPLATE_MATCHING::modify2UserDefinedFixedOrientationForComplexShapeMultiThreaded(CTARGET_OBJECT_DATA &target_object_data, const Eigen::Matrix4f &T_O2E, Eigen::Matrix4f &T_out)
{
    bool func_debug_mode = false;
    mtx.lock();
    Eigen::Matrix4f T_B2O = target_object_data.T_matching_B2O;
    Eigen::Matrix4f T_O2B = target_object_data.T_matching_O2B;
    mtx.unlock();
    Eigen::Matrix4f T_O2E_raw = T_O2E;
    Eigen::Matrix4f T_B2O_process = T_B2O;

    /////////////////////////////////////////////////////////////////////////
    // a) (raw data) HTM from template matching results
    Eigen::Matrix4f T_O2E_process = T_O2E_raw;
    Eigen::Matrix4f T_B2E_raw = T_B2O*T_O2E_raw;

    Eigen::Vector3f custom_vector_major_axis;
    Eigen::Vector3f vec_global_z;
    Eigen::Vector3f vec_B2E_modified_x;
    Eigen::Vector3f vec_B2E_tmp_x;
    Eigen::Matrix3f R_Rotation = Eigen::Matrix3f::Identity();
    Eigen::Matrix4f T_Rotation = Eigen::Matrix4f::Identity();

    if(func_debug_mode) {
        std::cout << "***********************************************************" << std::endl;
        std::cout << "************** Modification for complex shape *************" << std::endl;
        std::cout << "************** User-defined fixed orientation *************" << std::endl;
        std::cout << T_O2E << std::endl;
        std::cout << "***********************************************************" << std::endl;
    }


    //// TODO: z축 JSON 처리 
    vec_global_z = {0.0, 0.0, 1.0};
    mtx.lock();
    custom_vector_major_axis = target_object_data.custom_vector_major_axis; // {B} 기준
    mtx.unlock();
    vec_B2E_tmp_x = T_B2E_raw.block<3, 1>(0, 0); // {E} 기준의 +x방향벡터
    vec_B2E_tmp_x[2] = 0.0;
    vec_B2E_tmp_x.normalize();

    double angle_threshold = 1.0;
    double dot_tmp = custom_vector_major_axis.dot(vec_B2E_tmp_x);
    bool direction_plus = false;
    if (dot_tmp < cos(angle_threshold * (M_PI / 180.0))) 
    {
        double angle_tmp = fabs((180.0 / M_PI)*acos(dot_tmp));
        Eigen::Vector3f vec_tmp = custom_vector_major_axis.cross(vec_B2E_tmp_x);
        vec_tmp.normalize();
        if (vec_tmp.dot(vec_global_z) > cos(90.0 * (M_PI / 180.0))) { // 동일한 방향이면
            // {O}의 z축 기준으로 추출된 각도만큼 회전
            m_math.genRotM(angle_tmp, R_Rotation, T_Rotation, 2); // Rz
            direction_plus = true;
        } else { // 반대 방향이면
            // {O}의 z축 기준으로 추출된 각도만큼 회전
            m_math.genRotM(-angle_tmp, R_Rotation, T_Rotation, 2); // Rz
            direction_plus = false;
        }

        if(func_debug_mode) {
            std::cout << "**************************************************" << std::endl;
            std::cout << "******** Vector flipped! (w.r.t. major axis) ********" << std::endl;
            printf("*** custom_vector_major_axis: %0.4f %0.4f %0.4f ***\n", custom_vector_major_axis[0], custom_vector_major_axis[1], custom_vector_major_axis[2]);
            printf("*** vec_B2E_tmp_x: %0.4f %0.4f %0.4f ***\n", vec_B2E_tmp_x[0], vec_B2E_tmp_x[1], vec_B2E_tmp_x[2]);
            if(direction_plus) {
                printf("*** angle_tmp: %0.1f ***\n", angle_tmp);
            } else {
                printf("*** angle_tmp: %0.1f ***\n", -angle_tmp);
            }
            std::cout << "**************************************************" << std::endl;
        }
    }
    
    // update
    T_out = T_Rotation;
    if(func_debug_mode) {
        std::cout << "--------------- User-defined fixed orientation process applied! ---------------!" << std::endl;
    }
    return true;
}



/** @brief Korean: 입력된 회전축, 회전각도를 이용하여 후보 파지자세의 회전 및 변환행렬을 계산한다.
 * @param[in] target_object_data : 물체별 프로세스 객체
 * @param[in] direction : 회전 축 설정 (0: Rx, 1: Ry, 2: Rz)
 */
Eigen::Matrix4f TEMPLATE_MATCHING::generateSubGraspingPose(CTARGET_OBJECT_DATA* &target_object_data, int direction)
{
    Eigen::Matrix4f T_B2O = target_object_data->T_matching_B2O;
    Eigen::Matrix4f T_O2B = target_object_data->T_matching_O2B;
    //// TODO: 아래 변경
    Eigen::Matrix4f T_O2E_raw = target_object_data->sub_pose_set_T_O2GP[0];
    
    Eigen::Matrix4f T_B2O_process = T_B2O;

    /////////////////////////////////////////////////////////////////////////
    // a) (raw data) HTM from template matching results
    Eigen::Matrix4f T_O2E_process = T_O2E_raw;
    Eigen::Matrix4f T_B2E_raw = T_B2O*T_O2E_raw;

    //// TODO: 입력된 template의 CAD 좌표계의 법선이 z축, 장축이 x축으로 사용자가 설정하도록 처리해야 함.
    //// cylinder는 CAD 좌표계 상으로 명확히 붙지 않으므로, 항상 로봇 베이스 좌표계 기준으로 평행하도록 처리해야 함.

    // b) (user-modified data) Only fixed orientation - no translation infomation
    // b-1) 로봇 x축 방향 결정 - Template에 정의된 
    //// TODO: 입력된 template의 CAD 좌표계의 법선이 z축, 장축이 x축으로 사용자가 설정하도록 처리
    //// TODO: 물체 좌표계의 cylinder 장축을 정의하도록 처리해야 함. 예) {O}기준의 x축이 cylinder의 장축
    //// TODO: 사용되는 로봇의 작업영역, x, y, z축을 정의하여, vec_B2E_initial_x에 입력되도록 처리해야 함.

    Eigen::Vector3f vec_B2E_initial_x;
    Eigen::Vector3f vec_B2E_initial_z;
    Eigen::Vector3f vec_B2E_modified_x;
    Eigen::Vector3f vec_B2E_tmp_x;
    Eigen::Matrix3f R_Rotation;
    Eigen::Matrix4f T_Rotation;
	switch (direction)
	{
	case 0: // in x direction
        vec_B2E_initial_z = {0.0, 0.0, -1.0};
        vec_B2E_initial_x = {-1.0, 0.0, 0.0};
        // vec_B2E_modified_x = T_B2E_raw.block<3, 1>(0, 0);
        vec_B2E_tmp_x = T_B2E_raw.block<3, 1>(0, 0);
        vec_B2E_tmp_x[2] = 0.0;
        vec_B2E_tmp_x.normalize();

        //// a) flip 
        //// TODO: Flip이 적용되는 경우, CAD 좌표계가 대칭의 중심에 위치하고, 파지점도 해당 중심이어야 함. 그렇지 않으면 잘못된 위치로 변환됨
        if (vec_B2E_initial_x.dot(vec_B2E_tmp_x) < cos(90.0 * (M_PI / 180.0))) // 사잇각이 90도보다 크면 flip
        {
            if(target_object_data->debug_mode)
            {
                std::cout << "***********************************" << std::endl;
                std::cout << "******** Vector X flipped! ********" << std::endl;
                std::cout << "***********************************" << std::endl;
            }
            // x 기준일 경우, {O}의 z축 기준으로 Rz 180 회전
            m_math.genRotM(180.0, R_Rotation, T_Rotation, 2); // Rz
            T_O2E_process = T_Rotation*T_O2E_process; // {O}의 z축 기준으로 180deg 회전
            
            ////////////////
            //// B2O results update
            T_B2O_process = T_B2O_process*T_Rotation; 
            ////////////////
        }
		break;

    //// TODO: 아래 y, z에 대해서 모두 처리해야 함.
	case 1: // in y direction

		break;

	case 2: // in z direction

		break;
	}

    // b-2) 방향 벡터 정의
    //// Rx가 항상 180deg가 되도록 cylinder는 굳이 꺾어서 잡을 이유는 없음
    // 로봇 말단의 y축 벡터가 base 좌표계 기준의 xy평면 상에 있어야 함. --> vec_B_z = {0 0 1}과 수직이어야 함.
    Eigen::Matrix4f T_B2E_process = T_B2O*T_O2E_process;

    vec_B2E_modified_x = T_B2E_process.block<3, 1>(0, 0);
    Eigen::Vector3f vec_B2E_modified_y = vec_B2E_initial_z.cross(vec_B2E_modified_x);
    vec_B2E_modified_y.normalize();
    Eigen::Vector3f vec_O2E_modified_y = T_O2B.block<3, 3>(0, 0) * vec_B2E_modified_y; // modified rotation vector
    Eigen::Vector3f vec_B2E_modified_z = vec_B2E_modified_x.cross(vec_B2E_modified_y);
    vec_B2E_modified_z.normalize();
    Eigen::Vector3f vec_O2E_modified_z = T_O2B.block<3, 3>(0, 0) * vec_B2E_modified_z; // modified rotation vector
    Eigen::Vector3f vec_O2E_modified_x = T_O2B.block<3, 3>(0, 0) * vec_B2E_modified_x; // modified rotation vector

    if(target_object_data->debug_mode) { std::cout << "--------------- Modification (a) applied! ---------------!" << std::endl; }

    //// parallel rotation
    // {O} 기준의 x축(물체 좌표계의 cylinder 장축) 기준의 회전각도 산출
    //// TODO: 정의된 장축에 맞게 입력 파라미터에 연동되어야 함.
    Eigen::Vector3f vec_O2E_raw_tmp = T_O2E_process.block<3, 1>(0, 1); // y
    Eigen::Vector3f vec_O2E_modified_tmp = vec_O2E_modified_y; // modified
    // yz평면으로 정사영
    vec_O2E_raw_tmp[0] = 0.0;
    vec_O2E_raw_tmp.normalize();
    vec_O2E_modified_tmp[0] = 0.0;
    vec_O2E_modified_tmp.normalize();
    double dot_tmp = vec_O2E_raw_tmp.dot(vec_O2E_modified_tmp);
    double angle_between_deg = fabs((180.0 / M_PI)*acos(dot_tmp));
    // std::cout << "---- Angle between: " << angle_between_deg << "[deg] ----" << std::endl;

    // 각도만큼 회전            
    Eigen::Vector3f vec_O_x_axis = {1.0, 0.0, 0.0};
    Eigen::Vector3f vec_O_y_axis = {0.0, 1.0, 0.0};
    Eigen::Vector3f vec_O_z_axis = {0.0, 0.0, 1.0};

    Eigen::Vector3f cross_tmp = vec_O2E_raw_tmp.cross(vec_O2E_modified_tmp);
    cross_tmp.normalize();
    Eigen::Matrix3f rotM_tmp;
    Eigen::Matrix4f HTM_tmp;
    if(cross_tmp.dot(vec_O_x_axis) > cos(90.0 * (M_PI / 180.0))) // 장축과 부호 동일
    {
        m_math.genRotM(angle_between_deg, rotM_tmp, HTM_tmp, 0); // 0: x, 1: y, 2: z
    }
    else // 장축과 부호 반대
    {
        m_math.genRotM(-angle_between_deg, rotM_tmp, HTM_tmp, 0); // 0: x, 1: y, 2: z
    }

    Eigen::Matrix4f T_rotation_wrt_O2O_modified = HTM_tmp;
    Eigen::Matrix4f T_tgt_O2E_modified = T_rotation_wrt_O2O_modified*T_O2E_process; // {O}의 대상 축 기준으로 각도만큼 회전
    if(target_object_data->debug_mode) { std::cout << "--------------- Modification (b) applied! ---------------!" << std::endl; }

    ////////////////
    //// B2O results update
    T_B2O_process = T_B2O_process*T_rotation_wrt_O2O_modified; 
    ////////////////
    target_object_data->T_matching_B2O_sub_process = T_B2O_process;
    
    // update
    Eigen::Matrix4f T_B2E_modified = T_B2O*T_tgt_O2E_modified;
    if(target_object_data->debug_mode) { std::cout << "--------------- User-defined orientation process applied! ---------------!" << std::endl; }
    return T_B2E_modified;
}

/** @brief Korean: 입력된 회전축, 회전각도를 이용하여 후보 파지자세의 회전 및 변환행렬을 계산한다.
 * @param[in] target_object_data : 물체별 프로세스 객체
 * @param[in] direction : 회전 축 설정 (0: Rx, 1: Ry, 2: Rz)
 */
Eigen::Matrix4f TEMPLATE_MATCHING::generateSubGraspingPoseMultiThreaded(CTARGET_OBJECT_DATA &target_object_data, int direction)
{
    mtx.lock();
    Eigen::Matrix4f T_B2O = target_object_data.T_matching_B2O;
    Eigen::Matrix4f T_O2B = target_object_data.T_matching_O2B;
    //// TODO: 아래 변경
    Eigen::Matrix4f T_O2E_raw = target_object_data.sub_pose_set_T_O2GP[0];
    mtx.unlock();
    
    Eigen::Matrix4f T_B2O_process = T_B2O;

    /////////////////////////////////////////////////////////////////////////
    // a) (raw data) HTM from template matching results
    Eigen::Matrix4f T_O2E_process = T_O2E_raw;
    Eigen::Matrix4f T_B2E_raw = T_B2O*T_O2E_raw;

    //// TODO: 입력된 template의 CAD 좌표계의 법선이 z축, 장축이 x축으로 사용자가 설정하도록 처리해야 함.
    //// cylinder는 CAD 좌표계 상으로 명확히 붙지 않으므로, 항상 로봇 베이스 좌표계 기준으로 평행하도록 처리해야 함.

    // b) (user-modified data) Only fixed orientation - no translation infomation
    // b-1) 로봇 x축 방향 결정 - Template에 정의된 
    //// TODO: 입력된 template의 CAD 좌표계의 법선이 z축, 장축이 x축으로 사용자가 설정하도록 처리
    //// TODO: 물체 좌표계의 cylinder 장축을 정의하도록 처리해야 함. 예) {O}기준의 x축이 cylinder의 장축
    //// TODO: 사용되는 로봇의 작업영역, x, y, z축을 정의하여, vec_B2E_initial_x에 입력되도록 처리해야 함.

    Eigen::Vector3f vec_B2E_initial_x;
    Eigen::Vector3f vec_B2E_initial_z;
    Eigen::Vector3f vec_B2E_modified_x;
    Eigen::Vector3f vec_B2E_tmp_x;
    Eigen::Matrix3f R_Rotation;
    Eigen::Matrix4f T_Rotation;
	switch (direction)
	{
	case 0: // in x direction
        vec_B2E_initial_z = {0.0, 0.0, -1.0};
        vec_B2E_initial_x = {-1.0, 0.0, 0.0};
        // vec_B2E_modified_x = T_B2E_raw.block<3, 1>(0, 0);
        vec_B2E_tmp_x = T_B2E_raw.block<3, 1>(0, 0);
        vec_B2E_tmp_x[2] = 0.0;
        vec_B2E_tmp_x.normalize();

        //// a) flip 
        //// TODO: Flip이 적용되는 경우, CAD 좌표계가 대칭의 중심에 위치하고, 파지점도 해당 중심이어야 함. 그렇지 않으면 잘못된 위치로 변환됨
        if (vec_B2E_initial_x.dot(vec_B2E_tmp_x) < cos(90.0 * (M_PI / 180.0))) // 사잇각이 90도보다 크면 flip
        {
            // if(target_object_data.debug_mode)
            // {
            //     std::cout << "***********************************" << std::endl;
            //     std::cout << "******** Vector X flipped! ********" << std::endl;
            //     std::cout << "***********************************" << std::endl;
            // }
            // x 기준일 경우, {O}의 z축 기준으로 Rz 180 회전
            m_math.genRotM(180.0, R_Rotation, T_Rotation, 2); // Rz
            T_O2E_process = T_Rotation*T_O2E_process; // {O}의 z축 기준으로 180deg 회전
            
            ////////////////
            //// B2O results update
            T_B2O_process = T_B2O_process*T_Rotation; 
            ////////////////
        }
		break;

    //// TODO: 아래 y, z에 대해서 모두 처리해야 함.
	case 1: // in y direction

		break;

	case 2: // in z direction

		break;
	}

    // b-2) 방향 벡터 정의
    //// Rx가 항상 180deg가 되도록 cylinder는 굳이 꺾어서 잡을 이유는 없음
    // 로봇 말단의 y축 벡터가 base 좌표계 기준의 xy평면 상에 있어야 함. --> vec_B_z = {0 0 1}과 수직이어야 함.
    Eigen::Matrix4f T_B2E_process = T_B2O*T_O2E_process;

    vec_B2E_modified_x = T_B2E_process.block<3, 1>(0, 0);
    Eigen::Vector3f vec_B2E_modified_y = vec_B2E_initial_z.cross(vec_B2E_modified_x);
    vec_B2E_modified_y.normalize();
    Eigen::Vector3f vec_O2E_modified_y = T_O2B.block<3, 3>(0, 0) * vec_B2E_modified_y; // modified rotation vector
    Eigen::Vector3f vec_B2E_modified_z = vec_B2E_modified_x.cross(vec_B2E_modified_y);
    vec_B2E_modified_z.normalize();
    Eigen::Vector3f vec_O2E_modified_z = T_O2B.block<3, 3>(0, 0) * vec_B2E_modified_z; // modified rotation vector
    Eigen::Vector3f vec_O2E_modified_x = T_O2B.block<3, 3>(0, 0) * vec_B2E_modified_x; // modified rotation vector

    // if(target_object_data.debug_mode) { std::cout << "--------------- Modification (a) applied! ---------------!" << std::endl; }

    //// parallel rotation
    // {O} 기준의 x축(물체 좌표계의 cylinder 장축) 기준의 회전각도 산출
    //// TODO: 정의된 장축에 맞게 입력 파라미터에 연동되어야 함.
    Eigen::Vector3f vec_O2E_raw_tmp = T_O2E_process.block<3, 1>(0, 1); // y
    Eigen::Vector3f vec_O2E_modified_tmp = vec_O2E_modified_y; // modified
    // yz평면으로 정사영
    vec_O2E_raw_tmp[0] = 0.0;
    vec_O2E_raw_tmp.normalize();
    vec_O2E_modified_tmp[0] = 0.0;
    vec_O2E_modified_tmp.normalize();
    double dot_tmp = vec_O2E_raw_tmp.dot(vec_O2E_modified_tmp);
    double angle_between_deg = fabs((180.0 / M_PI)*acos(dot_tmp));
    // std::cout << "---- Angle between: " << angle_between_deg << "[deg] ----" << std::endl;

    // 각도만큼 회전            
    Eigen::Vector3f vec_O_x_axis = {1.0, 0.0, 0.0};
    Eigen::Vector3f vec_O_y_axis = {0.0, 1.0, 0.0};
    Eigen::Vector3f vec_O_z_axis = {0.0, 0.0, 1.0};

    Eigen::Vector3f cross_tmp = vec_O2E_raw_tmp.cross(vec_O2E_modified_tmp);
    cross_tmp.normalize();
    Eigen::Matrix3f rotM_tmp;
    Eigen::Matrix4f HTM_tmp;
    if(cross_tmp.dot(vec_O_x_axis) > cos(90.0 * (M_PI / 180.0))) // 장축과 부호 동일
    {
        m_math.genRotM(angle_between_deg, rotM_tmp, HTM_tmp, 0); // 0: x, 1: y, 2: z
    }
    else // 장축과 부호 반대
    {
        m_math.genRotM(-angle_between_deg, rotM_tmp, HTM_tmp, 0); // 0: x, 1: y, 2: z
    }

    Eigen::Matrix4f T_rotation_wrt_O2O_modified = HTM_tmp;
    Eigen::Matrix4f T_tgt_O2E_modified = T_rotation_wrt_O2O_modified*T_O2E_process; // {O}의 대상 축 기준으로 각도만큼 회전
    // if(target_object_data.debug_mode) { std::cout << "--------------- Modification (b) applied! ---------------!" << std::endl; }

    ////////////////
    //// B2O results update
    T_B2O_process = T_B2O_process*T_rotation_wrt_O2O_modified; 
    ////////////////
    mtx.lock();
    target_object_data.T_matching_B2O_sub_process = T_B2O_process;
    mtx.unlock();
    
    // update
    Eigen::Matrix4f T_B2E_modified = T_B2O*T_tgt_O2E_modified;
    // if(target_object_data.debug_mode) { std::cout << "--------------- User-defined orientation process applied! ---------------!" << std::endl; }
    return T_B2E_modified;
}

/** @brief Korean: 입력된 목표 자세(4x4 변환행렬)의 충돌여부를 검사하고, 충돌을 회피하는 파지 자세를 산출한다.
 * @param[in] target_object_data : 물체별 프로세스 객체
 * @param[in] direction : 회전 축 설정 (0: Rx, 1: Ry, 2: Rz)
 */
Eigen::Matrix4f TEMPLATE_MATCHING::genCollisionFreeGraspingPoseForCylinderShape(CTARGET_OBJECT_DATA* &target_object_data, Eigen::Matrix4f &T_tgt)
{
    printf("\n*****************************************************************************\n");
    printf("\n*****************************************************************************\n");
    printf("******* Generate optimal grasping pose ver.1 - for cylinder (shaft-shaped) *******\n");
    printf("\n*****************************************************************************\n");
    printf("\n*****************************************************************************\n");
    
    Eigen::Matrix4f T_out;
    size_t thre_collision = target_object_data->collision_pt_threshold; // # of points
    target_object_data->is_collision = false;
    if (target_object_data->do_collision_check_using_voxel_map) // gripper CAD 파일의 voxel map 이용
    {
        //// Check collision
        std::vector<size_t> collision_count_set;
        if(checkGripperCollisionUsingVoxelMap(target_object_data, T_tgt, thre_collision, collision_count_set, false)) {
            //// 적합한 Candidate이 없는 경우, 실패
            Eigen::Matrix4f T_tgt_process;
            if(estimatePoseWithoutCollisionForCylinderShape(target_object_data, T_tgt, thre_collision, collision_count_set, T_tgt_process)) {
                T_out = T_tgt_process; // Feasible pose
            } else {
                //// TODO: 아래 부분 삭제
                // m_pcl_proc.plotFinalPoseResultsNoKDTree(target_object_data, T_tgt_process, thre_collision, collision_count_set, "genCollisionFreeGraspingPoseForCylinderShape - No solution, Infeasible pose with collision", target_object_data->plot_collision_results);
                T_out = T_tgt;
                return T_out;
            }
        } else {
            printf("\n*****************************************************************************\n");
            printf("*****************************************************************************\n");
            printf("---- Collision estimation: No collision! ----\n");
            printf("Collision counts: %zu (L: %zu, R: %zu)\n", collision_count_set[0], collision_count_set[1], collision_count_set[2]);
            printf("*****************************************************************************\n");
            printf("\n*****************************************************************************\n");
            target_object_data->is_collision = false;
            target_object_data->is_feasible_pose = true;
            T_out = T_tgt;

            //// TODO: apporach 거리에 따라 접근한 후에
            //// TODO: +z방향으로 상승하는 방향으로 충돌 체크(올라올 때는 파지한 상태에서 물체까지 포함하도록 처리)
            if(checkCollisionApproach2Escape(target_object_data, T_tgt)) {
                Eigen::Matrix4f T_tgt_process;
                if(estimatePoseWithoutCollisionForCylinderShape(target_object_data, T_tgt, thre_collision, collision_count_set, T_tgt_process)) {
                    T_out = T_tgt_process; // Feasible pose
                } else {
                    //// TODO: 아래 부분 삭제
                    // m_pcl_proc.plotFinalPoseResultsNoKDTree(target_object_data, T_tgt_process, thre_collision, collision_count_set, "genCollisionFreeGraspingPoseForCylinderShape - No solution, Infeasible pose with collision", target_object_data->plot_collision_results);
                    T_out = T_tgt;
                    return T_out;
                }
            } else {
                //// For plot
                // m_pcl_proc.plotFinalPoseResultsNoKDTree(target_object_data, T_tgt, thre_collision, collision_count_set, "genCollisionFreeGraspingPoseForCylinderShape - No collision", target_object_data->plot_collision_results);
            }
        }
    }
    else // 박스의 경계박스 정보 이용 (회전각도 고정)
    {
        double candidate_angle = 20.0;
        Eigen::Matrix4f T_tgt_without_collision;
        if(checkGripperCollisionUsingBoundingBox(target_object_data, T_tgt, candidate_angle, T_tgt_without_collision)) 
        {
            target_object_data->is_collision = false;
            target_object_data->is_feasible_pose = true;
            T_out = T_tgt_without_collision;
        }
        else 
        {
            target_object_data->is_collision = true;
            target_object_data->is_feasible_pose = false;
            T_out = T_tgt;
        }
    }

    return T_out;
}

