void TEMPLATE_MATCHING::importCADNormalModel3(const pcl::PointCloud<pcl::PointXYZ> &cloud_in, pcl::PointCloud<pcl::PointXYZRGBNormal> &cloud_out, const Eigen::Matrix4f &T_Base2CAD, const std::string &file_path_input) 
{
    pcl::PointCloud<pcl::PointXYZRGBNormal>::Ptr cloud_CAD_output(new pcl::PointCloud<pcl::PointXYZRGBNormal>);
    pcl::PointCloud<pcl::PointXYZRGBNormal>::Ptr cloud_CAD_output_downsampled(new pcl::PointCloud<pcl::PointXYZRGBNormal>);
    std::cout << file_path_input.c_str() << std::endl;

    printf("CAD with normal vectors save process (importCADNormalModel3)\n");

    pcl::PointCloud<pcl::PointNormal>::Ptr outputCloud(new pcl::PointCloud<pcl::PointNormal>);
    // pcl::PointCloud<pcl::PointXYZ> objCloud;
    pcl::PointCloud<pcl::PointXYZ>::Ptr objCloud(new pcl::PointCloud<pcl::PointXYZ>);
    pcl::PointCloud<pcl::PointXYZRGBNormal>::Ptr cloud_CAD(new pcl::PointCloud<pcl::PointXYZRGBNormal>);
    pcl::PointCloud<pcl::PointXYZRGBNormal>::Ptr cloud_CAD_base_frame(new pcl::PointCloud<pcl::PointXYZRGBNormal>);
    pcl::PointCloud<pcl::PointXYZRGBNormal>::Ptr cloud_CAD_mesh(new pcl::PointCloud<pcl::PointXYZRGBNormal>);
    pcl::PolygonMesh::Ptr mesh_CAD(new pcl::PolygonMesh);
    ROS_LOG_INFO("This process 1 (importCADNormalModel3)\n");

    ////////////////////////////////
    ////////////////////////////////
    //// TODO: double free or corruption (out) Error 발생
    ////////////////////////////////
    //// 기존
    // pcl::io::loadPolygonFilePLY(file_path_input, *mesh_CAD);

    ////////////////////////////////
    //// 변경 - VTK 버전 문제일 가능성이 높음
    vtkSmartPointer<vtkPLYReader> reader = vtkSmartPointer<vtkPLYReader>::New();
    vtkSmartPointer<vtkPolyData> vtk_mesh = vtkSmartPointer<vtkPolyData>::New();
    reader->SetFileName(file_path_input.c_str());
    reader->SetOutput(vtk_mesh);

    std::cout << "(vtk_mesh)Number of points = " << vtk_mesh->GetNumberOfPoints() << std::endl;
    pcl::PolygonMesh pcl_mesh;
    pcl::VTKUtils::vtk2mesh(vtk_mesh, pcl_mesh);

    ROS_LOG_INFO("This process 2 (importCADNormalModel3)\n");
    std::cout << mesh_CAD->polygons.size() << std::endl;
    ////////////////////////////////
    ////////////////////////////////
    ////////////////////////////////

    // pcl::PCLPointCloud2 ptCloud2 = mesh_CAD.cloud;
    // pcl::fromPCLPointCloud2(ptCloud2, objCloud);

    pcl::PCLPointCloud2::Ptr ptCloud2(new pcl::PCLPointCloud2);
    *ptCloud2 = mesh_CAD->cloud;
    pcl::fromPCLPointCloud2(*ptCloud2, *objCloud);
    ROS_LOG_INFO("This process 3 (importCADNormalModel3)\n");

    //// Transform
    pcl::transformPointCloud(*objCloud, *objCloud, T_Base2CAD);
    m_math.printCloudMinMax(*objCloud, "objCloud");

    //// 1) PLY 파일에 저장된 점군 정보와 mesh index를 이용하여, mesh의 중심점과 mesh의 법선 벡터를 포함하는 점군 데이터를 산출
    cloud_CAD_mesh->resize(mesh_CAD->polygons.size());

    for (size_t i = 0; i < mesh_CAD->polygons.size(); i++)
    {
        pcl::Vertices currentPoly = mesh_CAD->polygons[i];

        for (size_t j = 0; j < currentPoly.vertices.size(); j++)
        {
            pcl::PointNormal currentPt = pcl::PointNormal();
            currentPt.x = objCloud->points[currentPoly.vertices[j]].x;
            currentPt.y = objCloud->points[currentPoly.vertices[j]].y;
            currentPt.z = objCloud->points[currentPoly.vertices[j]].z;
            outputCloud->points.push_back(currentPt);
        }

        size_t index = outputCloud->points.size() - 1;
        double mesh_center_x = 0.0;
        double mesh_center_y = 0.0;
        double mesh_center_z = 0.0;

        pcl::PointXYZ pt3(outputCloud->points[index].x, outputCloud->points[index].y, outputCloud->points[index].z);
        mesh_center_x = mesh_center_x + outputCloud->points[index].x;
        mesh_center_y = mesh_center_y + outputCloud->points[index].y;
        mesh_center_z = mesh_center_z + outputCloud->points[index].z;
        index--;

        pcl::PointXYZ pt2(outputCloud->points[index].x, outputCloud->points[index].y, outputCloud->points[index].z);
        mesh_center_x = mesh_center_x + outputCloud->points[index].x;
        mesh_center_y = mesh_center_y + outputCloud->points[index].y;
        mesh_center_z = mesh_center_z + outputCloud->points[index].z;
        index--;

        pcl::PointXYZ pt1(outputCloud->points[index].x, outputCloud->points[index].y, outputCloud->points[index].z);
        mesh_center_x = mesh_center_x + outputCloud->points[index].x;
        mesh_center_y = mesh_center_y + outputCloud->points[index].y;
        mesh_center_z = mesh_center_z + outputCloud->points[index].z;

        // mesh center
        mesh_center_x = mesh_center_x / 3.0;
        mesh_center_y = mesh_center_y / 3.0;
        mesh_center_z = mesh_center_z / 3.0;

        Eigen::Vector3f vec12(pt2.x - pt1.x, pt2.y - pt1.y, pt2.z - pt1.z);
        Eigen::Vector3f vec23(pt3.x - pt2.x, pt3.y - pt2.y, pt3.z - pt2.z);
        Eigen::Vector3f vecNorm = vec12.cross(vec23);
        vecNorm.normalize();

        cloud_CAD_mesh->points[i].x = mesh_center_x;
        cloud_CAD_mesh->points[i].y = mesh_center_y;
        cloud_CAD_mesh->points[i].z = mesh_center_z;
        cloud_CAD_mesh->points[i].normal_x = vecNorm[0];
        cloud_CAD_mesh->points[i].normal_y = vecNorm[1];
        cloud_CAD_mesh->points[i].normal_z = vecNorm[2];
    }

    // filtering
    bool do_grid_filter = false;
    if (do_grid_filter)
    {
        pcl::VoxelGrid<pcl::PointXYZRGBNormal> grid;
        grid.setLeafSize(1.0, 1.0, 1.0); // metric: mm

        grid.setInputCloud(cloud_CAD_mesh);
        grid.filter(*cloud_CAD_mesh);
    }

    pcl::copyPointCloud(cloud_in, *cloud_CAD_base_frame);
    m_math.printCloudMinMax(*cloud_CAD_base_frame, "cloud_CAD_base_frame");
    *cloud_CAD_output = *cloud_CAD_base_frame;


    ROS_LOG_WARN("importCADNormalModel3 - Process 1");

    if(cloud_CAD_mesh->size() == 0) {
        ROS_LOG_WARN("cloud_CAD_mesh->size() == 0 // NormalEstimation...");
        ROS_LOG_WARN("cloud_CAD_mesh->size() == 0 // NormalEstimation...");
        ROS_LOG_WARN("cloud_CAD_mesh->size() == 0 // NormalEstimation...");
        Eigen::Vector3d sensor_origin = {0.0, 0.0, 1000.0}; // z축 기준
        pcl::PointCloud<pcl::PointXYZ>::Ptr cloud_CAD_base_frame_tmp(new pcl::PointCloud<pcl::PointXYZ>);
        pcl::copyPointCloud(*cloud_CAD_base_frame, *cloud_CAD_base_frame_tmp);
        m_pcl_proc.cloudNormalEst2Measured(*cloud_CAD_base_frame_tmp, *cloud_CAD_mesh, 10, sensor_origin, 80.0); // K = 10, angle: 80 [deg]
    }



    //// Input CAD mesh cloud tree
    pcl::KdTreeFLANN<pcl::PointXYZRGBNormal, flann::L2_Simple<float> > modelKDTree_mesh;
    modelKDTree_mesh.setInputCloud(cloud_CAD_mesh->makeShared());
    ROS_LOG_WARN("importCADNormalModel3 - Process 2");
    genSegmentNormalFromCAD(*cloud_CAD_mesh, *cloud_CAD_output, modelKDTree_mesh);

    cloud_out = *cloud_CAD_output;
}

void TEMPLATE_MATCHING::genSegmentNormalFromCAD(const pcl::PointCloud<pcl::PointXYZRGBNormal> &cloud_CAD_mesh, pcl::PointCloud<pcl::PointXYZRGBNormal> &cloud_CAD, pcl::KdTreeFLANN<pcl::PointXYZRGBNormal, flann::L2_Simple<float>> &model)
{
	std::vector<int> nn_indices;
	std::vector<float> nn_dists;
	for (size_t i = 0; i < cloud_CAD.points.size(); i++)
	{
		// update
		model.nearestKSearch(cloud_CAD.points[i], 1, nn_indices, nn_dists);
		cloud_CAD.points[i].normal_x = cloud_CAD_mesh.points[nn_indices[0]].normal_x;
		cloud_CAD.points[i].normal_y = cloud_CAD_mesh.points[nn_indices[0]].normal_y;
		cloud_CAD.points[i].normal_z = cloud_CAD_mesh.points[nn_indices[0]].normal_z;
	}
}

void TEMPLATE_MATCHING::extractFeaturePFH(const pcl::PointCloud<pcl::PointXYZRGBNormal> &cloud_in, pcl::PointCloud<pcl::PFHSignature125> &output)
{
    pcl::PointCloud<pcl::PointXYZ>::Ptr cloud(new pcl::PointCloud<pcl::PointXYZ>);
    pcl::PointCloud<pcl::Normal>::Ptr normals(new pcl::PointCloud<pcl::Normal>());
    pcl::copyPointCloud(cloud_in, *cloud);
    pcl::copyPointCloud(cloud_in, *normals);

    // Normal
    for (size_t i = 0; i < normals->size(); i++)
    {
        if (!pcl::isFinite<pcl::Normal>((*normals)[i]))
        {
            PCL_WARN("normals[%d] is not finite\n", i);
        }
    }

    //  ... read, pass in or create a point cloud with normals ...
    //  ... (note: you can create a single PointCloud<PointNormal> if you want) ...

    // Create the PFH estimation class, and pass the input dataset+normals to it
    pcl::PFHEstimation<pcl::PointXYZ, pcl::Normal, pcl::PFHSignature125> pfh;
    pfh.setInputCloud(cloud);
    pfh.setInputNormals(normals);
    // alternatively, if cloud is of tpe PointNormal, do fpfh.setInputNormals (cloud);

    // Create an empty kdtree representation, and pass it to the FPFH estimation object.
    // Its content will be filled inside the object, based on the given input dataset (as no other search surface is given).
    pcl::search::KdTree<pcl::PointXYZ>::Ptr tree(new pcl::search::KdTree<pcl::PointXYZ>());
    pfh.setSearchMethod(tree);

    // Output datasets
    pcl::PointCloud<pcl::PFHSignature125>::Ptr pfhs(new pcl::PointCloud<pcl::PFHSignature125>());

    // Use all neighbors in a sphere of radius 5cm
    // IMPORTANT: the radius used here has to be larger than the radius used to estimate the surface normals!!!
    pfh.setRadiusSearch(0.05);

    // Compute the features
    pfh.compute(*pfhs);

    // pfhs->size () should have the same size as the input cloud->size ()*
    std::cout << "PFH featrue extracted! - size: " << pfhs->size() << std::endl;
    output = *pfhs;
}

void TEMPLATE_MATCHING::extractFeatureFPFH(const pcl::PointCloud<pcl::PointXYZRGBNormal> &cloud_in, pcl::PointCloud<pcl::FPFHSignature33> &output)
{
    pcl::PointCloud<pcl::PointXYZ>::Ptr cloud(new pcl::PointCloud<pcl::PointXYZ>);
    pcl::PointCloud<pcl::Normal>::Ptr normals(new pcl::PointCloud<pcl::Normal>());
    pcl::copyPointCloud(cloud_in, *cloud);
    pcl::copyPointCloud(cloud_in, *normals);

    // Normal
    for (size_t i = 0; i < normals->size(); i++)
    {
        if (!pcl::isFinite<pcl::Normal>((*normals)[i]))
        {
            PCL_WARN("normals[%d] is not finite\n", i);
        }
    }

    //  ... read, pass in or create a point cloud with normals ...
    //  ... (note: you can create a single PointCloud<PointNormal> if you want) ...

    // Create the FPFH estimation class, and pass the input dataset+normals to it
    pcl::FPFHEstimation<pcl::PointXYZ, pcl::Normal, pcl::FPFHSignature33> fpfh;
    fpfh.setInputCloud(cloud);
    fpfh.setInputNormals(normals);
    // alternatively, if cloud is of tpe PointNormal, do fpfh.setInputNormals (cloud);

    // Create an empty kdtree representation, and pass it to the FPFH estimation object.
    // Its content will be filled inside the object, based on the given input dataset (as no other search surface is given).
    pcl::search::KdTree<pcl::PointXYZ>::Ptr tree(new pcl::search::KdTree<pcl::PointXYZ>());
    fpfh.setSearchMethod(tree);

    // Output datasets
    pcl::PointCloud<pcl::FPFHSignature33>::Ptr fpfhs(new pcl::PointCloud<pcl::FPFHSignature33>());

    // Use all neighbors in a sphere of radius 5cm
    // IMPORTANT: the radius used here has to be larger than the radius used to estimate the surface normals!!!
    // fpfh.setRadiusSearch(0.05);
    fpfh.setRadiusSearch(50); // 50 mm

    // Compute the features
    fpfh.compute(*fpfhs);

    // fpfhs->size () should have the same size as the input cloud->size ()*
    std::cout << "FPFH featrue extracted! - size: " << fpfhs->size() << std::endl;
    output = *fpfhs;
}

void TEMPLATE_MATCHING::extractFeatureSpinImage(const pcl::PointCloud<pcl::PointXYZRGBNormal> &cloud_in, pcl::PointCloud<pcl::Histogram<153>> &output)
{
  pcl::PointCloud<pcl::PointXYZ>::Ptr cloud(new pcl::PointCloud<pcl::PointXYZ>);
  pcl::PointCloud<pcl::Normal>::Ptr normals(new pcl::PointCloud<pcl::Normal>());
  pcl::copyPointCloud(cloud_in, *cloud);
  pcl::search::KdTree<pcl::PointXYZ>::Ptr kdtree(new pcl::search::KdTree<pcl::PointXYZ>);
  if(0) // normal est. 
  {
    // Compute the normals
    pcl::NormalEstimation<pcl::PointXYZ, pcl::Normal> normal_estimation;
    normal_estimation.setInputCloud (cloud);

    pcl::search::KdTree<pcl::PointXYZ>::Ptr kdtree (new pcl::search::KdTree<pcl::PointXYZ>);
    normal_estimation.setSearchMethod (kdtree);

    pcl::PointCloud<pcl::Normal>::Ptr normals (new pcl::PointCloud< pcl::Normal>);
    // normal_estimation.setRadiusSearch (0.03);
    normal_estimation.setRadiusSearch (30); // 3cm
    normal_estimation.compute (*normals);
  }
  else // assigned normal
  {
    pcl::copyPointCloud(cloud_in, *normals);
  }

  // Normal
  for (size_t i = 0; i < normals->size(); i++)
  {
    if (!pcl::isFinite<pcl::Normal>((*normals)[i]))
    {
      PCL_WARN("normals[%d] is not finite\n", i);
    }
  }

  // Setup spin image computation
  pcl::SpinImageEstimation<pcl::PointXYZ, pcl::Normal, pcl::Histogram<153>> spin_image_descriptor(8, 0.5, 16);
  spin_image_descriptor.setInputCloud (cloud);
  spin_image_descriptor.setInputNormals (normals);

  // Use the same KdTree from the normal estimation
  spin_image_descriptor.setSearchMethod (kdtree);
  pcl::PointCloud<pcl::Histogram<153>>::Ptr spin_images(new pcl::PointCloud<pcl::Histogram<153>>);
  // spin_image_descriptor.setRadiusSearch (0.2);
  spin_image_descriptor.setRadiusSearch (200); // 20cm

  // Actually compute the spin images
  spin_image_descriptor.compute (*spin_images);
  std::cout << "SI output points.size (): " << spin_images->points.size() << std::endl;

  // Display and retrieve the spin image descriptor vector for the first point.
  pcl::Histogram<153> first_descriptor = spin_images->points[0];
  std::cout << first_descriptor << std::endl;
}

void TEMPLATE_MATCHING::extractFeatureShapeContext(const pcl::PointCloud<pcl::PointXYZRGBNormal> &cloud_in, pcl::PointCloud<pcl::ShapeContext1980> &output)
{
  pcl::PointCloud<pcl::PointXYZ>::Ptr cloud(new pcl::PointCloud<pcl::PointXYZ>);
  pcl::PointCloud<pcl::Normal>::Ptr normals(new pcl::PointCloud<pcl::Normal>());
  pcl::copyPointCloud(cloud_in, *cloud);
  pcl::search::KdTree<pcl::PointXYZ>::Ptr kdtree(new pcl::search::KdTree<pcl::PointXYZ>);
  if (0) // normal est.
  {
    // Compute the normals
    pcl::NormalEstimation<pcl::PointXYZ, pcl::Normal> normal_estimation;
    normal_estimation.setInputCloud(cloud);

    pcl::search::KdTree<pcl::PointXYZ>::Ptr kdtree(new pcl::search::KdTree<pcl::PointXYZ>);
    normal_estimation.setSearchMethod(kdtree);

    pcl::PointCloud<pcl::Normal>::Ptr normals(new pcl::PointCloud<pcl::Normal>);
    // normal_estimation.setRadiusSearch (0.03);
    normal_estimation.setRadiusSearch(30); // 3cm
    normal_estimation.compute(*normals);
  }
  else // assigned normal
  {
    pcl::copyPointCloud(cloud_in, *normals);
  }

  // Normal
  for (size_t i = 0; i < normals->size(); i++)
  {
    if (!pcl::isFinite<pcl::Normal>((*normals)[i]))
    {
      PCL_WARN("normals[%d] is not finite\n", i);
    }
  }

  // Setup the shape context computation
  pcl::ShapeContext3DEstimation<pcl::PointXYZ, pcl::Normal, pcl::ShapeContext1980> shape_context;

  // Provide the point cloud
  shape_context.setInputCloud (cloud);
  // Provide normals
  shape_context.setInputNormals (normals);
  // Use the same KdTree from the normal estimation
  shape_context.setSearchMethod (kdtree);
  pcl::PointCloud<pcl::ShapeContext1980>::Ptr shape_context_features (new pcl::PointCloud<pcl::ShapeContext1980>);

  // The minimal radius is generally set to approx. 1/10 of the search radius, while the pt. density radius is generally set to 1/5
  // shape_context.setRadiusSearch (0.2);
  shape_context.setRadiusSearch (200);
  // shape_context.setPointDensityRadius (0.04);
  shape_context.setPointDensityRadius (40);
  // shape_context.setMinimalRadius (0.02);
  shape_context.setMinimalRadius (20);

  // Actually compute the shape contexts
  shape_context.compute (*shape_context_features);
  std::cout << "3DSC output points.size (): " << shape_context_features->points.size () << std::endl;

  // Display and retrieve the shape context descriptor vector for the 0th point.
  std::cout << shape_context_features->points[0] << std::endl;
  float* first_descriptor = shape_context_features->points[0].descriptor; // 1980 elements
}

