void TEMPLATE_MATCHING::saveBase2SensorFrameData2JSON(const Eigen::Matrix4f &T_in)
{
    ///////////////////////////////////////////////////////
    //// JSON parsing - sensor config
    ///////////////////////////////////////////////////////
    //// json file load
    std::stringstream sensor_config_path;
    sensor_config_path << m_package_path << "/config/sensor_config.json";
    std::ifstream ifs_sensor_config(sensor_config_path.str().c_str());
    json j_sensor_config = json::parse(ifs_sensor_config);
    // Eye-to-hand (global), calibrated
    std::vector<double> htm_base2sensor_vec(16, 0.0); // [mm]
    for (size_t i = 0; i < 4; i++) {
        for (size_t j = 0; j < 4; j++) {
            // htm_base2sensor_vec[4 * i + j] = T_in(i, j);
            htm_base2sensor_vec[4 * i + j] = round(T_in(i, j)*1e6) / 1e6;
        }
    }
    ////////////////////////////////////////////////////////////
    //// json file save
    std::stringstream ss;
    json j_out = j_sensor_config;

    // write the data to the output file
    j_out["htm_B2S_eye_to_hand"] = htm_base2sensor_vec;
    std::ofstream ofs(sensor_config_path.str().c_str());
    ofs << j_out.dump(4) << std::endl;
}

void TEMPLATE_MATCHING::saveEndEffector2SensorFrameData2JSON(const Eigen::Matrix4f &T_in)
{
    ///////////////////////////////////////////////////////
    //// JSON parsing - sensor config
    ///////////////////////////////////////////////////////
    //// json file load
    std::stringstream sensor_config_path;
    sensor_config_path << m_package_path << "/config/sensor_config.json";
    std::ifstream ifs_sensor_config(sensor_config_path.str().c_str());
    json j_sensor_config = json::parse(ifs_sensor_config);
    // Eye-in-hand (end-effector), calibrated
    // 1) T_E2S
    std::vector<double> htm_end2sensor_vec(16, 0.0); // [mm]
    Eigen::Matrix4f T_E2S_json = T_in;
    for (size_t i = 0; i < 4; i++) {
        for (size_t j = 0; j < 4; j++) {
            htm_end2sensor_vec[4 * i + j] = round(T_E2S_json(i, j)*1e6) / 1e6;
        }
    }

    // 1) T_E2S
    std::vector<double> htm_sensor2end_vec(16, 0.0); // [mm]
    Eigen::Matrix4f T_S2E_json = T_in.inverse();
    for (size_t i = 0; i < 4; i++) {
        for (size_t j = 0; j < 4; j++) {
            htm_sensor2end_vec[4 * i + j] = round(T_S2E_json(i, j)*1e6) / 1e6;
        }
    }

    ////////////////////////////////////////////////////////////
    //// json file save
    std::stringstream ss;
    json j_out = j_sensor_config;

    // write the data to the output file
    j_out["htm_E2S_eye_in_hand"] = htm_end2sensor_vec;
    j_out["htm_S2E_eye_in_hand"] = htm_sensor2end_vec;


    std::ofstream ofs(sensor_config_path.str().c_str());
    ofs << j_out.dump(4) << std::endl;
}
