//// b) Base frame optimization results
void TEMPLATE_MATCHING::saveNominalRobotBase2SensorFrameData2JSON(const Eigen::Matrix4f &T_in)
{
    ///////////////////////////////////////////////////////
    //// JSON parsing - sensor config
    ///////////////////////////////////////////////////////
    //// json file load
    std::stringstream sensor_config_path;
    sensor_config_path << m_package_path << "/config/sensor_config.json";
    std::ifstream ifs_sensor_config(sensor_config_path.str().c_str());
    json j_sensor_config = json::parse(ifs_sensor_config);
    bool is_eye_in_hand = j_sensor_config["is_eye_in_hand"];
    // Eye-in-hand (end-effector)
    std::vector<double> htm_end2sensor_vec = j_sensor_config["htm_E2S_eye_in_hand"].get<std::vector<double> >(); // HTM - End-effector(E) to Camera(S) (calibrated)
    // Eye-to-hand (global)
    std::vector<double> htm_base2sensor_vec = j_sensor_config["htm_B2S_eye_to_hand"].get<std::vector<double> >(); // Global, HTM - Robot Base{B) to Camera(S) (calibrated)
    size_t img_rows = j_sensor_config["img_rows"]; // 1200
    size_t img_cols = j_sensor_config["img_cols"]; // 1920
    std::vector<double> eye_to_hand_sensor_translation = j_sensor_config["eye_to_hand_sensor_translation"].get<std::vector<double> >();

    std::vector<double> htm_nominal_base2sensor_vec(16, 0.0); // [mm]
    for (size_t i = 0; i < 4; i++)
    {
        for (size_t j = 0; j < 4; j++)
        {
            // htm_nominal_base2sensor_vec[4 * i + j] = T_in(i, j);
            htm_nominal_base2sensor_vec[4 * i + j] = round(T_in(i, j)*1e6) / 1e6;
        }
    }

    ////////////////////////////////////////////////////////////
    //// json file save
    std::stringstream ss;
    json j_out;

    // write the data to the output file
    j_out["is_eye_in_hand"] = is_eye_in_hand;
    j_out["htm_E2S_eye_in_hand"] = htm_end2sensor_vec;
    j_out["htm_B2S_eye_to_hand"] = htm_base2sensor_vec;
    j_out["htm_B2S_eye_to_hand_nominal"] = htm_nominal_base2sensor_vec;
    j_out["img_rows"] = img_rows;
    j_out["img_cols"] = img_cols;
    j_out["eye_to_hand_sensor_translation"] = eye_to_hand_sensor_translation;
    std::ofstream ofs(sensor_config_path.str().c_str());
    ofs << j_out.dump(4) << std::endl;
}

