    j_out["img_cols"] = img_cols;
    j_out["eye_to_hand_sensor_translation"] = eye_to_hand_sensor_translation;
    std::ofstream ofs(sensor_config_path.str().c_str());
    ofs << j_out.dump(4) << std::endl;
