void TEMPLATE_MATCHING::saveVectorData2JSON(std::vector<std::vector<double>> &data, std::string file_path)
{
    //// json file save
    std::stringstream ss;
    json j_out;

    j_out["data_num"] = data.size();
    j_out["data_dim"] = data[0].size();
    // write the data to the output file
    for (size_t i = 0; i < data.size(); i++)
    {
        j_out["data"][i] = data[i];
    }

    std::ofstream ofs(file_path.c_str());
    ofs << j_out.dump(4) << std::endl;

}

bool TEMPLATE_MATCHING::loadVectorData2JSON(std::vector<std::vector<double>> &data, std::string file_path)
{
    std::ifstream ifs(file_path.c_str());
    json j_in = json::parse(ifs);
    size_t data_num = j_in["data_num"];
    size_t data_dim = j_in["data_dim"];
    data.clear();
    data.reserve(data_num);
    for(size_t i=0; i<data_num; i++)
    {
        data.push_back(j_in["data"][i].get<std::vector<double>>());
    }
    return true;
}

void TEMPLATE_MATCHING::saveEigenData2CSV(std::vector<Eigen::VectorXf> &data, std::string file_path)
{
    size_t data_dim = data[0].size();
    std::ofstream outputFile;
    // create a name for the file output
    // create and open the .csv file
    outputFile.open(file_path.c_str());
    outputFile << data.size() << "," << data_dim << std::endl
               << std::endl;

    // write the data to the output file
    for (size_t i = 0; i < data.size(); i++)
    {
        for (size_t j = 0; j < data_dim; j++) { outputFile << data[i][j] << ","; }
        outputFile << std::endl;
    }
    // close the output file
    outputFile.close();
}

