void TEMPLATE_MATCHING::saveIndexData2CSV(std::vector<size_t> &data, std::string file_path, std::string file_name)
{
    std::ofstream outputFile;
    // create a name for the file output
    std::stringstream ss;
    ss << file_path.c_str() << file_name << ".csv";
    // create and open the .csv file
    outputFile.open(ss.str().c_str());

    outputFile << data.size() << std::endl
               << std::endl;
    // write the data to the output file
    for (size_t i = 0; i < data.size(); i++)
    {
        outputFile << data[i] << std::endl;
    }
    // close the output file
    outputFile.close();
}

bool TEMPLATE_MATCHING::loadIndexData2CSV(std::vector<size_t> &data, std::string file_path, std::string file_name)
{
    data.clear();
    std::stringstream ss;
    ss << file_path.c_str() << file_name << ".csv";
    // create and open the .csv file
    FILE *f;
    size_t idx, num;
    if ((f = fopen(ss.str().c_str(), "r")) == NULL)
    {
        return false;
    }
    int ret = fscanf(f, "%zu", &num);
    for (size_t i = 0; i < num; i++)
    {
        int ret_tmp = fscanf(f, "%zu", &idx);
        data.push_back(idx);
    }
    fclose(f);

    return true;
}

void TEMPLATE_MATCHING::selectMaskRCNN(CTARGET_OBJECT_DATA* &target_object_data, pcl::PointCloud<pcl::PointXYZ> &cloud_mask, pcl::PointCloud<pcl::PointXYZRGBNormal> &cloud_mask_rgbn, pcl::PointCloud<pcl::PointXYZ> &cloud_mask_processed, pcl::PointCloud<pcl::PointXYZRGBNormal> &cloud_mask_processed_rgbn)
{
    size_t idx_target_mask = 0;
    //// Mask RCNN results processing
    std::vector<size_t> mask_confident_idx_set = target_object_data->mask_data.mask_confident_idx_set;
    std::vector<size_t> pre_selected_idx_set = target_object_data->mask_data.pre_selected_idx_set;
    if (mask_confident_idx_set.size() == 0) // no mask results
    {
        ROS_LOG_INFO("mrcnn - no confident mask results!!!");
        ROS_LOG_INFO("Object detection failure! (Mask RCNN) - No results");
    }
    ///////////////////////////////////////////////////////
    //// mrcnn results processing 1 - cloud_base_aligned z
    ROS_LOG_INFO("---------------- mrcnn mask selection process 1 --------------------");
    double max_z_value = 0.0;
    bool is_all_objects_same_level = true;
    double thre_dist_z = 0.005; // 5mm
    Eigen::Vector3f bin_center_point_base_frame = target_object_data->bin_center_point_base_frame;
    std::vector<size_t> idx_centroid_to_bin_center_set;
    std::vector<double> dist_centroid_to_bin_center_set;
    for (size_t i = 0; i < mask_confident_idx_set.size(); i++)
    {
        if (mask_confident_idx_set.size() == 1) { break; }
        size_t idx_now = mask_confident_idx_set[i];

        // 사용한 인덱스는 제외
        bool is_selected_mask = false;
        for (size_t j = 0; j < pre_selected_idx_set.size(); j++)
        {
            if(pre_selected_idx_set[j] == idx_now) 
            {
                is_selected_mask = true;
                break;
            }
        }
        if(is_selected_mask) 
        {
            ROS_LOG_INFO("Already used mask! (index #%zu)", idx_now + 1); 
            continue; 
        }

        // *mask_cloud_base_aligned = target_object_data->mask_data.mask_cloud_base_aligned_list[idx_now];
        //// centroid
        Eigen::Vector4f xyz_centroid = target_object_data->mask_data.xyz_centroid_list[idx_now];
        // ROS_LOG_INFO("Centroid (#%zu): %0.6f, %0.6f, %0.6f", idx_now + 1, xyz_centroid[0], xyz_centroid[1], xyz_centroid[2]);
        if (i == 0)
        {
            idx_target_mask = idx_now; // update
            max_z_value = xyz_centroid[2];
            idx_centroid_to_bin_center_set.clear();
            dist_centroid_to_bin_center_set.clear();
            idx_centroid_to_bin_center_set.push_back(idx_now);
            Eigen::Vector2f xyz_centroid_2d = xyz_centroid.block<2, 1>(0, 0);
            Eigen::Vector2f bin_center_point_2d = bin_center_point_base_frame.block<2, 1>(0, 0);
            double dist_centroid_to_bin_center = (xyz_centroid_2d - bin_center_point_2d).norm();
            dist_centroid_to_bin_center_set.push_back(dist_centroid_to_bin_center);
        }
        else
        {
            double dist_z = fabs(max_z_value - xyz_centroid[2]);
            if (max_z_value < xyz_centroid[2] && dist_z >= thre_dist_z)
            {
                // ROS_LOG_INFO("maximum z!");
                idx_target_mask = idx_now; // update
                max_z_value = xyz_centroid[2];
                is_all_objects_same_level = false;
                idx_centroid_to_bin_center_set.clear();
                dist_centroid_to_bin_center_set.clear();
                idx_centroid_to_bin_center_set.push_back(idx_now);
                Eigen::Vector2f xyz_centroid_2d = xyz_centroid.block<2, 1>(0, 0);
                Eigen::Vector2f bin_center_point_2d = bin_center_point_base_frame.block<2, 1>(0, 0);
                double dist_centroid_to_bin_center = (xyz_centroid_2d - bin_center_point_2d).norm();
                dist_centroid_to_bin_center_set.push_back(dist_centroid_to_bin_center);
            }
            else if (max_z_value >= xyz_centroid[2] && dist_z >= thre_dist_z)
            {
                // ROS_LOG_INFO("skipped!");
            }
            else
            {
                // ROS_LOG_INFO("same level z!");
                is_all_objects_same_level = true;
                idx_centroid_to_bin_center_set.push_back(idx_now);
                Eigen::Vector2f xyz_centroid_2d = xyz_centroid.block<2, 1>(0, 0);
                Eigen::Vector2f bin_center_point_2d = bin_center_point_base_frame.block<2, 1>(0, 0);
                double dist_centroid_to_bin_center = (xyz_centroid_2d - bin_center_point_2d).norm();
                dist_centroid_to_bin_center_set.push_back(dist_centroid_to_bin_center);
            }
        }
    }

    ROS_LOG_INFO("---------------- mrcnn mask selection process 2 --------------------");
    //// TODO: 모든 인식된 물체 사이의 거리가 threshold 이내에 있으면 이 중에 가장 중심에 가까운 물체를 선택
    if (is_all_objects_same_level && dist_centroid_to_bin_center_set.size() > 1)
    {
        // ROS_LOG_INFO("**** All objects are in the same level! ****");
        size_t idx_min;
        double dis_min;
        m_math.genVecMinMax(dist_centroid_to_bin_center_set, idx_min, dis_min, 0);
        idx_target_mask = idx_centroid_to_bin_center_set[idx_min];
        // ROS_LOG_INFO("Bin center point: %0.6f, %0.6f, %0.6f", bin_center_point_base_frame[0], bin_center_point_base_frame[1], bin_center_point_base_frame[2]);
        // ROS_LOG_INFO("Minimum distance(XY plane) to bin center(object #%zu): %0.3f", idx_target_mask + 1, dis_min);
    }

    /////////////////////////////////////////////////////////////////
    /////////////////////////////////////////////////////////////////
    /////////////////////////////////////////////////////////////////
    ///////////////////// Mask cloud generation /////////////////////
    /////////////////////////////////////////////////////////////////
    /////////////////////////////////////////////////////////////////
    /////////////////////////////////////////////////////////////////

    pcl::PointCloud<pcl::PointXYZRGBA>::Ptr cloud_mask_sensor(new pcl::PointCloud<pcl::PointXYZRGBA>);
    pcl::PointCloud<pcl::PointXYZRGBNormal>::Ptr cloud_mask_sensor_rgbn(new pcl::PointCloud<pcl::PointXYZRGBNormal>);
    pcl::PointCloud<pcl::PointXYZ>::Ptr cloud_mask_base(new pcl::PointCloud<pcl::PointXYZ>);
    pcl::PointCloud<pcl::PointXYZRGBNormal>::Ptr cloud_mask_base_rgbn(new pcl::PointCloud<pcl::PointXYZRGBNormal>);
    *cloud_mask_sensor = target_object_data->mask_data.cloud_mask_rgba_list[idx_target_mask];
    *cloud_mask_sensor_rgbn = target_object_data->mask_data.cloud_mask_rgbn_list[idx_target_mask];
    *cloud_mask_base = target_object_data->mask_data.mask_cloud_base_aligned_list[idx_target_mask]; // on_points에서 미리 처리된 cloud
    *cloud_mask_base_rgbn = target_object_data->mask_data.mask_cloud_base_aligned_rgbn_list[idx_target_mask];


    // ROS_LOG_INFO("*******************************************");
    // ROS_LOG_INFO("cloud in mask(selected): %d", cloud_mask_selected->size());
    // ROS_LOG_INFO("*******************************************");
    // ROS_LOG_INFO("Final mask index: #%zu", idx_target_mask + 1);
    // ROS_LOG_INFO("*******************************************");

    // output mask cloud
    pcl::copyPointCloud(*cloud_mask_sensor, cloud_mask);
    pcl::copyPointCloud(*cloud_mask_sensor_rgbn, cloud_mask_rgbn);
    pcl::copyPointCloud(*cloud_mask_base, cloud_mask_processed);
    pcl::copyPointCloud(*cloud_mask_base_rgbn, cloud_mask_processed_rgbn);
    
    
    // update
    target_object_data->mask_data.idx_target_mask_process = idx_target_mask; // current index
    pre_selected_idx_set.push_back(idx_target_mask); // selected index update
    target_object_data->mask_data.pre_selected_idx_set = pre_selected_idx_set;
}

void TEMPLATE_MATCHING::selectMaskSAM(CTARGET_OBJECT_DATA* &target_object_data, pcl::PointCloud<pcl::PointXYZ> &cloud_mask, pcl::PointCloud<pcl::PointXYZRGBNormal> &cloud_mask_rgbn, pcl::PointCloud<pcl::PointXYZ> &cloud_mask_processed, pcl::PointCloud<pcl::PointXYZRGBNormal> &cloud_mask_processed_rgbn)
{
    size_t idx_target_mask = 0;
    //// SAM results processing
    std::vector<size_t> mask_confident_idx_set = target_object_data->mask_data.mask_confident_idx_set;
    std::vector<size_t> pre_selected_idx_set = target_object_data->mask_data.pre_selected_idx_set;
    if (mask_confident_idx_set.size() == 0) // no mask results
    {
        ROS_LOG_INFO("selectMaskSAM - no confident mask results!!!");
        ROS_LOG_INFO("Object detection failure! (SAM) - No results");
    }

    bool is_optimal_mask_selected = false;
    ROS_LOG_INFO("---------------- sam mask selection process 1 --------------------");
    //// Mask selection process 1 - SAM
    //// TODO: 아래 임계값을 설정 부분 추가하기. --> 현재는 1.0이 최소값이고, 이 값에 가까울수록 주변에 물체가 없는 것
    // float sam_nearby_ratio_threshold = 1.05;
    float sam_nearby_ratio_threshold = target_object_data->sam_nearby_ratio_threshold;
    ROS_LOG_INFO("sam_nearby_ratio_threshold: %0.2f", sam_nearby_ratio_threshold);
    std::vector<float> ext_nearby_ratio_set = target_object_data->mask_data.ext_nearby_ratio;

    ROS_LOG_INFO("The # of confident masks: %zu", mask_confident_idx_set.size());

    for (size_t i = 0; i < mask_confident_idx_set.size(); i++)
    {
        if (mask_confident_idx_set.size() == 1) { 
            is_optimal_mask_selected = true;
            break; 
        }
        size_t idx_now = mask_confident_idx_set[i];
        // 사용한 인덱스는 제외
        bool is_selected_mask = false;
        for (size_t j = 0; j < pre_selected_idx_set.size(); j++) 
        {
            if(pre_selected_idx_set[j] == idx_now) {
                is_selected_mask = true;
                break;
            }
        }
        if(is_selected_mask) { continue; }

        //// NOTICE: 이 부분을 수행하면 z 기준이 적용되지 않음
        //// TODO: z는 낮지만 우선순위가 높은 것은 선택하도록 처리해야 함.
        //// TODO: 현재, SAM에서 주변 물체가 인식되지 않는 경우에는 이 지표가 잘못된 값을 갖게될 가능성이 큼
        if(0) {
            if(ext_nearby_ratio_set[i] < sam_nearby_ratio_threshold) {
                idx_target_mask = idx_now;
                is_optimal_mask_selected = true;
                ROS_LOG_INFO("Selected mask index(SAM selection process 1): #%zu (nearby_ratio: %0.3f)", idx_target_mask + 1, ext_nearby_ratio_set[i]);
                break;
            }
        }
    }

    ///////////////////////////////////////////////////////
    //// Mask selection process 2 - base frame 기준의 z값이 가장 큰 index를 선택
    ROS_LOG_INFO("---------------- sam mask selection process 2 --------------------");
    double max_z_value = 0.0;
    bool is_all_objects_same_level = true;
    double thre_dist_z = 0.005; // 5mm
    Eigen::Vector3f bin_center_point_base_frame = target_object_data->bin_center_point_base_frame;
    std::vector<size_t> idx_centroid_to_bin_center_set;
    for (size_t i = 0; i < mask_confident_idx_set.size(); i++)
    {
        if(is_optimal_mask_selected) { break; }
        if (mask_confident_idx_set.size() == 1) { break; }
        size_t idx_now = mask_confident_idx_set[i];

        // 사용한 인덱스는 제외
        bool is_selected_mask = false;
        for (size_t j = 0; j < pre_selected_idx_set.size(); j++)
        {
            if(pre_selected_idx_set[j] == idx_now) 
            {
                is_selected_mask = true;
                break;
            }
        }
        if(is_selected_mask) 
        {
            ROS_LOG_INFO("Already used mask! (index #%zu)", idx_now + 1); 
            continue; 
        }

        // *mask_cloud_base_aligned = target_object_data->mask_data.mask_cloud_base_aligned_list[idx_now];
        //// centroid
        Eigen::Vector4f xyz_centroid = target_object_data->mask_data.xyz_centroid_list[idx_now];
        // ROS_LOG_INFO("Centroid (#%zu): %0.6f, %0.6f, %0.6f", idx_now + 1, xyz_centroid[0], xyz_centroid[1], xyz_centroid[2]);
        if (i == 0)
        {
            idx_target_mask = idx_now; // update
            max_z_value = xyz_centroid[2];
            idx_centroid_to_bin_center_set.clear();
            idx_centroid_to_bin_center_set.push_back(idx_now);
        }
        else
        {
            double dist_z = fabs(max_z_value - xyz_centroid[2]);
            if (max_z_value < xyz_centroid[2] && dist_z >= thre_dist_z)
            {
                ROS_LOG_INFO("maximum z!");
                idx_target_mask = idx_now; // update
                max_z_value = xyz_centroid[2];
                is_all_objects_same_level = false;
                idx_centroid_to_bin_center_set.clear();
                idx_centroid_to_bin_center_set.push_back(idx_now);
            }
            else if (max_z_value >= xyz_centroid[2] && dist_z >= thre_dist_z)
            {
                ROS_LOG_INFO("skipped!");
            }
            else
            {
                ROS_LOG_INFO("same level z!");
                is_all_objects_same_level = true;
                idx_centroid_to_bin_center_set.push_back(idx_now);
            }
        }
    }
    //// Mask selection process 3 - z값이 큰 물체 중에 우선순위가 높은 것을 선택
    if (!is_optimal_mask_selected && is_all_objects_same_level && idx_centroid_to_bin_center_set.size() > 1) {
        idx_target_mask = idx_centroid_to_bin_center_set[0]; // index의 정렬 기준은 우선순위가 높은 순서
    }

    /////////////////////////////////////////////////////////////////
    /////////////////////////////////////////////////////////////////
    /////////////////////////////////////////////////////////////////
    ///////////////////// Mask cloud generation /////////////////////
    /////////////////////////////////////////////////////////////////
    /////////////////////////////////////////////////////////////////
    /////////////////////////////////////////////////////////////////

    pcl::PointCloud<pcl::PointXYZRGBA>::Ptr cloud_mask_sensor(new pcl::PointCloud<pcl::PointXYZRGBA>);
    pcl::PointCloud<pcl::PointXYZRGBNormal>::Ptr cloud_mask_sensor_rgbn(new pcl::PointCloud<pcl::PointXYZRGBNormal>);
    pcl::PointCloud<pcl::PointXYZ>::Ptr cloud_mask_base(new pcl::PointCloud<pcl::PointXYZ>);
    pcl::PointCloud<pcl::PointXYZRGBNormal>::Ptr cloud_mask_base_rgbn(new pcl::PointCloud<pcl::PointXYZRGBNormal>);
    *cloud_mask_sensor = target_object_data->mask_data.cloud_mask_rgba_list[idx_target_mask];
    *cloud_mask_sensor_rgbn = target_object_data->mask_data.cloud_mask_rgbn_list[idx_target_mask];
    *cloud_mask_base = target_object_data->mask_data.mask_cloud_base_aligned_list[idx_target_mask]; // on_points에서 미리 처리된 cloud
    *cloud_mask_base_rgbn = target_object_data->mask_data.mask_cloud_base_aligned_rgbn_list[idx_target_mask];


    // ROS_LOG_INFO("*******************************************");
    // ROS_LOG_INFO("cloud in mask(selected): %d", cloud_mask_selected->size());
    // ROS_LOG_INFO("*******************************************");
    // ROS_LOG_INFO("Final mask index: #%zu", idx_target_mask + 1);
    // ROS_LOG_INFO("*******************************************");

    // output mask cloud
    pcl::copyPointCloud(*cloud_mask_sensor, cloud_mask);
    pcl::copyPointCloud(*cloud_mask_sensor_rgbn, cloud_mask_rgbn);
    pcl::copyPointCloud(*cloud_mask_base, cloud_mask_processed);
    pcl::copyPointCloud(*cloud_mask_base_rgbn, cloud_mask_processed_rgbn);
    
    
    // update
    target_object_data->mask_data.idx_target_mask_process = idx_target_mask; // current index
    pre_selected_idx_set.push_back(idx_target_mask); // selected index update
    target_object_data->mask_data.pre_selected_idx_set = pre_selected_idx_set;
}

