    // 변경 브라켓
    // std::vector<double> tcp = {0.0, 0.0, 0.24700, 0, 0, 90.0*DEGTORAD}; // base gripper
    // std::vector<double> tcp = {-0.20424, 0.0, 0.21964, 0, -45.0*DEGTORAD, 0}; // left gripper

