    pcl::PointCloud<pcl::PointXYZ>::Ptr cloud_mask_base_aligned(new pcl::PointCloud<pcl::PointXYZ>);
    pcl::PointCloud<pcl::PointXYZRGBNormal>::Ptr cloud_mask_base_aligned_rgbn(new pcl::PointCloud<pcl::PointXYZRGBNormal>);
