                    Eigen::Matrix4f T_result;

                    // cloud_base_aligned, cloud_CAD_uniformly_downsampled - [mm]
                    m_pcl_proc.matchingMajorAxisTranslation(*target_object_data->cloud_base_aligned, *target_object_data->cloud_CAD_uniformly_downsampled, T_init, T_result, false);
                    pcl::PointCloud<pcl::PointXYZ>::Ptr cloud_mask_tmp(new pcl::PointCloud<pcl::PointXYZ>);
                    pcl::transformPointCloud(*target_object_data->cloud_base_aligned, *cloud_mask_tmp, T_result);

