                //// 다음 물체에서의 충돌확인을 위해 앞서 제거했던 부분에 매칭된 CAD 파일을 병합함
                //// Object CAD cloud
                // merging matching results w.r.t {B}
                pcl::PointCloud<pcl::PointXYZ>::Ptr cloud_object_CAD(new pcl::PointCloud<pcl::PointXYZ>);
                pcl::copyPointCloud(*target_object_data->cloud_CAD_uniformly_downsampled, *cloud_object_CAD);
