                //// 다음 물체에서의 충돌확인을 위해 앞서 제거했던 부분에 매칭된 CAD 파일을 병합함
                selectMaskSAM(target_object_data, *cloud_src, *cloud_src_rgbn, *cloud_mask_base_aligned, *cloud_mask_base_aligned_rgbn);
