            m_math.cloudScaling(*cloud_mask_base_aligned_rgbn, 1); // m to mm
            *target_object_data->cloud_base_aligned = *cloud_mask_base_aligned; // metric: [mm]
            *target_object_data->cloud_base_aligned_rgbn = *cloud_mask_base_aligned_rgbn; // metric: [mm]

