    //////////////////////////////////////////////////////////////////
    //////////////////////////////////////////////////////////////////            
    //// SOLUTION: 일단 구 내에 존재하는 격자형태로 Base frame 위치를 지정해둔 후에, 이 중에 모든 자세에 대해 특이점이 없고, 조작성이 최대인 base frame을 선택
    //// Gen. base translation set
    pcl::PointCloud<pcl::PointXYZ>::Ptr cloud_query_base_center(new pcl::PointCloud<pcl::PointXYZ>);
    pcl::PointCloud<pcl::PointXYZRGB>::Ptr cloud_query_base_center_rgb(new pcl::PointCloud<pcl::PointXYZRGB>);
    genQueryBaseFramePoints(target_object_data, *cloud_query_base_center_rgb);
    pcl::copyPointCloud(*cloud_query_base_center_rgb, *cloud_query_base_center);

