bool TEMPLATE_MATCHING::checkWorkspace(const std::vector<double> pose, const std::vector<double> &workspace)
{
    double x_min = workspace[0]; double x_max = workspace[1]; // m
    double y_min = workspace[2]; double y_max = workspace[3]; // m
    double z_min = workspace[4]; double z_max = workspace[5];// m
    double rx_min = workspace[6]; double rx_max = workspace[7]; // deg
    double ry_min = workspace[8]; double ry_max = workspace[9]; // deg
    double rz_min = workspace[10]; double rz_max = workspace[11]; // deg

    if ((pose[0] > x_min && pose[0] < x_max) && (pose[1] > y_min && pose[1] < y_max) && (pose[2] > z_min && pose[2] < z_max) && (fabs(pose[3]) > rx_min && fabs(pose[3]) < rx_max) && (pose[4] > ry_min && pose[4] < ry_max) && (fabs(pose[5]) > rz_min && fabs(pose[5]) < rz_max))
    {
        ROS_LOG_INFO("Check the pose in the workspace - OK");
        return true;
    }
    else
    {
        ROS_LOG_WARN("Check the pose in the workspace - out of range");
        ROS_LOG_WARN("Grasping Pose [m],[deg]: %0.5f, %0.5f, %0.5f, %0.2f, %0.2f, %0.2f", pose[0], pose[1], pose[2], pose[3], pose[4], pose[5]);
        ROS_LOG_WARN("Workspace [m] - x: %0.5f, %0.5f, y: %0.5f, %0.5f, z: %0.5f, %0.5f", x_min, x_max, y_min, y_max, z_min, z_max);
        return false;
    }
}

bool TEMPLATE_MATCHING::checkWorkspacePosition(const std::vector<double> pose, const std::vector<double> &workspace)
{
    double x_min = workspace[0]; double x_max = workspace[1]; // m
    double y_min = workspace[2]; double y_max = workspace[3]; // m
    double z_min = workspace[4]; double z_max = workspace[5];// m

    if ((pose[0] > x_min && pose[0] < x_max) && (pose[1] > y_min && pose[1] < y_max) && (pose[2] > z_min && pose[2] < z_max))
    {
        // ROS_LOG_INFO("(checkWorkspacePosition)Check the position in the workspace - OK");
        return true;
    }
    else
    {
        // ROS_LOG_WARN("(checkWorkspacePosition) Check the position in the workspace - out of range");
        // ROS_LOG_WARN("Grasping Pose [m],[deg]: %0.5f, %0.5f, %0.5f, %0.2f, %0.2f, %0.2f", pose[0], pose[1], pose[2], pose[3], pose[4], pose[5]);
        // ROS_LOG_WARN("Workspace [m] - x: %0.5f, %0.5f, y: %0.5f, %0.5f, z: %0.5f, %0.5f", x_min, x_max, y_min, y_max, z_min, z_max);
        return false;
    }
}

