bool TEMPLATE_MATCHING::extractCollisionCloudResults(CTARGET_OBJECT_DATA* &target_object_data, const std::string &color, pcl::PointCloud<pcl::PointXYZRGBNormal> &cloud_matching_results) 
{
    size_t cnt_occupied = 0;
    std::vector<double> rgb_match(3);
    std::vector<double> rgb_fail(3);
    if(color == "r")
    {
        rgb_match[0] = 255;   rgb_match[1] = 1; rgb_match[2] = 1;
        rgb_fail[0] = 1;   rgb_fail[1] = 1; rgb_fail[2] = 255;
    }
    else if(color == "g")
    {
        rgb_match[0] = 1;   rgb_match[1] = 255; rgb_match[2] = 1;
        rgb_fail[0] = 1;   rgb_fail[1] = 1; rgb_fail[2] = 255;
    }
    else if(color == "b")
    {
        rgb_match[0] = 1;   rgb_match[1] = 1; rgb_match[2] = 255;
        rgb_fail[0] = 255;   rgb_fail[1] = 1; rgb_fail[2] = 1;
    }
    int octo_status = 0;
    
    //// collection 생성 시간 - 추후 연산량 줄이기 위해, 전역변수로 변경
    octomap::MapCollection<octomap::MapNode<octomap::OcTree>> collection;
    m_pcl_proc.genOctomapCollection(target_object_data->m_OctoMap_bin_CAD, target_object_data->m_OctoMap_simulation_process, collection);

    for (size_t i = 0; i < cloud_matching_results.size(); i++)
    {
        // Eigen::Vector3f pt = m_math.cloud2pt(cloud_matching_results, i);
        Eigen::Vector3f pt = cloud_matching_results.points[i].getVector3fMap();
        octomap::point3d pt_in;
	    pt_in(0) = pt[0]; pt_in(1) = pt[1]; pt_in(2) = pt[2];

        // octo_status = m_pcl_proc.checkSinglePointOccupancyVer3(pt_in, OctoMap_CAD, 0.6);
        octo_status = m_pcl_proc.checkSinglePointOccupancyUsingMapCollection(pt_in, collection);
        if (octo_status == 1)
        {
            cloud_matching_results.points[i].r = rgb_match[0];
            cloud_matching_results.points[i].g = rgb_match[1];
            cloud_matching_results.points[i].b = rgb_match[2];
            cnt_occupied++;
        }
        else if(octo_status == 0)
        {
            // ROS_LOG_INFO("Point #%u unoccupied!", i);
            cloud_matching_results.points[i].r = rgb_fail[0];
            cloud_matching_results.points[i].g = rgb_fail[1];
            cloud_matching_results.points[i].b = rgb_fail[2];
        }
        else if(octo_status == -1)
        {
            throw std::runtime_error("The the input cloud have NAN point, func.: TEMPLATE_MATCHING::extractCollisionCloudResults -> VIEWPLANNING::checkSinglePointOccupancyVer3()");
        }
    }
    if(cnt_occupied > 0) return true;
    else return false;
}

double TEMPLATE_MATCHING::extractCollisionCloudResultsWithKDTree(CTARGET_OBJECT_DATA* &target_object_data, const std::string &color, pcl::PointCloud<pcl::PointXYZRGBNormal> &cloud_matching_results)
{
    double matching_accuracy = 0.0;
    size_t cnt_occupied = 0;

    std::vector<int> nn_indices;
	std::vector<float> nn_squared_dists;
    pcl::PointCloud<pcl::PointXYZ>::Ptr cloud_matching_xyz(new pcl::PointCloud<pcl::PointXYZ>);
    pcl::copyPointCloud(cloud_matching_results, *cloud_matching_xyz);

	pcl::PointIndices::Ptr idx_cloud_in(new pcl::PointIndices());
	pcl::PointIndices::Ptr idx_cloud_map(new pcl::PointIndices());

    std::vector<double> rgb_match(3);
    std::vector<double> rgb_fail(3);
    if(color == "r")
    {
        rgb_match[0] = 255;   rgb_match[1] = 1; rgb_match[2] = 1;
        rgb_fail[0] = 1;   rgb_fail[1] = 1; rgb_fail[2] = 255;
    }
    else if(color == "g")
    {
        rgb_match[0] = 1;   rgb_match[1] = 255; rgb_match[2] = 1;
        rgb_fail[0] = 1;   rgb_fail[1] = 1; rgb_fail[2] = 255;
    }
    else if(color == "b")
    {
        rgb_match[0] = 1;   rgb_match[1] = 1; rgb_match[2] = 255;
        rgb_fail[0] = 255;   rgb_fail[1] = 1; rgb_fail[2] = 1;
    }

    int octo_status = 0;

    //// collection 생성 시간 - 추후 연산량 줄이기 위해, 전역변수로 변경
    octomap::MapCollection<octomap::MapNode<octomap::OcTree>> collection;
    m_pcl_proc.genOctomapCollection(target_object_data->m_OctoMap_bin_CAD, target_object_data->m_OctoMap_simulation_process, collection);

    for (size_t i = 0; i < cloud_matching_results.size(); i++)
    {
        // Eigen::Vector3f pt = m_math.cloud2pt(cloud_matching_results, i);
        Eigen::Vector3f pt = cloud_matching_results.points[i].getVector3fMap();
        octomap::point3d pt_in;
	    pt_in(0) = pt[0]; pt_in(1) = pt[1]; pt_in(2) = pt[2];

        // target_object_data->md_KdTree_octoMap_bin_CAD.nearestKSearch(cloud_matching_xyz->points[i], 1, nn_indices, nn_squared_dists);
        target_object_data->md_KdTree_octoMap_objects_with_bin_simulation_process.nearestKSearch(cloud_matching_xyz->points[i], 1, nn_indices, nn_squared_dists);
        // octo_status = m_pcl_proc.checkSinglePointOccupancyVer3(pt_in, OctoMap_CAD, 0.6);
        octo_status = m_pcl_proc.checkSinglePointOccupancyUsingMapCollection(pt_in, collection);

        if (octo_status == 1)
        {
            cloud_matching_results.points[i].r = rgb_match[0];
            cloud_matching_results.points[i].g = rgb_match[1];
            cloud_matching_results.points[i].b = rgb_match[2];
            cnt_occupied++;

            idx_cloud_in->indices.push_back(i); // input cloud collision point idx
            idx_cloud_map->indices.push_back(nn_indices[0]); // input cloud collision point idx
        }
        else if(octo_status == 0)
        {
            // // KDTree 이용한 최소 거리 판별 --> 잘 matching 됐으나, OctoMap으로 판별되지 않은 경우를 체크
            // target_object_data->md_KdTree_octoMap_bin_CAD.nearestKSearch(cloud_matching_xyz->points[i], 1, nn_indices, nn_squared_dists);

            if(sqrt(nn_squared_dists[0]) < target_object_data->cad_raw_voxel_filter_size)
            {
                cloud_matching_results.points[i].r = rgb_match[0];
                cloud_matching_results.points[i].g = rgb_match[1];
                cloud_matching_results.points[i].b = rgb_match[2];
                cnt_occupied++;

                idx_cloud_in->indices.push_back(i); // input cloud collision point idx
                idx_cloud_map->indices.push_back(nn_indices[0]); // input cloud collision point idx
            }
            else
            {
                // ROS_LOG_INFO("Point #%u unoccupied!", i);
                cloud_matching_results.points[i].r = rgb_fail[0];
                cloud_matching_results.points[i].g = rgb_fail[1];
                cloud_matching_results.points[i].b = rgb_fail[2];
            }
        }
        else if(octo_status == -1)
        {
            throw std::runtime_error("The the input cloud have NAN point, func.: TEMPLATE_MATCHING::extractCollisionCloudResults -> VIEWPLANNING::checkSinglePointOccupancyVer3()");
        }
    }

    *target_object_data->simulation_collision_idx_cloud_in = *idx_cloud_in;
    *target_object_data->simulation_collision_idx_cloud_map = *idx_cloud_map;

    matching_accuracy = static_cast<double>(cnt_occupied)/static_cast<double>(cloud_matching_results.size());
    return matching_accuracy;
}

