//// CAD simulation - bin placing
//// 초기 자세 입력
void TEMPLATE_MATCHING::doCustomPlacingObject2Bin_ver2(CTARGET_OBJECT_DATA* &target_object_data)
{
    //// Manipulate objects
    pcl::copyPointCloud(*target_object_data->cloud_CAD_uniformly_downsampled_with_mesh_normal, *target_object_data->cloud_process_object_CAD_simulation);

    //// Contact point initialize
    target_object_data->idx_set_contact_point.clear();
    // target_object_data->m_set_cloud_contact_nearest.clear();
    target_object_data->m_set_idx_contact_nearest.clear();
    target_object_data->T_process_simulation = Eigen::Matrix4f::Identity();
    target_object_data->T_bin2Contact = Eigen::Matrix4f::Identity();
    target_object_data->T_contact2Bin = Eigen::Matrix4f::Identity();
    

    //// Custom matching 
    std::vector<double> custom_transformation_pose = target_object_data->custom_transformation_pose;
    for (int i = 0; i < 3; i++) 
    { 
        custom_transformation_pose[i] = 1000.0*custom_transformation_pose[i]; 
        custom_transformation_pose[i + 3] = DEGTORAD * custom_transformation_pose[i + 3]; 
    }

    // input metric: [mm], [rad]
    Eigen::Matrix4f T_init = Eigen::Matrix4f::Identity();
    Eigen::Matrix4f T_process = model_.poseVector2HTM(custom_transformation_pose);
    T_process = T_process*T_init;


    //// NOTICE: 기존에 임의로 모션을 주던 부분을 동역학으로 대체함.
    // simulation object update
    std::vector<double> pose_now = m_math.htm2pose_mm2m(T_process, "T_process"); // [mm] to [m]
    Eigen::Vector3f linear_position(pose_now[0], pose_now[1], pose_now[2]);
    target_object_data->simulation_object.setPosition(linear_position, T_process.block<3, 3>(0, 0));
    target_object_data->simulation_object.setContact(false);

    manipulateObjectsAndEvaluateVoxelMap_ver2(false, target_object_data, *target_object_data->cloud_process_object_CAD_simulation);
    // if(0) plotRGBCloud(*cloud_simulation_merged_object_only_results, 800.0, 5.0, "cloud_simulation_merged_object_only_results");

}

