bool TEMPLATE_MATCHING::manipulateObjectsAndEvaluateVoxelMap_ver2(bool do_step, CTARGET_OBJECT_DATA* &target_object_data, pcl::PointCloud<pcl::PointXYZRGBNormal> &cloud_process)
{
    //// NOTTODO: 동역학으로 추출된 현재 자세를 물체 좌표계 기준으로? --> 이럴 필요 없음
    //// NOTICE: 단순히 step() 함수 실행 후에 현재 자세 받아와서 T 변환하면 됨.

    //////////////////////////////////////////////////////////////////////////////////////
    // Manipulate
    printf("\n\n*****************************************************************************\n");
    printf("**********************************************************************\n");
    printf("****************************************************************\n");
    if(do_step) target_object_data->simulation_object.step();
    Eigen::Matrix4f T_now = target_object_data->simulation_object.getPosition(); // [m], [rad]
    T_now.block<3, 1>(0, 3) *= 1000.0;
    std::vector<double> pose_now = m_math.htm2pose(T_now, "T_now");
    Eigen::VectorXf pose_tmp(6);
    for (int i = 0; i < 6; i++) pose_tmp[i] = pose_now[i];
    Eigen::VectorXf vel_tmp = target_object_data->simulation_object.getVelocity(); // [m/s], [rad/s]
    Eigen::VectorXf F_tmp = target_object_data->simulation_object.getForce(); // [F], [F*m]

    printf("\n*-*-*-*-*-*-*-*-\n");
    vel_tmp.segment<3>(0) *= 1000.0;
    vel_tmp.segment<3>(3) *= RADTODEG;
    m_math.printVector(pose_tmp, "pose_now"); // [mm], [deg]
    m_math.printVector(vel_tmp, "vel_now"); // [mm/s], [deg/s]
    m_math.printVector(F_tmp, "F_now");
    printf("- The number of the contact points: %zu\n", target_object_data->idx_set_contact_point.size());
    printf("- Contact stable count: %zu\n", target_object_data->simulation_contact_stable_cnt);
    printf("*-*-*-*-*-*-*-*-\n\n");
    if(do_step) target_object_data->simulation_object.clearForces();
    printf("****************************************************************\n");
    printf("**********************************************************************\n");
    printf("*****************************************************************************\n\n");
    //////////////////////////////////////////////////////////////////////////////////////

    // 2) Manipulate
    Eigen::Matrix4f T_process = T_now; // [mm]
    // pcl::transformPointCloudWithNormals(cloud_process, cloud_process, target_object_data->T_contact2Bin); // contact point 기준으로 좌표변환
    pcl::transformPointCloudWithNormals(*target_object_data->cloud_CAD_uniformly_downsampled_with_mesh_normal, cloud_process, T_process);
    // pcl::transformPointCloudWithNormals(cloud_process, cloud_process, target_object_data->T_bin2Contact); // bin 기준으로 좌표변환

    //// update
    target_object_data->T_process_simulation = T_process;
    // m_math.printHTM(T_process, "T_process");


    //// 물체의 중심점 update, Center of Mass
    target_object_data->simulation_center_of_mass_process = (target_object_data->T_process_simulation*target_object_data->simulation_center_of_mass_object_frame).segment<3>(0);

    double thre_dist_KDTree = target_object_data->cad_raw_voxel_filter_size;
    if(extractCollisionCloudResults(target_object_data, "r", cloud_process))
    {
        printf("Object Collision!\n");
        // 조금이라도 충돌로 간주되면 KDTree까지 사용하여 충돌 여부를 판단, KDTree는 연산량이 과다하여 필요할 때만 사용
        extractCollisionCloudResultsWithKDTree(target_object_data, "r", cloud_process);


        ////////////////////////////////////////////////////////////////////////////////////////////////////////////////////
        //// a) Penetration check
        ////////////////////////////////////////////////////////////////////////////////////////////////////////////////////
        bool do_avoiding_penetration = false;
        //// HERE: 아래 부분이 수행되어야 뚫고 들어가지 않음
        // Penetration만큼 위로 상승
        if(do_avoiding_penetration)
        {
            m_math.extractCloud(*target_object_data->cloud_process_object_CAD_simulation, *target_object_data->simulation_collision_idx_cloud_in, *target_object_data->collision_cloud_in);
            m_math.extractCloud(*target_object_data->cloud_simulation_merged_object_with_bin, *target_object_data->simulation_collision_idx_cloud_map, *target_object_data->collision_cloud_map);
            ///////////////////////////////////////////////
            // Nearest point to bin
            //// FIXME: 아래 z 최소값 구해서 마지막에 bin 바닥과 접촉하도록 미세한 translation 필요  - 복셀 특성 상 약간 떠있음
            pcl::PointCloud<pcl::PointXYZ>::Ptr collision_cloud_in_xyz(new pcl::PointCloud<pcl::PointXYZ>);
            pcl::PointCloud<pcl::PointXYZ>::Ptr collision_cloud_map_xyz(new pcl::PointCloud<pcl::PointXYZ>);
            pcl::copyPointCloud(*target_object_data->collision_cloud_in, *collision_cloud_in_xyz);
            pcl::copyPointCloud(*target_object_data->collision_cloud_map, *collision_cloud_map_xyz);
            pcl::PointXYZ minPt_in, maxPt_in, minPt_map, maxPt_map;
            m_math.genCloudMinMax(*collision_cloud_in_xyz, minPt_in, maxPt_in);
            m_math.genCloudMinMax(*collision_cloud_map_xyz, minPt_map, maxPt_map);

            float dist_object_to_bin = minPt_in.z - maxPt_map.z;
            // float thre_dist = 1.0; // if the object is penetrated.
            float thre_dist = -1.0; // if the object is penetrated. --> 미세하게 접촉은 유지하도록 음수로 처리
            if(dist_object_to_bin < thre_dist)
            {
                printf("\n\nPenetration avoiding process... z upward direction: %0.1fmm (Object: %0.3f, Bin: %0.3f)\n", fabs(dist_object_to_bin), minPt_in.z, maxPt_map.z);
                Eigen::Matrix4f T_process = Eigen::Matrix4f::Identity();
                T_process(2, 3) = fabs(dist_object_to_bin);
                pcl::transformPointCloudWithNormals(*target_object_data->cloud_process_object_CAD_simulation, *target_object_data->cloud_process_object_CAD_simulation, T_process);
                // update
                target_object_data->T_process_simulation = T_process*target_object_data->T_process_simulation;
                //// 물체의 중심점 update, Center of Mass
                target_object_data->simulation_center_of_mass_process = (target_object_data->T_process_simulation*target_object_data->simulation_center_of_mass_object_frame).segment<3>(0);

                //// NOTICE: 기존에 임의로 모션을 주던 부분을 동역학으로 대체함.
                // simulation object update
                std::vector<double> pose_z_penetration = m_math.htm2pose_mm2m(target_object_data->T_process_simulation, "target_object_data->T_process_simulation"); // [mm] to [m]
                Eigen::Vector3f linear_position(pose_z_penetration[0], pose_z_penetration[1], pose_z_penetration[2]);
                target_object_data->simulation_object.setPosition(linear_position, target_object_data->T_process_simulation.block<3, 3>(0, 0));
            }
        }
        ////////////////////////////////////////////////////////////////////////////////////////////////////////////////////
        ////////////////////////////////////////////////////////////////////////////////////////////////////////////////////
        ////////////////////////////////////////////////////////////////////////////////////////////////////////////////////
        return true;
    }
    else
    {
        return false;
    }
}

//// contact point를 euclidean cluster을 통해 동시에 찾음 (사용 안함)
//// OBB 이용하여 무게중심이 Form closure 형태로 산출되면 Monment 산출하여 net moment가 일정 이하면 안정적인 접촉으로 간주함.
