bool TEMPLATE_MATCHING::featureSimilarityEvaluation(const pcl::PointCloud<pcl::FPFHSignature33> &fpfhs_meas, const pcl::PointCloud<pcl::FPFHSignature33> &fpfhs_ref) {
    //// TODO: Similarity evaluation 추가, downsampling - O(p*q)를 20,000 수준으로
    Eigen::VectorXf fpfhs_ref_value(33);
    Eigen::VectorXf fpfhs_meas_value(33);
    Eigen::VectorXf model_weight(33);
    std::vector<double> sim_eval_results;
    Eigen::VectorXf sim_eval_tmp;
    
    
    //// TODO: 초기단계에서 처리하도록 변경하기
    // model gen.
    std::vector<Eigen::MatrixXf> model_matrix;
    Eigen::MatrixXf model_matrix_state_1(20,33);
    model_matrix.push_back(model_matrix_state_1);

    //// TODO: 일단 measured cloud의 normal 추정 및 특징 추출 하는데 걸리는 연산 시간 확인한 후에, 적합하면 아래 코드 수정하기
    //// TODO: 일단 measured cloud의 normal 추정 및 특징 추출 하는데 걸리는 연산 시간 확인한 후에, 적합하면 아래 코드 수정하기
    //// TODO: 일단 measured cloud의 normal 추정 및 특징 추출 하는데 걸리는 연산 시간 확인한 후에, 적합하면 아래 코드 수정하기

    /////////////////////////////////////////////
    ///////////////////////////////////////////// similarityEvaluation start
    /////////////////////////////////////////////
    // Test function
    //// TODO: model size 정의해야 함
    //// TODO: 아래 구현된 함수는 일단 VD 이용하여 20개의 근접한 특징을 모델 매트릭스로 정의하여 이와 측정 20개의 점의 유사도를 비교한 것이라 각 점의 유사도가 제각각일 수 있음
    //// TODO: 221114, 추후 분할영역마다 모델을 생성하여 계산하는 방법 만들기 + MD를 이용하여 확률적 모델로 변경하기
    for (size_t i = 0; i < model_matrix.size(); i++)
    { 
        for (size_t j = 0; j < 20; j++) { 
        for (int k = 0; k < 33; k++) { fpfhs_ref_value[k] = fpfhs_ref.points[j].histogram[k]; }
        model_matrix[i].row(j) = fpfhs_ref_value;
        }
    }
    std::cout << "Model matrix: " << model_matrix[0] << std::endl;

    // weight
    for (int k = 0; k < 33; k++) { model_weight[k] = 1.0; }
    std::cout << "Model matrix size: " << model_matrix.size() << std::endl;
    std::cout << "measured point size: " << fpfhs_meas.size() << std::endl;

    // state est.
    //// TODO: state 정리 및 점 개수 다운샘플링 정의
    // sim_eval_results.resize(fpfhs_meas->size());
    // for (size_t j = 0; j < fpfhs_meas->size(); j++)
    sim_eval_results.resize(20);
    for (size_t j = 0; j < 20; j++)
    {
        for (int k = 0; k < 33; k++) { fpfhs_meas_value[k] = fpfhs_meas.points[j].histogram[k]; }
        // Similarity evaluation
        sim_eval_tmp = m_state_evaluation.CalSimilarityVD2(model_matrix, fpfhs_meas_value, model_weight);
        sim_eval_results[j] = sim_eval_tmp[0]; 
    }
    /////////////////////////////////////////////
    ///////////////////////////////////////////// similarityEvaluation end
    /////////////////////////////////////////////









  return true;
}

/** @brief Korean: Feature의 유사도 비교를 통한 빈피킹 대상 물체가 포함된 cluster를 선택한다.
 * @details 빈피킹 시스템 기능
 * @param[in] cluster_set : cluster set
 * @param[out] cloud_out : 출력 point cloud (빈피킹 대상 물체가 포함된 cluster)
 */
void TEMPLATE_MATCHING::selectClusterUsingFeatureSimilarity(const std::vector<pcl::PointCloud<pcl::PointXYZRGBA>, Eigen::aligned_allocator<pcl::PointXYZRGBA> > &cluster_set, pcl::PointCloud<pcl::PointXYZRGBA> &cloud_out)
{

    pcl::PointCloud<pcl::FPFHSignature33>::Ptr fpfhs_ref(new pcl::PointCloud<pcl::FPFHSignature33>());
    pcl::PointCloud<pcl::FPFHSignature33>::Ptr fpfhs_meas(new pcl::PointCloud<pcl::FPFHSignature33>());
    pcl::console::TicToc time;
    time.tic();
    printf("\n\n------------------------------------------------\n");
    printf("Do FPFH feature extractor - CAD!\n");
    printf("(Input: Color-based RGS results)\n");
    //// TODO: cloud_CAD의 특징은 미리 초기단계에서 추출하도록 처리

    m_math.printCloudMinMax(*m_ptr_template_list[0]->cloud_CAD_with_normal_downsampled, "cloud_CAD");
    extractFeatureFPFH(*m_ptr_template_list[0]->cloud_CAD_with_normal_downsampled, *fpfhs_ref);
    m_pcl_proc.printFPFHCompare(*fpfhs_ref, *fpfhs_ref, "Feature FPFH reference", false);
    std::cout << "CAD cloud size: " << m_ptr_template_list[0]->cloud_CAD_with_normal_downsampled->size() << std::endl;
    std::cout << "fpfhs_ref size: " << fpfhs_ref->size() << std::endl;
    printf("------------------------------------------------\n\n");
    std::cout << "FPFH feature extractor(CAD) finished :" << time.toc() << " ms" << std::endl;
    
    printf("\n\n------------------------------------------------\n");
    printf("Do FPFH feature extractor! - Cluster (measured cloud)\n");
    //// TODO: 특징을 추출하려면 sensor 좌표계 기준으로 측정된 점군의 normal 추정이 필요함.
    std::vector<size_t> cluster_idx_list;
    double downsample_size = 5.0;
    for (size_t i = 0; i < cluster_set.size(); i++)
    {
        pcl::PointCloud<pcl::PointXYZ>::Ptr cloud_cluster(new pcl::PointCloud<pcl::PointXYZ>);
        pcl::PointCloud<pcl::PointXYZRGBNormal>::Ptr cloud_query(new pcl::PointCloud<pcl::PointXYZRGBNormal>);
        pcl::copyPointCloud(cluster_set[i], *cloud_cluster);

    	// pcl::console::TicToc time;
        // time.tic();
        // normal estimation - input cloud는 센서 좌표계 기준의 결과를 입력
        Eigen::Vector3d sensor_origin = {0.0, 0.0, 0.0};
        //// TODO: 적절한 K 설정 필요
        m_pcl_proc.cloudNormalEst2Measured(*cloud_cluster, *cloud_query, 10, sensor_origin, 80.0); // K = 10, angle: 80 [deg]
        // m_math.printCloudPoints(*cloud_query, 10);
        // m_math.printCloudMinMax(*cloud_query, "cloud_query");
        // std::cout << " Normal estimation(cloudNormalEst2Measured) for cluster" << i+1 << "(size: " << cloud_cluster->size() << ") process time: " << time.toc() << " ms" << std::endl;




        //// TODO: 특징 유사도 비교를 위해 CAD와 측정결과 사이의 매칭이 필요할 지 (매칭 후, KdTree이용하여 근접점만 선택한후 유사도 비교.. 이 지점에서 뭔가 점 간 거리, 유사도를 이용하여 방법을 만들어 볼 수 있을듯)
        //// 여러 cluster에 대해 하나하나 매칭을 통해 아래의 결과를 얻는 것은 연산량이 과다
        //// 일단 아래 코드는 보류

        // Downsampling to 5mm voxel grid
        m_math.cloudScaling(*cloud_query, 1); // m to mm
        pcl::VoxelGrid<pcl::PointXYZRGBNormal> vox_grid;
        vox_grid.setInputCloud(cloud_query);
        vox_grid.setLeafSize(downsample_size, downsample_size, downsample_size);
        vox_grid.filter(*cloud_query); // voxel filtering (downsizing)
        printf("After voxel filtering size: %zu", cloud_query->size());

        //// TODO: 분할영역 중에서 유사도가 낮은 영역은 제외하는 함수 --> input: cluster_list
        //// Feature extraction - FPFH
        printf("cloud_query #%zu!\n", i + 1);
        extractFeatureFPFH(*cloud_query, *fpfhs_meas);
        m_pcl_proc.printFPFHCompare(*fpfhs_meas, *fpfhs_meas, "Feature FPFH reference", false);
        std::cout << "Cluster #"<< i+1 << " size:" << m_ptr_template_list[0]->cloud_CAD_with_normal_downsampled->size() << std::endl;
        std::cout << "fpfhs_meas #" << i+1 << " size: " << fpfhs_meas->size() << std::endl;
        // Comparision results
        m_pcl_proc.printFPFHCompare(*fpfhs_meas, *fpfhs_ref, "Feature FPFH comparison between modified 1 and reference!", true);

        // // Similarity evaluation
        // if(featureSimilarityEvaluation(*fpfhs_meas, *fpfhs_ref)) { cluster_idx_list.push_back(i); }
        // else { ROS_LOG_INFO("Cluster #%u has no target objects", i+1);}
    }
    printf("------------------------------------------------\n\n");
}


